/**
 * SchedulePickerModal
 * 
 * Modal for scheduling messages to be sent later.
 * Provides preset options and a custom date/time picker.
 */

import { useState, useMemo } from 'react';
import { Clock, Calendar, Send } from 'lucide-react';
import { Modal } from '../ui/Modal';
import { cn } from '../../utils/cn';

interface SchedulePickerModalProps {
    isOpen: boolean;
    onClose: () => void;
    onSchedule: (scheduledFor: Date) => void;
    isLoading?: boolean;
}

/**
 * Get preset schedule options based on current time.
 */
function getPresetOptions(): { label: string; value: Date }[] {
    const now = new Date();
    const presets: { label: string; value: Date }[] = [];

    // In 1 hour
    const inOneHour = new Date(now.getTime() + 60 * 60 * 1000);
    presets.push({ label: 'In 1 hour', value: inOneHour });

    // In 2 hours
    const inTwoHours = new Date(now.getTime() + 2 * 60 * 60 * 1000);
    presets.push({ label: 'In 2 hours', value: inTwoHours });

    // Tomorrow 9 AM
    const tomorrow9am = new Date(now);
    tomorrow9am.setDate(tomorrow9am.getDate() + 1);
    tomorrow9am.setHours(9, 0, 0, 0);
    presets.push({ label: 'Tomorrow 9:00 AM', value: tomorrow9am });

    // Next Monday 9 AM
    const nextMonday = new Date(now);
    const currentDay = nextMonday.getDay();
    const daysUntilMonday = currentDay === 0 ? 1 : 8 - currentDay;
    nextMonday.setDate(nextMonday.getDate() + daysUntilMonday);
    nextMonday.setHours(9, 0, 0, 0);
    if (nextMonday > now) {
        presets.push({ label: 'Monday 9:00 AM', value: nextMonday });
    }

    return presets;
}

/**
 * Format date for display.
 */
function formatScheduleTime(date: Date): string {
    return date.toLocaleString(undefined, {
        weekday: 'short',
        month: 'short',
        day: 'numeric',
        hour: 'numeric',
        minute: '2-digit',
    });
}

export function SchedulePickerModal({
    isOpen,
    onClose,
    onSchedule,
    isLoading = false,
}: SchedulePickerModalProps) {
    const [selectedPreset, setSelectedPreset] = useState<Date | null>(null);
    const [customDate, setCustomDate] = useState('');
    const [customTime, setCustomTime] = useState('');
    const [useCustom, setUseCustom] = useState(false);

    // Memoize presets to avoid impure function call during render
    const presets = useMemo(() => getPresetOptions(), []);

    // Memoize minimum date calculation to avoid impure Date.now() call during render
    const { minDateString } = useMemo(() => {
        const minDate = new Date(Date.now() + 5 * 60 * 1000);
        return {
            minDateString: minDate.toISOString().split('T')[0],
        };
    }, []);

    const handlePresetSelect = (date: Date) => {
        setSelectedPreset(date);
        setUseCustom(false);
    };

    const handleCustomChange = () => {
        setUseCustom(true);
        setSelectedPreset(null);
    };

    const getScheduledTime = (): Date | null => {
        if (useCustom && customDate && customTime) {
            const combined = new Date(`${customDate}T${customTime}`);
            if (combined > new Date()) {
                return combined;
            }
        }
        return selectedPreset;
    };

    const scheduledTime = getScheduledTime();

    const handleSubmit = () => {
        if (scheduledTime) {
            onSchedule(scheduledTime);
        }
    };

    return (
        <Modal
            isOpen={isOpen}
            onClose={onClose}
            title={
                <div className="flex items-center gap-2 text-white">
                    <Clock className="w-5 h-5 text-indigo-400" />
                    <span>Schedule Message</span>
                </div>
            }
            maxWidth="max-w-md"
        >
            <div className="space-y-4">
                {/* Preset Options */}
                <div className="space-y-2">
                    <label className="text-sm font-medium text-gray-400">Quick Options</label>
                    <div className="grid grid-cols-2 gap-2">
                        {presets.map((preset, index) => (
                            <button
                                key={index}
                                onClick={() => handlePresetSelect(preset.value)}
                                className={cn(
                                    'px-3 py-2 rounded-lg text-sm font-medium transition-all',
                                    'border',
                                    selectedPreset === preset.value && !useCustom
                                        ? 'bg-indigo-600 border-indigo-500 text-white'
                                        : 'bg-gray-800 border-gray-700 text-gray-300 hover:bg-gray-700 hover:border-gray-600'
                                )}
                            >
                                {preset.label}
                            </button>
                        ))}
                    </div>
                </div>

                {/* Divider */}
                <div className="flex items-center gap-3">
                    <div className="flex-1 h-px bg-gray-700" />
                    <span className="text-xs text-gray-500 uppercase">or</span>
                    <div className="flex-1 h-px bg-gray-700" />
                </div>

                {/* Custom Date/Time */}
                <div className="space-y-3">
                    <label className="text-sm font-medium text-gray-400">Custom Time</label>
                    <div className="flex gap-2">
                        <div className="flex-1">
                            <div className="flex items-center gap-2 px-3 py-2 bg-gray-800 border border-gray-700 rounded-lg focus-within:border-indigo-500">
                                <Calendar className="w-4 h-4 text-gray-400" />
                                <input
                                    type="date"
                                    value={customDate}
                                    onChange={(e) => {
                                        setCustomDate(e.target.value);
                                        handleCustomChange();
                                    }}
                                    min={minDateString}
                                    className="flex-1 bg-transparent text-white text-sm outline-none"
                                />
                            </div>
                        </div>
                        <div className="flex-1">
                            <div className="flex items-center gap-2 px-3 py-2 bg-gray-800 border border-gray-700 rounded-lg focus-within:border-indigo-500">
                                <Clock className="w-4 h-4 text-gray-400" />
                                <input
                                    type="time"
                                    value={customTime}
                                    onChange={(e) => {
                                        setCustomTime(e.target.value);
                                        handleCustomChange();
                                    }}
                                    className="flex-1 bg-transparent text-white text-sm outline-none"
                                />
                            </div>
                        </div>
                    </div>
                </div>

                {/* Selected Time Preview */}
                {scheduledTime && (
                    <div className="p-3 bg-indigo-900/30 border border-indigo-700/50 rounded-lg">
                        <div className="flex items-center gap-2 text-indigo-300">
                            <Send className="w-4 h-4" />
                            <span className="text-sm">
                                Message will be sent: <strong>{formatScheduleTime(scheduledTime)}</strong>
                            </span>
                        </div>
                    </div>
                )}
            </div>

            {/* Footer */}
            <div className="flex justify-end gap-2 pt-4 mt-4 border-t border-gray-700">
                <button
                    onClick={onClose}
                    className="px-4 py-2 text-sm font-medium text-gray-300 bg-gray-700 rounded-lg hover:bg-gray-600 transition-colors"
                >
                    Cancel
                </button>
                <button
                    onClick={handleSubmit}
                    disabled={!scheduledTime || isLoading}
                    className={cn(
                        'px-4 py-2 text-sm font-medium rounded-lg transition-colors flex items-center gap-2',
                        scheduledTime && !isLoading
                            ? 'bg-indigo-600 text-white hover:bg-indigo-500'
                            : 'bg-gray-700 text-gray-500 cursor-not-allowed'
                    )}
                >
                    <Clock className="w-4 h-4" />
                    {isLoading ? 'Scheduling...' : 'Schedule'}
                </button>
            </div>
        </Modal>
    );
}

/**
 * ToolbarPlugin - Configurable toolbar with formatting buttons.
 * Renders buttons based on enabled features.
 */
import { useCallback, useEffect, useState, useRef } from 'react';
import { useLexicalComposerContext } from '@lexical/react/LexicalComposerContext';
import {
    $getSelection,
    $isRangeSelection,
    FORMAT_TEXT_COMMAND,
    SELECTION_CHANGE_COMMAND,
    COMMAND_PRIORITY_CRITICAL,
} from 'lexical';
import { $isLinkNode, TOGGLE_LINK_COMMAND } from '@lexical/link';
import {
    INSERT_ORDERED_LIST_COMMAND,
    INSERT_UNORDERED_LIST_COMMAND,
    $isListNode,
    ListNode,
} from '@lexical/list';
import { $getNearestNodeOfType } from '@lexical/utils';
import {
    Bold,
    Italic,
    Underline,
    Link,
    List,
    ListOrdered,
    Smile,
} from 'lucide-react';

export type ToolbarFeature =
    | 'bold'
    | 'italic'
    | 'underline'
    | 'link'
    | 'list'
    | 'heading'
    | 'emoji'
    | 'image';

interface ToolbarPluginProps {
    features: ToolbarFeature[];
}

// Common emojis for quick access
const EMOJI_LIST = [
    '😊', '😂', '❤️', '👍', '🙏', '🎉', '🔥', '✨',
    '👏', '💯', '🤝', '💪', '🙌', '✅', '⭐', '💡',
    '📦', '🚚', '💳', '📧', '📞', '🛒', '💰', '🎁',
];

export function ToolbarPlugin({ features }: ToolbarPluginProps) {
    const [editor] = useLexicalComposerContext();
    const [isBold, setIsBold] = useState(false);
    const [isItalic, setIsItalic] = useState(false);
    const [isUnderline, setIsUnderline] = useState(false);
    const [isLink, setIsLink] = useState(false);
    const [listType, setListType] = useState<'bullet' | 'number' | null>(null);
    const [showLinkModal, setShowLinkModal] = useState(false);
    const [linkUrl, setLinkUrl] = useState('');
    const [showEmojiPicker, setShowEmojiPicker] = useState(false);
    const emojiPickerRef = useRef<HTMLDivElement>(null);

    const updateToolbar = useCallback(() => {
        const selection = $getSelection();
        if ($isRangeSelection(selection)) {
            setIsBold(selection.hasFormat('bold'));
            setIsItalic(selection.hasFormat('italic'));
            setIsUnderline(selection.hasFormat('underline'));

            // Check for link
            const node = selection.anchor.getNode();
            const parent = node.getParent();
            setIsLink($isLinkNode(parent) || $isLinkNode(node));

            // Check for list
            const anchorNode = selection.anchor.getNode();
            const element = anchorNode.getKey() === 'root'
                ? anchorNode
                : anchorNode.getTopLevelElementOrThrow();
            const elementDOM = editor.getElementByKey(element.getKey());

            if (elementDOM !== null) {
                const listNode = $getNearestNodeOfType<ListNode>(anchorNode, ListNode);
                if (listNode) {
                    setListType(listNode.getListType() === 'bullet' ? 'bullet' : 'number');
                } else {
                    setListType(null);
                }
            }
        }
    }, [editor]);

    useEffect(() => {
        return editor.registerCommand(
            SELECTION_CHANGE_COMMAND,
            () => {
                updateToolbar();
                return false;
            },
            COMMAND_PRIORITY_CRITICAL
        );
    }, [editor, updateToolbar]);

    // Close emoji picker when clicking outside
    useEffect(() => {
        const handleClickOutside = (event: MouseEvent) => {
            if (emojiPickerRef.current && !emojiPickerRef.current.contains(event.target as Node)) {
                setShowEmojiPicker(false);
            }
        };
        if (showEmojiPicker) {
            document.addEventListener('mousedown', handleClickOutside);
            return () => document.removeEventListener('mousedown', handleClickOutside);
        }
    }, [showEmojiPicker]);

    const formatBold = () => editor.dispatchCommand(FORMAT_TEXT_COMMAND, 'bold');
    const formatItalic = () => editor.dispatchCommand(FORMAT_TEXT_COMMAND, 'italic');
    const formatUnderline = () => editor.dispatchCommand(FORMAT_TEXT_COMMAND, 'underline');

    const insertLink = () => {
        if (isLink) {
            editor.dispatchCommand(TOGGLE_LINK_COMMAND, null);
        } else {
            setLinkUrl('https://');
            setShowLinkModal(true);
        }
    };

    const confirmLink = () => {
        if (linkUrl && linkUrl !== 'https://') {
            editor.dispatchCommand(TOGGLE_LINK_COMMAND, linkUrl);
        }
        setShowLinkModal(false);
        setLinkUrl('');
    };

    const insertBulletList = () => editor.dispatchCommand(INSERT_UNORDERED_LIST_COMMAND, undefined);
    const insertNumberedList = () => editor.dispatchCommand(INSERT_ORDERED_LIST_COMMAND, undefined);

    // Insert emoji at cursor position
    const insertEmoji = (emoji: string) => {
        editor.update(() => {
            const selection = $getSelection();
            if ($isRangeSelection(selection)) {
                selection.insertText(emoji);
            }
        });
        setShowEmojiPicker(false);
    };

    const has = (feature: ToolbarFeature) => features.includes(feature);

    return (
        <>
            <div className="rte-toolbar">
                {/* Text Formatting Group */}
                {(has('bold') || has('italic') || has('underline')) && (
                    <div className="rte-toolbar-group">
                        {has('bold') && (
                            <button
                                type="button"
                                onClick={formatBold}
                                className={`rte-toolbar-btn ${isBold ? 'active' : ''}`}
                                title="Bold (Ctrl+B)"
                                aria-label="Format Bold"
                            >
                                <Bold size={16} />
                            </button>
                        )}
                        {has('italic') && (
                            <button
                                type="button"
                                onClick={formatItalic}
                                className={`rte-toolbar-btn ${isItalic ? 'active' : ''}`}
                                title="Italic (Ctrl+I)"
                                aria-label="Format Italic"
                            >
                                <Italic size={16} />
                            </button>
                        )}
                        {has('underline') && (
                            <button
                                type="button"
                                onClick={formatUnderline}
                                className={`rte-toolbar-btn ${isUnderline ? 'active' : ''}`}
                                title="Underline (Ctrl+U)"
                                aria-label="Format Underline"
                            >
                                <Underline size={16} />
                            </button>
                        )}
                    </div>
                )}

                {/* Link */}
                {has('link') && (
                    <div className="rte-toolbar-group">
                        <button
                            type="button"
                            onClick={insertLink}
                            className={`rte-toolbar-btn ${isLink ? 'active' : ''}`}
                            title="Insert Link"
                            aria-label="Insert Link"
                        >
                            <Link size={16} />
                        </button>
                    </div>
                )}

                {/* Lists */}
                {has('list') && (
                    <div className="rte-toolbar-group">
                        <button
                            type="button"
                            onClick={insertBulletList}
                            className={`rte-toolbar-btn ${listType === 'bullet' ? 'active' : ''}`}
                            title="Bullet List"
                            aria-label="Insert Bullet List"
                        >
                            <List size={16} />
                        </button>
                        <button
                            type="button"
                            onClick={insertNumberedList}
                            className={`rte-toolbar-btn ${listType === 'number' ? 'active' : ''}`}
                            title="Numbered List"
                            aria-label="Insert Numbered List"
                        >
                            <ListOrdered size={16} />
                        </button>
                    </div>
                )}

                {/* Emoji Picker */}
                {has('emoji') && (
                    <div className="rte-toolbar-group" style={{ position: 'relative' }} ref={emojiPickerRef}>
                        <button
                            type="button"
                            onClick={() => setShowEmojiPicker(!showEmojiPicker)}
                            className={`rte-toolbar-btn ${showEmojiPicker ? 'active' : ''}`}
                            title="Insert Emoji"
                            aria-label="Insert Emoji"
                        >
                            <Smile size={16} />
                        </button>
                        {showEmojiPicker && (
                            <div className="rte-emoji-picker">
                                {EMOJI_LIST.map((emoji) => (
                                    <button
                                        key={emoji}
                                        type="button"
                                        className="rte-emoji-btn"
                                        onClick={() => insertEmoji(emoji)}
                                        title={emoji}
                                    >
                                        {emoji}
                                    </button>
                                ))}
                            </div>
                        )}
                    </div>
                )}
            </div>

            {/* Link Modal */}
            {showLinkModal && (
                <div className="rte-link-modal-overlay" onClick={() => setShowLinkModal(false)}>
                    <div className="rte-link-modal" onClick={(e) => e.stopPropagation()}>
                        <h3>Insert Link</h3>
                        <input
                            type="url"
                            value={linkUrl}
                            onChange={(e) => setLinkUrl(e.target.value)}
                            placeholder="Enter URL..."
                            autoFocus
                            onKeyDown={(e) => {
                                if (e.key === 'Enter') confirmLink();
                                if (e.key === 'Escape') setShowLinkModal(false);
                            }}
                        />
                        <div className="rte-link-modal-actions">
                            <button
                                type="button"
                                className="rte-link-modal-btn cancel"
                                onClick={() => setShowLinkModal(false)}
                            >
                                Cancel
                            </button>
                            <button
                                type="button"
                                className="rte-link-modal-btn confirm"
                                onClick={confirmLink}
                            >
                                Insert
                            </button>
                        </div>
                    </div>
                </div>
            )}
        </>
    );
}

/**
 * MergeCustomerModal - Find and merge duplicate customer records.
 */
import { useState, useEffect } from 'react';
import { Users, ArrowRight, AlertTriangle, Check, X } from 'lucide-react';
import { useAuth } from '../../context/AuthContext';
import { useAccount } from '../../context/AccountContext';
import { Modal } from '../ui/Modal';
import { formatCurrency } from '../../utils/format';

interface Customer {
    id: string;
    wooId: number;
    firstName: string;
    lastName: string;
    email: string;
    ordersCount: number;
    totalSpent: number;
}

interface MergeCustomerModalProps {
    isOpen: boolean;
    onClose: () => void;
    customerId: string;
    onMergeComplete: () => void;
}

export function MergeCustomerModal({ isOpen, onClose, customerId, onMergeComplete }: MergeCustomerModalProps) {
    const { token } = useAuth();
    const { currentAccount } = useAccount();
    const [target, setTarget] = useState<Customer | null>(null);
    const [duplicates, setDuplicates] = useState<Customer[]>([]);
    const [selectedSource, setSelectedSource] = useState<Customer | null>(null);
    const [isLoading, setIsLoading] = useState(false);
    const [isMerging, setIsMerging] = useState(false);
    const [error, setError] = useState('');

    useEffect(() => {
        if (isOpen && customerId) {
            fetchDuplicates();
        }
    }, [isOpen, customerId]);

    const fetchDuplicates = async () => {
        setIsLoading(true);
        setError('');
        try {
            const res = await fetch(`/api/customers/${customerId}/duplicates`, {
                headers: { 'Authorization': `Bearer ${token}`, 'x-account-id': currentAccount?.id || '' }
            });
            if (res.ok) {
                const data = await res.json();
                setTarget(data.target);
                setDuplicates(data.duplicates || []);
            }
        } catch (e) {
            setError('Failed to load duplicates');
        } finally {
            setIsLoading(false);
        }
    };

    const handleMerge = async () => {
        if (!selectedSource || !target) return;

        setIsMerging(true);
        try {
            const res = await fetch(`/api/customers/${target.id}/merge`, {
                method: 'POST',
                headers: {
                    'Content-Type': 'application/json',
                    'Authorization': `Bearer ${token}`,
                    'x-account-id': currentAccount?.id || ''
                },
                body: JSON.stringify({ sourceId: selectedSource.id })
            });

            if (res.ok) {
                onMergeComplete();
                onClose();
            } else {
                const err = await res.json();
                setError(err.error || 'Merge failed');
            }
        } catch (e) {
            setError('Failed to merge customers');
        } finally {
            setIsMerging(false);
        }
    };

    return (
        <Modal isOpen={isOpen} onClose={onClose} title="Merge Duplicate Customers" maxWidth="max-w-2xl">
            <div className="space-y-4">
                {isLoading ? (
                    <div className="flex justify-center py-8">
                        <div className="animate-spin rounded-full h-8 w-8 border-b-2 border-blue-600" />
                    </div>
                ) : duplicates.length === 0 ? (
                    <div className="text-center py-8 text-gray-500">
                        <Users size={48} className="mx-auto mb-3 text-gray-300" />
                        <p className="font-medium">No Duplicates Found</p>
                        <p className="text-sm mt-1">No other customers match this email or phone.</p>
                    </div>
                ) : (
                    <>
                        {/* Target Customer */}
                        <div className="bg-blue-50 border border-blue-200 rounded-lg p-4">
                            <div className="text-xs font-medium text-blue-600 uppercase mb-2">Keep This Customer</div>
                            <div className="flex items-center justify-between">
                                <div>
                                    <div className="font-medium text-gray-900">{target?.firstName} {target?.lastName}</div>
                                    <div className="text-sm text-gray-500">{target?.email}</div>
                                </div>
                                <div className="text-right text-sm">
                                    <div>{target?.ordersCount} orders</div>
                                    <div className="font-medium text-green-600">{formatCurrency(target?.totalSpent || 0)}</div>
                                </div>
                            </div>
                        </div>

                        <div className="flex items-center justify-center">
                            <ArrowRight className="text-gray-400" />
                        </div>

                        {/* Duplicate Customers */}
                        <div className="space-y-2">
                            <div className="text-xs font-medium text-gray-500 uppercase">Select Customer to Merge Into Above</div>
                            {duplicates.map((dup) => (
                                <button
                                    key={dup.id}
                                    onClick={() => setSelectedSource(dup)}
                                    className={`w-full border rounded-lg p-4 text-left transition-colors ${selectedSource?.id === dup.id
                                        ? 'border-red-300 bg-red-50'
                                        : 'border-gray-200 hover:border-gray-300'
                                        }`}
                                >
                                    <div className="flex items-center justify-between">
                                        <div className="flex items-center gap-3">
                                            {selectedSource?.id === dup.id && (
                                                <div className="w-5 h-5 rounded-full bg-red-500 flex items-center justify-center">
                                                    <Check size={12} className="text-white" />
                                                </div>
                                            )}
                                            <div>
                                                <div className="font-medium text-gray-900">{dup.firstName} {dup.lastName}</div>
                                                <div className="text-sm text-gray-500">{dup.email}</div>
                                            </div>
                                        </div>
                                        <div className="text-right text-sm">
                                            <div>{dup.ordersCount} orders</div>
                                            <div className="font-medium">{formatCurrency(dup.totalSpent)}</div>
                                        </div>
                                    </div>
                                </button>
                            ))}
                        </div>

                        {selectedSource && (
                            <div className="bg-amber-50 border border-amber-200 rounded-lg p-3 flex items-start gap-2">
                                <AlertTriangle size={16} className="text-amber-500 mt-0.5 flex-shrink-0" />
                                <div className="text-sm text-amber-800">
                                    <strong>Warning:</strong> This will transfer all orders and conversations from
                                    <span className="font-medium"> {selectedSource.firstName} {selectedSource.lastName}</span> to
                                    <span className="font-medium"> {target?.firstName} {target?.lastName}</span>, then delete the merged customer.
                                </div>
                            </div>
                        )}

                        {error && (
                            <div className="text-red-600 text-sm">{error}</div>
                        )}

                        <div className="flex justify-end gap-2 pt-2">
                            <button onClick={onClose} className="btn-white">
                                Cancel
                            </button>
                            <button
                                onClick={handleMerge}
                                disabled={!selectedSource || isMerging}
                                className="btn-primary bg-red-600 hover:bg-red-700 disabled:opacity-50"
                            >
                                {isMerging ? 'Merging...' : 'Merge & Delete'}
                            </button>
                        </div>
                    </>
                )}
            </div>
        </Modal>
    );
}

/**
 * POStatusStepper - Visual progress indicator for Purchase Order workflow
 * 
 * Shows the current status and progression through the PO lifecycle.
 */

import { FileText, ShoppingCart, Truck, CheckCircle2 } from 'lucide-react';

type POStatus = 'DRAFT' | 'ORDERED' | 'RECEIVED' | 'CANCELLED';

interface POStatusStepperProps {
    status: POStatus;
    onStatusChange?: (newStatus: POStatus) => void;
    disabled?: boolean;
}

const STEPS: { key: POStatus; label: string; icon: React.ReactNode }[] = [
    { key: 'DRAFT', label: 'Draft', icon: <FileText size={18} /> },
    { key: 'ORDERED', label: 'Ordered', icon: <ShoppingCart size={18} /> },
    { key: 'RECEIVED', label: 'Received', icon: <CheckCircle2 size={18} /> },
];

const STATUS_ORDER: POStatus[] = ['DRAFT', 'ORDERED', 'RECEIVED'];

export function POStatusStepper({ status, onStatusChange, disabled = false }: POStatusStepperProps) {
    const currentIndex = STATUS_ORDER.indexOf(status);
    const isCancelled = status === 'CANCELLED';

    if (isCancelled) {
        return (
            <div className="flex items-center gap-2 px-4 py-3 bg-red-50 border border-red-200 rounded-lg">
                <span className="text-red-600 font-medium">Order Cancelled</span>
            </div>
        );
    }

    return (
        <div
            className="flex items-center justify-between bg-gray-50 p-4 rounded-xl border border-gray-200"
            role="navigation"
            aria-label="Purchase order status progression"
        >
            {STEPS.map((step, index) => {
                const isCompleted = index < currentIndex;
                const isCurrent = index === currentIndex;
                const isUpcoming = index > currentIndex;
                const isClickable = !disabled && onStatusChange && (index === currentIndex + 1 || index === currentIndex);

                return (
                    <div key={step.key} className="flex items-center flex-1">
                        {/* Step Circle */}
                        <button
                            type="button"
                            disabled={!isClickable}
                            onClick={() => isClickable && onStatusChange?.(step.key)}
                            className={`
                                relative flex items-center justify-center w-10 h-10 rounded-full border-2 transition-all
                                ${isCompleted ? 'bg-green-500 border-green-500 text-white' : ''}
                                ${isCurrent ? 'bg-blue-500 border-blue-500 text-white ring-4 ring-blue-100' : ''}
                                ${isUpcoming ? 'bg-white border-gray-300 text-gray-400' : ''}
                                ${isClickable ? 'cursor-pointer hover:scale-110' : 'cursor-default'}
                            `}
                            title={isClickable ? `Change to ${step.label}` : undefined}
                            aria-label={`${step.label} ${isCurrent ? '(current)' : isCompleted ? '(completed)' : ''}`}
                            aria-current={isCurrent ? 'step' : undefined}
                        >
                            {step.icon}
                        </button>

                        {/* Label */}
                        <div className="ml-3 mr-4">
                            <p className={`text-sm font-medium ${isCurrent ? 'text-gray-900' : isCompleted ? 'text-green-600' : 'text-gray-400'}`}>
                                {step.label}
                            </p>
                            {isCurrent && (
                                <p className="text-xs text-blue-600">Current Status</p>
                            )}
                            {isCompleted && (
                                <p className="text-xs text-green-600">Completed</p>
                            )}
                        </div>

                        {/* Connector Line */}
                        {index < STEPS.length - 1 && (
                            <div className={`flex-1 h-1 rounded-full ${isCompleted ? 'bg-green-400' : 'bg-gray-200'}`} />
                        )}
                    </div>
                );
            })}
        </div>
    );
}

import { useState, useEffect } from 'react';
import { Logger } from '../../utils/logger';
import { useAuth } from '../../context/AuthContext';
import { useAccount } from '../../context/AccountContext';
import { Plus, Loader2, ChevronDown, ChevronRight, Pencil, Trash2, X, Check } from 'lucide-react';

interface SupplierItem {
    id: string;
    name: string;
    sku: string;
    cost: number;
    leadTime: number;
    moq: number;
}

interface Supplier {
    id: string;
    name: string;
    contactName?: string;
    email?: string;
    phone?: string;
    currency: string;
    leadTimeDefault?: number;
    leadTimeMin?: number;
    leadTimeMax?: number;
    paymentTerms?: string;
    items?: SupplierItem[];
}

/** Available currency options for suppliers */
const CURRENCY_OPTIONS = ['USD', 'EUR', 'GBP', 'AUD', 'CAD', 'NZD', 'CNY', 'JPY'] as const;

export function SuppliersList() {
    const { token } = useAuth();
    const { currentAccount } = useAccount();
    const [suppliers, setSuppliers] = useState<Supplier[]>([]);
    const [loading, setLoading] = useState(true);
    const [expandedSupplier, setExpandedSupplier] = useState<string | null>(null);
    const [isCreating, setIsCreating] = useState(false);
    const [newSupplier, setNewSupplier] = useState({
        name: '', contactName: '', email: '', phone: '', currency: 'USD',
        leadTimeMin: '', leadTimeMax: '', paymentTerms: ''
    });

    // Edit State
    const [editingId, setEditingId] = useState<string | null>(null);
    const [editData, setEditData] = useState<Partial<Supplier>>({});
    const [isSaving, setIsSaving] = useState(false);

    // Item Creation State
    const [addingItemTo, setAddingItemTo] = useState<string | null>(null);
    const [newItem, setNewItem] = useState({ name: '', sku: '', cost: '0', leadTime: '7', moq: '1' });

    useEffect(() => {
        if (currentAccount) fetchSuppliers();
    }, [currentAccount]);

    async function fetchSuppliers() {
        if (!currentAccount) return;
        setLoading(true);
        try {
            const res = await fetch('/api/inventory/suppliers', {
                headers: { 'Authorization': `Bearer ${token}`, 'X-Account-ID': currentAccount.id }
            });
            const data = await res.json();
            setSuppliers(data);
        } catch (error) {
            Logger.error('An error occurred', { error: error });
        } finally {
            setLoading(false);
        }
    }

    async function handleCreateSupplier(e: React.FormEvent) {
        e.preventDefault();
        try {
            const res = await fetch('/api/inventory/suppliers', {
                method: 'POST',
                headers: {
                    'Content-Type': 'application/json',
                    'Authorization': `Bearer ${token}`,
                    'X-Account-ID': currentAccount!.id
                },
                body: JSON.stringify(newSupplier)
            });
            if (res.ok) {
                setIsCreating(false);
                setNewSupplier({
                    name: '', contactName: '', email: '', phone: '', currency: 'USD',
                    leadTimeMin: '', leadTimeMax: '', paymentTerms: ''
                });
                fetchSuppliers();
            }
        } catch (error) {
            alert('Failed to create supplier');
        }
    }

    async function handleUpdateSupplier() {
        if (!editingId) return;
        setIsSaving(true);
        try {
            const res = await fetch(`/api/inventory/suppliers/${editingId}`, {
                method: 'PUT',
                headers: {
                    'Content-Type': 'application/json',
                    'Authorization': `Bearer ${token}`,
                    'X-Account-ID': currentAccount!.id
                },
                body: JSON.stringify(editData)
            });
            if (res.ok) {
                setEditingId(null);
                setEditData({});
                fetchSuppliers();
            } else {
                alert('Failed to update supplier');
            }
        } catch (error) {
            alert('Failed to update supplier');
        } finally {
            setIsSaving(false);
        }
    }

    async function handleDeleteSupplier(id: string, name: string) {
        if (!confirm(`Delete supplier "${name}"? This action cannot be undone.`)) return;
        try {
            const res = await fetch(`/api/inventory/suppliers/${id}`, {
                method: 'DELETE',
                headers: {
                    'Authorization': `Bearer ${token}`,
                    'X-Account-ID': currentAccount!.id
                }
            });
            if (res.ok) {
                fetchSuppliers();
            } else {
                alert('Failed to delete supplier. It may have linked items.');
            }
        } catch (error) {
            alert('Failed to delete supplier');
        }
    }

    function startEdit(supplier: Supplier) {
        setEditingId(supplier.id);
        setEditData({
            name: supplier.name,
            contactName: supplier.contactName || '',
            email: supplier.email || '',
            phone: supplier.phone || '',
            currency: supplier.currency,
            leadTimeMin: supplier.leadTimeMin,
            leadTimeMax: supplier.leadTimeMax,
            paymentTerms: supplier.paymentTerms || ''
        });
    }

    function cancelEdit() {
        setEditingId(null);
        setEditData({});
    }

    async function handleAddItem(e: React.FormEvent) {
        e.preventDefault();
        if (!addingItemTo) return;

        try {
            const res = await fetch(`/api/inventory/suppliers/${addingItemTo}/items`, {
                method: 'POST',
                headers: {
                    'Content-Type': 'application/json',
                    'Authorization': `Bearer ${token}`,
                    'X-Account-ID': currentAccount!.id
                },
                body: JSON.stringify(newItem)
            });
            if (res.ok) {
                setAddingItemTo(null);
                setNewItem({ name: '', sku: '', cost: '0', leadTime: '7', moq: '1' });
                fetchSuppliers();
            }
        } catch (error) {
            alert('Failed to add item');
        }
    }

    if (loading) return <div className="p-8 text-center"><Loader2 className="animate-spin inline text-blue-600" /></div>;

    return (
        <div className="space-y-6">
            <div className="flex justify-between items-center bg-gray-50 p-4 rounded-lg border border-gray-200">
                <h2 className="text-lg font-semibold text-gray-800">Supply Chain</h2>
                <button
                    onClick={() => setIsCreating(true)}
                    className="bg-blue-600 text-white px-4 py-2 rounded-lg flex items-center gap-2 hover:bg-blue-700 transition"
                >
                    <Plus size={16} /> Add Supplier
                </button>
            </div>

            {isCreating && (
                <div className="bg-white p-6 border border-blue-200 rounded-xl shadow-xs mb-6">
                    <h3 className="font-semibold mb-4">New Supplier</h3>
                    <form onSubmit={handleCreateSupplier} className="grid grid-cols-2 gap-4">
                        <input type="text" placeholder="Supplier Name" required className="border p-2 rounded-sm"
                            value={newSupplier.name} onChange={e => setNewSupplier({ ...newSupplier, name: e.target.value })} />
                        <input type="text" placeholder="Contact Name" className="border p-2 rounded-sm"
                            value={newSupplier.contactName} onChange={e => setNewSupplier({ ...newSupplier, contactName: e.target.value })} />
                        <input type="email" placeholder="Email" className="border p-2 rounded-sm"
                            value={newSupplier.email} onChange={e => setNewSupplier({ ...newSupplier, email: e.target.value })} />
                        <input type="tel" placeholder="Phone" className="border p-2 rounded-sm"
                            value={newSupplier.phone} onChange={e => setNewSupplier({ ...newSupplier, phone: e.target.value })} />
                        <select className="border p-2 rounded-sm" value={newSupplier.currency} onChange={e => setNewSupplier({ ...newSupplier, currency: e.target.value })}>
                            {CURRENCY_OPTIONS.map(c => <option key={c} value={c}>{c}</option>)}
                        </select>

                        <div className="col-span-2 grid grid-cols-3 gap-4">
                            <input type="number" placeholder="Min Lead Time (Days)" className="border p-2 rounded-sm"
                                value={newSupplier.leadTimeMin} onChange={e => setNewSupplier({ ...newSupplier, leadTimeMin: e.target.value })} />
                            <input type="number" placeholder="Max Lead Time (Days)" className="border p-2 rounded-sm"
                                value={newSupplier.leadTimeMax} onChange={e => setNewSupplier({ ...newSupplier, leadTimeMax: e.target.value })} />
                            <input type="text" placeholder="Payment Terms (e.g. Net 30)" className="border p-2 rounded-sm"
                                value={newSupplier.paymentTerms} onChange={e => setNewSupplier({ ...newSupplier, paymentTerms: e.target.value })} />
                        </div>

                        <div className="col-span-2 flex justify-end gap-2 mt-2">
                            <button type="button" onClick={() => setIsCreating(false)} className="px-4 py-2 text-gray-500">Cancel</button>
                            <button type="submit" className="px-4 py-2 bg-blue-600 text-white rounded-sm">CREATE</button>
                        </div>
                    </form>
                </div>
            )}

            <div className="space-y-4">
                {suppliers.map(supplier => (
                    <div key={supplier.id} className="bg-white border rounded-xl overflow-hidden shadow-xs">
                        <div
                            className="p-4 flex items-center justify-between cursor-pointer hover:bg-gray-50"
                            onClick={() => setExpandedSupplier(expandedSupplier === supplier.id ? null : supplier.id)}
                        >
                            <div className="flex items-center gap-3">
                                {expandedSupplier === supplier.id ? <ChevronDown size={18} /> : <ChevronRight size={18} />}
                                <div>
                                    <div className="font-medium text-gray-900">{supplier.name}</div>
                                    <div className="text-xs text-gray-500 mt-0.5 flex gap-3">
                                        <span>{supplier.currency}</span>
                                        <span>• {supplier.items?.length || 0} items</span>
                                        {supplier.paymentTerms && <span>• {supplier.paymentTerms}</span>}
                                        {(supplier.leadTimeMin || supplier.leadTimeMax) && (
                                            <span>• Lead: {supplier.leadTimeMin || 0} - {supplier.leadTimeMax || '?'} days</span>
                                        )}
                                    </div>
                                </div>
                            </div>
                            <div className="flex items-center gap-3">
                                <span className="text-sm text-gray-500">{supplier.email || '-'}</span>
                                <button
                                    onClick={(e) => { e.stopPropagation(); startEdit(supplier); }}
                                    className="p-1.5 text-gray-400 hover:text-blue-600 hover:bg-blue-50 rounded transition"
                                    title="Edit Supplier"
                                >
                                    <Pencil size={16} />
                                </button>
                                <button
                                    onClick={(e) => { e.stopPropagation(); handleDeleteSupplier(supplier.id, supplier.name); }}
                                    className="p-1.5 text-gray-400 hover:text-red-600 hover:bg-red-50 rounded transition"
                                    title="Delete Supplier"
                                >
                                    <Trash2 size={16} />
                                </button>
                            </div>
                        </div>

                        {/* Edit Form (inline) */}
                        {editingId === supplier.id && (
                            <div className="bg-blue-50 border-t border-blue-200 p-4">
                                <div className="flex items-center justify-between mb-3">
                                    <h4 className="font-semibold text-blue-900">Edit Supplier</h4>
                                    <button onClick={cancelEdit} className="text-gray-500 hover:text-gray-700">
                                        <X size={18} />
                                    </button>
                                </div>
                                <div className="grid grid-cols-2 md:grid-cols-4 gap-3">
                                    <input type="text" placeholder="Name" className="border p-2 rounded-sm"
                                        value={editData.name || ''} onChange={e => setEditData({ ...editData, name: e.target.value })} />
                                    <input type="text" placeholder="Contact" className="border p-2 rounded-sm"
                                        value={editData.contactName || ''} onChange={e => setEditData({ ...editData, contactName: e.target.value })} />
                                    <input type="email" placeholder="Email" className="border p-2 rounded-sm"
                                        value={editData.email || ''} onChange={e => setEditData({ ...editData, email: e.target.value })} />
                                    <input type="tel" placeholder="Phone" className="border p-2 rounded-sm"
                                        value={editData.phone || ''} onChange={e => setEditData({ ...editData, phone: e.target.value })} />
                                    <select className="border p-2 rounded-sm" value={editData.currency || 'USD'} onChange={e => setEditData({ ...editData, currency: e.target.value })}>
                                        {CURRENCY_OPTIONS.map(c => <option key={c} value={c}>{c}</option>)}
                                    </select>
                                    <input type="number" placeholder="Min Lead (days)" className="border p-2 rounded-sm"
                                        value={editData.leadTimeMin || ''} onChange={e => setEditData({ ...editData, leadTimeMin: e.target.value ? parseInt(e.target.value) : undefined })} />
                                    <input type="number" placeholder="Max Lead (days)" className="border p-2 rounded-sm"
                                        value={editData.leadTimeMax || ''} onChange={e => setEditData({ ...editData, leadTimeMax: e.target.value ? parseInt(e.target.value) : undefined })} />
                                    <input type="text" placeholder="Payment Terms" className="border p-2 rounded-sm"
                                        value={editData.paymentTerms || ''} onChange={e => setEditData({ ...editData, paymentTerms: e.target.value })} />
                                </div>
                                <div className="flex justify-end gap-2 mt-3">
                                    <button onClick={cancelEdit} className="px-3 py-1.5 text-gray-600 text-sm">Cancel</button>
                                    <button
                                        onClick={handleUpdateSupplier}
                                        disabled={isSaving}
                                        className="px-4 py-1.5 bg-blue-600 text-white rounded-sm text-sm flex items-center gap-1 disabled:opacity-50"
                                    >
                                        {isSaving ? <Loader2 size={14} className="animate-spin" /> : <Check size={14} />}
                                        Save
                                    </button>
                                </div>
                            </div>
                        )}

                        {expandedSupplier === supplier.id && (
                            <div className="bg-gray-50 border-t p-4">
                                <table className="w-full text-sm">
                                    <thead>
                                        <tr className="text-left text-gray-500 border-b">
                                            <th className="pb-2">Material / Component</th>
                                            <th className="pb-2">SKU</th>
                                            <th className="pb-2">Cost</th>
                                            <th className="pb-2">Lead Time</th>
                                        </tr>
                                    </thead>
                                    <tbody>
                                        {supplier.items?.map(item => (
                                            <tr key={item.id} className="border-b last:border-0 border-gray-100">
                                                <td className="py-2 font-medium">{item.name}</td>
                                                <td className="py-2 font-mono text-xs">{item.sku || '-'}</td>
                                                <td className="py-2">{supplier.currency} {Number(item.cost).toFixed(2)}</td>
                                                <td className="py-2">{item.leadTime} days</td>
                                            </tr>
                                        ))}
                                    </tbody>
                                </table>

                                {addingItemTo === supplier.id ? (
                                    <form onSubmit={handleAddItem} className="mt-4 bg-white p-4 border rounded-sm shadow-xs">
                                        <h4 className="font-semibold mb-2">Add Material</h4>
                                        <div className="grid grid-cols-5 gap-2">
                                            <input className="border p-2 rounded-sm col-span-2" placeholder="Item Name" required
                                                value={newItem.name} onChange={e => setNewItem({ ...newItem, name: e.target.value })} />
                                            <input className="border p-2 rounded-sm" placeholder="SKU"
                                                value={newItem.sku} onChange={e => setNewItem({ ...newItem, sku: e.target.value })} />
                                            <input className="border p-2 rounded-sm" type="number" step="0.01" placeholder="Cost" required
                                                value={newItem.cost} onChange={e => setNewItem({ ...newItem, cost: e.target.value })} />
                                            <input className="border p-2 rounded-sm" type="number" placeholder="Lead Time (days)" required
                                                value={newItem.leadTime} onChange={e => setNewItem({ ...newItem, leadTime: e.target.value })} />
                                        </div>
                                        <div className="flex justify-end gap-2 mt-2">
                                            <button type="button" onClick={() => setAddingItemTo(null)} className="text-gray-500 text-sm">Cancel</button>
                                            <button type="submit" className="bg-green-600 text-white px-3 py-1 rounded-sm text-sm">Save Item</button>
                                        </div>
                                    </form>
                                ) : (
                                    <button
                                        onClick={(e) => { e.stopPropagation(); setAddingItemTo(supplier.id); }}
                                        className="mt-4 text-blue-600 text-sm font-medium flex items-center gap-1 hover:underline"
                                    >
                                        <Plus size={14} /> Add Material to Catalog
                                    </button>
                                )}
                            </div>
                        )}
                    </div>
                ))}
            </div>
        </div>
    );
}

import { ReactNode, useState, useEffect, useCallback, useRef } from 'react';
import { useLocation, Outlet } from 'react-router-dom';
import { RefreshCw, WifiOff, Download, X, Loader2 } from 'lucide-react';
import { MobileNav } from './MobileNav';
import { MobileErrorBoundary } from '../mobile/MobileErrorBoundary';

import { PWAUpdateModal, usePWAUpdate, PWAUpdateBanner } from '../mobile/PWAUpdateModal';
import { useAuth } from '../../context/AuthContext';
import { useAccount } from '../../context/AccountContext';
import { useVisibilityPolling } from '../../hooks/useVisibilityPolling';
import { useHaptic } from '../../hooks/useHaptic';

/**
 * MobileLayout - Premium dark glassmorphism layout for the PWA companion app.
 * 
 * Features:
 * - Dark theme with gradient backgrounds
 * - Glassmorphism cards throughout
 * - Bottom navigation with badge counts
 * - iOS safe areas handling
 * - Enhanced pull-to-refresh with custom spinner
 * - Smooth page transitions
 * - Custom install prompt
 * - Haptic feedback where supported
 */

interface MobileLayoutProps {
    children?: ReactNode;
}

interface BeforeInstallPromptEvent extends Event {
    prompt: () => Promise<void>;
    userChoice: Promise<{ outcome: 'accepted' | 'dismissed' }>;
}

export function MobileLayout({ children }: MobileLayoutProps) {
    const location = useLocation();
    const { token } = useAuth();
    const { currentAccount } = useAccount();
    const { triggerHaptic } = useHaptic();

    // Page transition state
    const [isTransitioning, setIsTransitioning] = useState(false);
    const [displayLocation, setDisplayLocation] = useState(location);
    const prevPathRef = useRef(location.pathname);

    // Pull-to-refresh state
    const [refreshing, setRefreshing] = useState(false);
    const [startY, setStartY] = useState(0);
    const [pullDistance, setPullDistance] = useState(0);

    // Badge counts
    const [inboxBadge, setInboxBadge] = useState(0);
    const [ordersBadge, setOrdersBadge] = useState(0);

    // Network status
    const [isOnline, setIsOnline] = useState(navigator.onLine);

    // PWA update system
    const {
        updateAvailable,
        showModal: showUpdateModal,
        updateInfo,
        handleUpdate,
        dismissModal
    } = usePWAUpdate();

    // Install prompt
    const [installPrompt, setInstallPrompt] = useState<BeforeInstallPromptEvent | null>(null);
    const [showInstallBanner, setShowInstallBanner] = useState(false);

    // Page transition effect
    useEffect(() => {
        if (location.pathname !== prevPathRef.current) {
            // Defer initial state update to avoid cascading renders
            const initialTimer = setTimeout(() => {
                setIsTransitioning(true);

                // Short delay for exit animation
                const exitTimer = setTimeout(() => {
                    setDisplayLocation(location);
                    prevPathRef.current = location.pathname;

                    // Allow enter animation
                    const enterTimer = setTimeout(() => {
                        setIsTransitioning(false);
                    }, 50);

                    return () => clearTimeout(enterTimer);
                }, 150);

                return () => clearTimeout(exitTimer);
            }, 0);

            return () => clearTimeout(initialTimer);
        }
    }, [location]);

    // Fetch badge counts
    const fetchBadgeCounts = useCallback(async () => {
        if (!token || !currentAccount) return;

        const headers = {
            'Authorization': `Bearer ${token}`,
            'X-Account-ID': currentAccount.id
        };

        try {
            // Fetch unread conversation count
            const convRes = await fetch('/api/chat/unread-count', { headers });
            if (convRes.ok) {
                const data = await convRes.json();
                setInboxBadge(data.count || 0);
            }

            // Fetch pending orders count
            const ordersRes = await fetch('/api/sync/orders/search?limit=1&status=pending', { headers });
            if (ordersRes.ok) {
                const data = await ordersRes.json();
                setOrdersBadge(data.total || 0);
            }
        } catch (error) {
            // Silently fail - badges are enhancement only
        }
    }, [token, currentAccount]);

    // Visibility-aware polling: pauses when app is backgrounded
    useVisibilityPolling(fetchBadgeCounts, 30000, [fetchBadgeCounts]);

    // Network status listeners
    useEffect(() => {
        const handleOnline = () => setIsOnline(true);
        const handleOffline = () => setIsOnline(false);
        window.addEventListener('online', handleOnline);
        window.addEventListener('offline', handleOffline);
        return () => {
            window.removeEventListener('online', handleOnline);
            window.removeEventListener('offline', handleOffline);
        };
    }, []);

    // Install prompt listener
    useEffect(() => {
        const handleBeforeInstall = (e: Event) => {
            e.preventDefault();
            setInstallPrompt(e as BeforeInstallPromptEvent);
            // Check if user hasn't dismissed recently
            const dismissed = localStorage.getItem('pwa-install-dismissed');
            const dismissedTime = dismissed ? parseInt(dismissed) : 0;
            const hoursSinceDismissed = (Date.now() - dismissedTime) / (1000 * 60 * 60);
            if (hoursSinceDismissed > 24) {
                setShowInstallBanner(true);
            }
        };

        window.addEventListener('beforeinstallprompt', handleBeforeInstall);
        return () => {
            window.removeEventListener('beforeinstallprompt', handleBeforeInstall);
        };
    }, []);

    // Handle install
    const handleInstall = async () => {
        if (!installPrompt) return;
        installPrompt.prompt();
        const { outcome } = await installPrompt.userChoice;
        if (outcome === 'accepted') {
            setShowInstallBanner(false);
        }
        setInstallPrompt(null);
    };

    // Dismiss install banner
    const dismissInstallBanner = () => {
        setShowInstallBanner(false);
        localStorage.setItem('pwa-install-dismissed', Date.now().toString());
    };

    // Pull-to-refresh handlers
    const handleTouchStart = (e: React.TouchEvent) => {
        if (window.scrollY === 0) {
            setStartY(e.touches[0].clientY);
        }
    };

    const handleTouchMove = (e: React.TouchEvent) => {
        if (startY === 0 || window.scrollY > 0) return;
        const currentY = e.touches[0].clientY;
        const distance = Math.max(0, currentY - startY);
        // Apply resistance for more natural feel
        const resistance = 0.5;
        const resistedDistance = distance * resistance;
        setPullDistance(Math.min(resistedDistance, 100));
    };

    const handleTouchEnd = async () => {
        if (pullDistance > 50) {
            setRefreshing(true);
            triggerHaptic(20);

            // Refresh badge counts
            await fetchBadgeCounts();
            // Dispatch custom event for pages to refresh their data
            window.dispatchEvent(new CustomEvent('mobile-refresh'));
            // Wait for visual feedback
            await new Promise(resolve => setTimeout(resolve, 1000));

            triggerHaptic(15);
            setRefreshing(false);
        }
        setStartY(0);
        setPullDistance(0);
    };

    const getActiveTab = () => {
        const path = location.pathname;
        if (path.includes('/m/orders')) return 'orders';
        if (path.includes('/m/inbox')) return 'inbox';
        if (path.includes('/m/analytics')) return 'analytics';
        if (path.includes('/m/more')) return 'more';
        return 'dashboard';
    };

    const pullProgress = Math.min(pullDistance / 50, 1);
    const pullThresholdMet = pullProgress >= 1;

    return (
        <div
            className="min-h-screen bg-gradient-to-br from-slate-900 via-slate-800/90 to-slate-800 flex flex-col"
            style={{
                paddingTop: 'env(safe-area-inset-top)',
                paddingBottom: 'calc(env(safe-area-inset-bottom) + 64px)'
            }}
        >
            {/* Offline Banner */}
            {!isOnline && (
                <div className="bg-amber-500/90 backdrop-blur-sm text-white text-center py-2.5 px-4 flex items-center justify-center gap-2 text-sm font-medium animate-fade-slide-up">
                    <WifiOff size={16} />
                    You're offline - some features may be unavailable
                </div>
            )}

            {/* PWA Update Modal */}
            <PWAUpdateModal
                isOpen={showUpdateModal}
                onClose={dismissModal}
                onUpdate={handleUpdate}
                updateInfo={updateInfo}
            />

            {/* PWA Update Available Banner (only if modal not shown) */}
            {updateAvailable && isOnline && !showUpdateModal && (
                <PWAUpdateBanner onTap={handleUpdate} />
            )}

            {/* Install App Banner */}
            {showInstallBanner && installPrompt && (
                <div className="bg-gradient-to-r from-emerald-500/90 to-teal-500/90 backdrop-blur-sm text-white py-3 px-4 flex items-center justify-between gap-3 animate-fade-slide-up">
                    <div className="flex items-center gap-3">
                        <div className="p-2 bg-white/20 rounded-xl">
                            <Download size={20} />
                        </div>
                        <div>
                            <p className="text-sm font-semibold">Install OverSeek</p>
                            <p className="text-xs text-white/80">Add to home screen for the best experience</p>
                        </div>
                    </div>
                    <div className="flex items-center gap-2">
                        <button
                            onClick={handleInstall}
                            className="px-4 py-1.5 bg-white text-emerald-600 rounded-lg text-sm font-semibold hover:bg-white/90 active:scale-95 transition-all"
                        >
                            Install
                        </button>
                        <button
                            onClick={dismissInstallBanner}
                            className="p-1.5 hover:bg-white/20 rounded-lg transition-colors"
                        >
                            <X size={18} />
                        </button>
                    </div>
                </div>
            )}

            {/* Enhanced Pull-to-refresh indicator */}
            <div
                className="fixed top-0 left-0 right-0 flex flex-col items-center justify-center z-50 overflow-hidden transition-all duration-300 ease-out"
                style={{
                    height: refreshing ? 80 : Math.max(pullDistance, 0),
                    paddingTop: 'env(safe-area-inset-top)',
                    opacity: pullProgress > 0.1 || refreshing ? 1 : 0,
                    background: 'linear-gradient(135deg, rgba(99, 102, 241, 0.95) 0%, rgba(139, 92, 246, 0.95) 100%)',
                }}
            >
                <div className="relative">
                    {/* Outer ring */}
                    <div
                        className={`w-12 h-12 rounded-full border-3 border-white/30 flex items-center justify-center ${refreshing ? '' : 'transition-transform duration-100'
                            }`}
                        style={{
                            transform: refreshing
                                ? 'scale(1)'
                                : `scale(${0.6 + pullProgress * 0.4})`,
                            borderWidth: '3px',
                        }}
                    >
                        {/* Inner spinner/icon */}
                        {refreshing ? (
                            <Loader2 size={24} className="text-white animate-spin" />
                        ) : (
                            <RefreshCw
                                size={22}
                                className="text-white transition-transform duration-100"
                                style={{
                                    transform: `rotate(${pullProgress * 180}deg)`,
                                }}
                            />
                        )}
                    </div>

                    {/* Progress ring */}
                    {!refreshing && pullProgress > 0 && (
                        <svg
                            className="absolute inset-0 w-12 h-12 -rotate-90"
                            viewBox="0 0 48 48"
                        >
                            <circle
                                cx="24"
                                cy="24"
                                r="21"
                                fill="none"
                                stroke="white"
                                strokeWidth="3"
                                strokeLinecap="round"
                                strokeDasharray={`${pullProgress * 132} 132`}
                                className="transition-all duration-100"
                            />
                        </svg>
                    )}
                </div>

                {/* Status text */}
                <span className={`text-white text-xs font-medium mt-2 transition-all duration-200 ${(pullThresholdMet || refreshing) ? 'opacity-100' : 'opacity-0'
                    }`}>
                    {refreshing ? 'Refreshing...' : 'Release to refresh'}
                </span>
            </div>

            {/* Main content with page transitions */}
            <main
                className="flex-1 overflow-x-hidden"
                onTouchStart={handleTouchStart}
                onTouchMove={handleTouchMove}
                onTouchEnd={handleTouchEnd}
            >
                <div
                    className={`p-4 transition-all duration-150 ease-out ${isTransitioning
                        ? 'opacity-0 translate-x-4'
                        : 'opacity-100 translate-x-0'
                        }`}
                >
                    <MobileErrorBoundary>
                        {children || <Outlet />}
                    </MobileErrorBoundary>
                </div>
            </main>

            {/* Bottom navigation with badges */}
            <MobileNav
                activeTab={getActiveTab()}
                inboxBadge={inboxBadge}
                ordersBadge={ordersBadge}
            />
        </div>
    );
}

import { useNavigate } from 'react-router-dom';
import {
    LayoutDashboard,
    ShoppingCart,
    Inbox,
    BarChart3,
    MoreHorizontal
} from 'lucide-react';

/**
 * MobileNav - Premium bottom navigation bar for the PWA.
 * 
 * Features:
 * - Glassmorphism design with blur backdrop
 * - Animated pill indicator
 * - Badge support with pulse animation
 * - Haptic feedback on tap
 */

interface MobileNavProps {
    activeTab: string;
    ordersBadge?: number;
    inboxBadge?: number;
}

interface NavItem {
    id: string;
    label: string;
    path: string;
    icon: typeof LayoutDashboard;
}

const navItems: NavItem[] = [
    { id: 'dashboard', label: 'Home', path: '/m/dashboard', icon: LayoutDashboard },
    { id: 'orders', label: 'Orders', path: '/m/orders', icon: ShoppingCart },
    { id: 'inbox', label: 'Inbox', path: '/m/inbox', icon: Inbox },
    { id: 'analytics', label: 'Analytics', path: '/m/analytics', icon: BarChart3 },
    { id: 'more', label: 'More', path: '/m/more', icon: MoreHorizontal },
];

export function MobileNav({ activeTab, ordersBadge, inboxBadge }: MobileNavProps) {
    const navigate = useNavigate();

    const handleNavClick = (path: string) => {
        // Haptic feedback
        if ('vibrate' in navigator) {
            navigator.vibrate(10);
        }
        navigate(path);
    };

    const getBadge = (id: string): number | undefined => {
        if (id === 'orders') return ordersBadge;
        if (id === 'inbox') return inboxBadge;
        return undefined;
    };

    const activeIndex = navItems.findIndex(item => item.id === activeTab);

    return (
        <nav
            className="fixed bottom-0 left-0 right-0 z-50"
            style={{ paddingBottom: 'env(safe-area-inset-bottom)' }}
        >
            {/* Glassmorphism background */}
            <div className="absolute inset-0 bg-slate-900/80 backdrop-blur-xl border-t border-white/10" />

            {/* Animated pill indicator */}
            <div
                className="absolute top-0 h-0.5 bg-gradient-to-r from-indigo-400 via-purple-400 to-indigo-400 rounded-full transition-all duration-300 ease-out"
                style={{
                    width: `${100 / navItems.length}%`,
                    left: `${(activeIndex / navItems.length) * 100}%`,
                }}
            />

            <div className="relative flex items-center justify-around h-16">
                {navItems.map((item, index) => {
                    const isActive = activeTab === item.id;
                    const badge = getBadge(item.id);
                    const Icon = item.icon;

                    return (
                        <button
                            key={item.id}
                            onClick={() => handleNavClick(item.path)}
                            className={`
                                flex flex-col items-center justify-center flex-1 h-full
                                transition-all duration-200 relative group
                                ${isActive
                                    ? 'text-white'
                                    : 'text-slate-400 active:text-slate-300'
                                }
                            `}
                        >
                            {/* Background glow for active item */}
                            {isActive && (
                                <div className="absolute inset-0 bg-gradient-to-t from-indigo-500/20 to-transparent pointer-events-none" />
                            )}

                            <div className="relative">
                                <div className={`
                                    p-1.5 rounded-xl transition-all duration-200
                                    ${isActive ? 'bg-indigo-500/20 scale-110' : 'group-active:scale-95'}
                                `}>
                                    <Icon
                                        size={22}
                                        strokeWidth={isActive ? 2.5 : 1.8}
                                        className={isActive ? 'drop-shadow-[0_0_8px_rgba(129,140,248,0.5)]' : ''}
                                    />
                                </div>

                                {/* Badge with pulse animation */}
                                {badge !== undefined && badge > 0 && (
                                    <span className="absolute -top-0.5 -right-0.5 min-w-[18px] h-[18px] bg-gradient-to-br from-red-400 to-rose-500 text-white text-[10px] font-bold rounded-full flex items-center justify-center px-1 shadow-lg shadow-red-500/30 animate-pulse">
                                        {badge > 99 ? '99+' : badge}
                                    </span>
                                )}
                            </div>

                            <span className={`
                                text-[10px] mt-0.5 transition-all duration-200
                                ${isActive ? 'font-semibold text-indigo-300' : 'font-medium'}
                            `}>
                                {item.label}
                            </span>
                        </button>
                    );
                })}
            </div>
        </nav>
    );
}

import { useState, useEffect, useMemo, memo } from 'react';
import { NavLink, useLocation } from 'react-router-dom';
import { usePrefetch } from '../../hooks/usePrefetch';
import { usePermissions } from '../../hooks/usePermissions';
import {
    LayoutDashboard,
    ShoppingCart,
    Package,
    Users,
    BarChart3,
    Settings,
    ChevronLeft,
    ChevronRight,
    Megaphone,
    MessageSquare,
    Store,
    PieChart,
    TrendingUp,
    PenTool,
    ChevronDown,
    Star,
    ShieldAlert,
    LineChart,
    DollarSign,
    GitBranch,
    X,
    BookOpen,
    Zap,
    Brain,
    HelpCircle,
    UsersRound,
    Filter,
    TrendingDown,
    RefreshCw,
    Activity,
    Search,
    Bot
} from 'lucide-react';
import { cn } from '../../utils/cn';
import { AccountSwitcher } from './AccountSwitcher';
import { useAccount } from '../../context/AccountContext';
import { useAuth } from '../../context/AuthContext';
import { useSocket } from '../../context/SocketContext';
import { SidebarSyncStatus } from './SidebarSyncStatus';

interface SidebarProps {
    /** Mobile drawer mode - whether sidebar is open */
    isOpen?: boolean;
    /** Callback to close mobile drawer */
    onClose?: () => void;
    /** Whether we're in mobile mode (drawer behavior) */
    isMobile?: boolean;
}

const navItems = [
    { type: 'link', icon: LayoutDashboard, label: 'Dashboard', path: '/dashboard' },
    { type: 'link', icon: MessageSquare, label: 'Inbox', path: '/inbox' },
    {
        type: 'group',
        label: 'Commerce',
        icon: Store,
        children: [
            { icon: ShoppingCart, label: 'Orders', path: '/orders' },
            { icon: Package, label: 'Inventory', path: '/inventory' },
            { icon: RefreshCw, label: 'BOM Sync', path: '/inventory/bom-sync' },
            { icon: TrendingDown, label: 'Forecasts', path: '/inventory/forecasts' },
            { icon: Users, label: 'Customers', path: '/customers' },
            { icon: Filter, label: 'Segments', path: '/customers/segments' },
        ]
    },
    {
        type: 'group',
        label: 'Analytics',
        icon: PieChart,
        children: [
            { icon: LineChart, label: 'Overview', path: '/analytics' },
            { icon: DollarSign, label: 'Revenue', path: '/analytics/revenue' },
            { icon: GitBranch, label: 'Attribution', path: '/analytics/attribution' },
            { icon: TrendingUp, label: 'Cohorts', path: '/analytics/cohorts' },
            { icon: BarChart3, label: 'Acquisition', path: '/live' },
            { icon: BarChart3, label: 'Reports', path: '/reports' },
            { icon: Bot, label: 'Bot Shield', path: '/crawlers' },
        ]
    },
    {
        type: 'group',
        label: 'Growth',
        icon: TrendingUp,
        children: [
            { icon: Brain, label: 'AI Co-Pilot', path: '/marketing/ai' },
            { icon: Megaphone, label: 'Paid Ads', path: '/ads' },
            { icon: Activity, label: 'CAPI Health', path: '/conversions/health' },
            { icon: Zap, label: 'Flows', path: '/flows' },
            { icon: Megaphone, label: 'Broadcasts', path: '/broadcasts' },
            { icon: Star, label: 'Reviews', path: '/reviews' },
            { icon: Search, label: 'SEO Keywords', path: '/seo' },
        ]
    },
    { type: 'link', icon: PenTool, label: 'Invoice Designer', path: '/invoices/design' },
    { type: 'link', icon: BookOpen, label: 'Policies & SOP', path: '/policies' },
    { type: 'link', icon: UsersRound, label: 'Team', path: '/team' },
    { type: 'link', icon: HelpCircle, label: 'Help Center', path: '/help' },
];

/** Why memo: Sidebar subscribes to many contexts; wrapping in memo ensures
 *  it only re-renders when its own props (`isOpen`, `onClose`, `isMobile`) change
 *  rather than on every parent re-render from DashboardLayout. */
export const Sidebar = memo(function Sidebar({ isOpen = true, onClose, isMobile = false }: SidebarProps) {
    const [collapsed, setCollapsed] = useState(false);
    const { currentAccount } = useAccount();
    const { user, token } = useAuth();
    const { socket } = useSocket();
    const { hasPermission } = usePermissions(); // Permission hook
    const { prefetch } = usePrefetch(); // Route prefetching for faster navigation
    const location = useLocation();

    /** Why useMemo: Permission filtering was running on every render (every route change).
     *  Permissions and nav items rarely change — only when user role or account changes. */
    const filteredNavItems = useMemo(() => {
        return navItems.filter(item => {
            if (item.label === 'Commerce') {
                const hasChild = item.children?.some(child => {
                    if (child.path === '/orders') return hasPermission('view_orders');
                    if (child.path === '/inventory' || child.path === '/inventory/forecasts' || child.path === '/inventory/bom-sync') return hasPermission('view_products');
                    if (child.path === '/customers' || child.path === '/customers/segments') return hasPermission('view_orders');
                    return true;
                });
                return hasChild;
            }
            if (item.label === 'Analytics') return hasPermission('view_finance');
            if (item.label === 'Growth') return hasPermission('view_marketing');
            if (item.label === 'Team') return hasPermission('view_orders');
            return true;
        }).map(item => {
            if (item.children) {
                return {
                    ...item,
                    children: item.children.filter(child => {
                        if (child.path === '/orders') return hasPermission('view_orders');
                        if (child.path === '/inventory' || child.path === '/inventory/forecasts' || child.path === '/inventory/bom-sync') return hasPermission('view_products');
                        if (child.path === '/customers' || child.path === '/customers/segments') return hasPermission('view_orders');
                        if (item.label === 'Analytics') return hasPermission('view_finance');
                        if (item.label === 'Growth') return hasPermission('view_marketing');
                        return true;
                    })
                };
            }
            return item;
        });
    }, [hasPermission]);

    // State for expanded groups
    const [expandedGroups, setExpandedGroups] = useState<string[]>([]);

    // State for unread inbox count
    const [hasUnread, setHasUnread] = useState(false);

    // Fetch unread conversations count and listen for new messages
    useEffect(() => {
        if (!currentAccount || !token) return;

        // Check for unread conversations count
        const checkUnread = async () => {
            try {
                const res = await fetch('/api/chat/unread-count', {
                    headers: {
                        'Authorization': `Bearer ${token}`,
                        'x-account-id': currentAccount.id
                    }
                });
                if (res.ok) {
                    const data = await res.json();
                    setHasUnread(data.count > 0);
                }
            } catch {
                // Silently fail
            }
        };

        checkUnread();

        // Listen for new messages via socket
        if (socket) {
            const handleNewMessage = () => {
                // Only set unread if not on inbox page
                if (!location.pathname.startsWith('/inbox')) {
                    setHasUnread(true);
                }
            };

            const handleConversationRead = () => {
                // Re-check unread count when a conversation is marked as read
                checkUnread();
            };

            socket.on('conversation:updated', handleNewMessage);
            socket.on('message:new', handleNewMessage);
            socket.on('conversation:read', handleConversationRead);

            return () => {
                socket.off('conversation:updated', handleNewMessage);
                socket.off('message:new', handleNewMessage);
                socket.off('conversation:read', handleConversationRead);
            };
        }
    }, [currentAccount?.id, token, socket, location.pathname]);

    // Clear unread when on inbox page
    useEffect(() => {
        if (location.pathname.startsWith('/inbox')) {
            // Defer state update to avoid cascading renders
            const timeoutId = setTimeout(() => {
                setHasUnread(false);
            }, 0);
            return () => clearTimeout(timeoutId);
        }
    }, [location.pathname]);

    // Auto-expand groups based on active route
    useEffect(() => {
        const activeGroup = navItems.find(item =>
            item.type === 'group' && item.children?.some(child => location.pathname.startsWith(child.path))
        );
        if (activeGroup && !collapsed) {
            // Defer state update to avoid cascading renders
            const timeoutId = setTimeout(() => {
                // Use functional update to avoid dependency on expandedGroups
                setExpandedGroups(prev => {
                    if (!prev.includes(activeGroup.label)) {
                        return [...prev, activeGroup.label];
                    }
                    return prev;
                });
            }, 0);
            return () => clearTimeout(timeoutId);
        }
    }, [location.pathname, collapsed]);

    // Close drawer on navigation (mobile only)
    useEffect(() => {
        if (isMobile && onClose) {
            // Defer the close to avoid cascading renders
            const timeoutId = setTimeout(() => {
                onClose();
            }, 0);
            return () => clearTimeout(timeoutId);
        }
    }, [location.pathname, isMobile, onClose]);


    const toggleGroup = (label: string) => {
        if (collapsed && !isMobile) {
            setCollapsed(false);
            setExpandedGroups([label]);
        } else {
            setExpandedGroups(prev =>
                prev.includes(label)
                    ? prev.filter(l => l !== label)
                    : [...prev, label]
            );
        }
    };

    const logoUrl = currentAccount?.appearance?.logoUrl;
    const appName = currentAccount?.appearance?.appName || 'OverSeek';
    const primaryColor = currentAccount?.appearance?.primaryColor || '#2563eb';

    // Shared sidebar content - extracted to avoid duplication
    const sidebarContent = (
        <>
            <div className="flex-col px-3 pt-4 pb-2">
                {/* Whitelabel Logo */}
                {logoUrl && (
                    <div className={cn("mb-4 flex justify-center", (collapsed && !isMobile) ? "px-0" : "px-2")}>
                        <img src={logoUrl} alt={appName} className="max-h-8 object-contain" />
                    </div>
                )}

                {/* Account Switcher or Default Logo */}
                {(!collapsed || isMobile) ? (
                    <AccountSwitcher />
                ) : (
                    // Only show default 'O' if no logo is provided
                    !logoUrl && (
                        <div
                            className="h-10 w-10 rounded-sm flex items-center justify-center text-white font-bold mx-auto mb-4"
                            style={{ backgroundColor: primaryColor }}
                        >
                            {appName.charAt(0)}
                        </div>
                    )
                )}
            </div>

            <div className="flex-1 overflow-y-auto py-4 px-3 space-y-1 no-scrollbar">
                {filteredNavItems.map((item, index) => {
                    if (item.type === 'link') {
                        const isInbox = item.label === 'Inbox';
                        return (
                            <NavLink
                                key={item.path}
                                to={item.path!}
                                onMouseEnter={() => prefetch(item.path!)}
                                onFocus={() => prefetch(item.path!)}
                                className={({ isActive }) => cn(
                                    "flex items-center gap-3 px-3 py-2.5 rounded-xl transition-all duration-200 group relative",
                                    isActive
                                        ? "bg-gradient-to-r from-blue-500/10 to-violet-500/10 text-blue-600 font-medium shadow-sm dark:from-blue-500/20 dark:to-violet-500/20"
                                        : "text-slate-600 hover:bg-slate-100/80 hover:text-slate-900 dark:text-slate-400 dark:hover:bg-slate-700/50 dark:hover:text-slate-200"
                                )}
                            >
                                <div className="relative">
                                    <item.icon size={22} strokeWidth={1.5} />
                                    {/* Notification dot for Inbox */}
                                    {isInbox && hasUnread && (
                                        <span className="absolute -top-1 -right-1 h-2.5 w-2.5 bg-red-500 rounded-full ring-2 ring-white" />
                                    )}
                                </div>
                                {(!collapsed || isMobile) && <span>{item.label}</span>}
                                {collapsed && !isMobile && (
                                    <div className="absolute left-full ml-2 px-2 py-1 bg-gray-900 text-white text-xs rounded-sm opacity-0 group-hover:opacity-100 whitespace-nowrap z-50 pointer-events-none">
                                        {item.label}
                                        {isInbox && hasUnread && <span className="ml-1 text-red-400">•</span>}
                                    </div>
                                )}
                            </NavLink>
                        );
                    }


                    // Group Item
                    const isExpanded = expandedGroups.includes(item.label);
                    const isActiveGroup = item.children?.some(child => location.pathname.startsWith(child.path));

                    return (
                        <div key={item.label} className="mb-1">
                            <button
                                onClick={() => toggleGroup(item.label)}
                                className={cn(
                                    "w-full flex items-center gap-3 px-3 py-2.5 rounded-xl transition-all duration-200 group relative",
                                    isActiveGroup && !isExpanded
                                        ? "bg-gradient-to-r from-blue-500/10 to-violet-500/10 text-blue-600 dark:from-blue-500/20 dark:to-violet-500/20"
                                        : "text-slate-600 hover:bg-slate-100/80 hover:text-slate-900 dark:text-slate-400 dark:hover:bg-slate-700/50 dark:hover:text-slate-200"
                                )}
                            >
                                <item.icon size={22} strokeWidth={1.5} className={cn(isActiveGroup ? "text-blue-600" : "")} />
                                {(!collapsed || isMobile) && (
                                    <>
                                        <span className="flex-1 text-left font-medium text-sm">{item.label}</span>
                                        <ChevronDown
                                            size={16}
                                            className={cn("transition-transform duration-200", isExpanded ? "transform rotate-180" : "")}
                                        />
                                    </>
                                )}

                                {/* Collapsed Tooltip/Popover preview */}
                                {collapsed && !isMobile && (
                                    <div className="absolute left-full ml-2 top-0 bg-white border border-gray-200 shadow-lg rounded-lg p-2 min-w-[160px] opacity-0 group-hover:opacity-100 transition-opacity z-50 pointer-events-none group-hover:pointer-events-auto">
                                        <div className="font-semibold text-xs text-gray-400 mb-2 px-2 uppercase">{item.label}</div>
                                        {item.children?.map(child => (
                                            <div key={child.path} className="flex items-center gap-2 px-2 py-1.5 text-sm text-gray-600">
                                                <child.icon size={16} />
                                                <span>{child.label}</span>
                                            </div>
                                        ))}
                                    </div>
                                )}
                            </button>

                            {/* Expanded Children (Only when not collapsed or on mobile) */}
                            {(!collapsed || isMobile) && isExpanded && (
                                <div className="mt-1 ml-4 border-l-2 border-slate-200/60 dark:border-slate-600/40 pl-2 space-y-0.5">
                                    {item.children?.map(child => (
                                        <NavLink
                                            key={child.path}
                                            to={child.path}
                                            end
                                            className={({ isActive }) => cn(
                                                "flex items-center gap-3 px-3 py-2 rounded-lg transition-all duration-200 text-sm",
                                                isActive
                                                    ? "bg-blue-500/10 text-blue-600 font-medium dark:bg-blue-500/20"
                                                    : "text-slate-500 hover:bg-slate-100/80 hover:text-slate-800 dark:text-slate-400 dark:hover:bg-slate-700/50 dark:hover:text-slate-300"
                                            )}
                                        >
                                            <child.icon size={18} strokeWidth={1.5} />
                                            <span>{child.label}</span>
                                        </NavLink>
                                    ))}
                                </div>
                            )}
                        </div>
                    );
                })}

                {user?.isSuperAdmin && (
                    <div className="mt-4 pt-4 border-t border-slate-200/60 dark:border-slate-600/40 space-y-1">
                        <NavLink
                            to="/admin"
                            className={({ isActive }) => cn(
                                "flex items-center gap-3 px-3 py-2.5 rounded-xl transition-all duration-200 group relative",
                                isActive
                                    ? "bg-gradient-to-r from-slate-800 to-slate-700 text-white font-medium shadow-lg shadow-slate-800/25"
                                    : "text-slate-600 hover:bg-slate-100/80 hover:text-slate-900 dark:text-slate-400 dark:hover:bg-slate-700/50 dark:hover:text-slate-200"
                            )}
                        >
                            <ShieldAlert size={22} strokeWidth={1.5} />
                            {(!collapsed || isMobile) && <span>Super Admin</span>}

                            {collapsed && !isMobile && (
                                <div className="absolute left-full ml-2 px-2 py-1 bg-gray-900 text-white text-xs rounded-sm opacity-0 group-hover:opacity-100 whitespace-nowrap z-50 pointer-events-none">
                                    Super Admin
                                </div>
                            )}
                        </NavLink>
                        <NavLink
                            to="/admin/diagnostics"
                            className={({ isActive }) => cn(
                                "flex items-center gap-3 px-3 py-2 rounded-xl transition-all duration-200 group relative text-sm",
                                isActive
                                    ? "bg-gradient-to-r from-emerald-500/10 to-teal-500/10 text-emerald-600 font-medium"
                                    : "text-slate-500 hover:bg-slate-100/80 hover:text-slate-700 dark:text-slate-500 dark:hover:bg-slate-700/50 dark:hover:text-slate-300"
                            )}
                        >
                            <Activity size={18} strokeWidth={1.5} />
                            {(!collapsed || isMobile) && <span>System Health</span>}

                            {collapsed && !isMobile && (
                                <div className="absolute left-full ml-2 px-2 py-1 bg-gray-900 text-white text-xs rounded-sm opacity-0 group-hover:opacity-100 whitespace-nowrap z-50 pointer-events-none">
                                    System Health
                                </div>
                            )}
                        </NavLink>
                    </div>
                )}
            </div>

            <div className="mt-auto px-3 pb-3 space-y-2 border-t border-slate-200/60 dark:border-slate-600/40 pt-3">
                {/* Settings Link (Pinned Bottom) */}
                <NavLink
                    to="/settings"
                    className={({ isActive }) => cn(
                        "flex items-center gap-3 px-3 py-2.5 rounded-xl transition-all duration-200 group relative mb-2",
                        isActive
                            ? "bg-gradient-to-r from-blue-500/10 to-violet-500/10 text-blue-600 font-medium dark:from-blue-500/20 dark:to-violet-500/20"
                            : "text-slate-600 hover:bg-slate-100/80 hover:text-slate-900 dark:text-slate-400 dark:hover:bg-slate-700/50 dark:hover:text-slate-200"
                    )}
                >
                    <Settings size={22} strokeWidth={1.5} />
                    {(!collapsed || isMobile) && <span>Settings</span>}
                    {collapsed && !isMobile && (
                        <div className="absolute left-full ml-2 px-2 py-1 bg-gray-900 text-white text-xs rounded-sm opacity-0 group-hover:opacity-100 whitespace-nowrap z-50 pointer-events-none">
                            Settings
                        </div>
                    )}
                </NavLink>

                <SidebarSyncStatus collapsed={collapsed && !isMobile} />

                {/* Collapse button (desktop only) */}
                {!isMobile && (
                    <button
                        onClick={() => setCollapsed(!collapsed)}
                        className="w-full flex items-center justify-center gap-2 p-2 text-slate-400 hover:bg-slate-100/80 hover:text-slate-600 rounded-xl transition-all duration-200 text-sm dark:hover:bg-slate-700/50 dark:hover:text-slate-300"
                    >
                        {collapsed ? <ChevronRight size={18} /> : <><ChevronLeft size={18} /><span>Collapse</span></>}
                    </button>
                )}
            </div>
        </>
    );

    // Mobile: render as fixed overlay drawer
    if (isMobile) {
        return (
            <>
                {/* Backdrop with blur */}
                {isOpen && (
                    <div
                        className="fixed inset-0 bg-slate-900/30 backdrop-blur-sm z-40 transition-opacity duration-300"
                        onClick={onClose}
                    />
                )}
                <aside
                    className={cn(
                        "fixed inset-y-0 left-0 w-72 flex flex-col z-50 transition-transform duration-300 ease-out",
                        "bg-gradient-to-b from-white to-slate-50 dark:from-slate-900 dark:to-slate-950",
                        "border-r border-slate-200/80 dark:border-slate-700/50",
                        "shadow-2xl shadow-slate-900/10 dark:shadow-slate-900/50",
                        isOpen ? "translate-x-0" : "-translate-x-full"
                    )}
                >
                    {/* Close button for mobile */}
                    <button
                        onClick={onClose}
                        className="absolute top-4 right-4 p-2 text-slate-400 hover:text-slate-600 hover:bg-slate-100 rounded-xl z-10 transition-all duration-200 dark:hover:bg-slate-700/50 dark:hover:text-slate-300"
                    >
                        <X size={20} />
                    </button>
                    {sidebarContent}
                </aside>
            </>
        );
    }

    // Desktop: render as sticky sidebar (CSS hides on mobile via hidden lg:flex)
    return (
        <aside
            className={cn(
                "h-screen sticky top-0 transition-all duration-300 flex-col z-50",
                "bg-gradient-to-b from-white via-white to-slate-50/80 dark:from-slate-900 dark:via-slate-900 dark:to-slate-950",
                "border-r border-slate-200/80 dark:border-slate-700/50",
                "hidden lg:flex", // Critical: CSS-hide on mobile
                collapsed ? "w-20" : "w-64"
            )}
        >
            {sidebarContent}
        </aside>
    );
});

/**
 * Actionable Change Card
 * 
 * Displays detailed actionable recommendations in the bottom grid section.
 * Shows platform, campaign type, score, headline, metrics, and action buttons.
 */

import {
    ArrowRight,
    Eye,
    CheckCircle2
} from 'lucide-react';
import { ActionableRecommendation, isBudgetAction, isKeywordAction } from '../../types/ActionableTypes';

interface ActionableChangeCardProps {
    recommendation: ActionableRecommendation;
    onImplementationGuide: () => void;
    onApply: () => void;
}

/**
 * Get platform badge configuration
 */
function getPlatformConfig(platform: string): { letter: string; bg: string; text: string } {
    switch (platform) {
        case 'google':
            return { letter: 'G', bg: 'bg-gray-100', text: 'text-gray-700' };
        case 'meta':
            return { letter: 'M', bg: 'bg-blue-100', text: 'text-blue-700' };
        default:
            return { letter: 'G', bg: 'bg-gray-100', text: 'text-gray-600' };
    }
}

/**
 * Get campaign type from recommendation
 */
function getCampaignType(rec: ActionableRecommendation): string {
    if (rec.tags?.includes('search')) return 'SEARCH';
    if (rec.tags?.includes('shopping')) return 'SHOPPING';
    if (rec.tags?.includes('pmax')) return 'PMAX';
    if (rec.category === 'creative') return 'CREATIVE';
    if (rec.category === 'budget') return 'BUDGET';
    if (rec.category === 'audience') return 'AUDIENCE';
    return rec.category.toUpperCase();
}

/**
 * Get score color based on value
 */
function getScoreColor(score: number): string {
    if (score >= 80) return 'text-emerald-600';
    if (score >= 60) return 'text-blue-600';
    if (score >= 40) return 'text-amber-600';
    return 'text-gray-500';
}

/**
 * Extract key metrics from recommendation for display
 */
function extractMetrics(rec: ActionableRecommendation): { label: string; value: string; highlight?: boolean }[] {
    const metrics: { label: string; value: string; highlight?: boolean }[] = [];
    const action = rec.action;
    const details = rec.implementationDetails;

    if (isBudgetAction(action)) {
        if (action.actionType === 'budget_increase' || action.actionType === 'budget_decrease') {
            metrics.push({ label: 'Current Budget', value: `$${action.currentBudget.toFixed(0)}` });
            metrics.push({ label: 'Suggested Budget', value: `$${action.suggestedBudget.toFixed(0)}`, highlight: true });
            metrics.push({ label: 'Change', value: `${action.changePercent > 0 ? '+' : ''}${action.changePercent}%` });
        }
    }

    if (isKeywordAction(action)) {
        metrics.push({ label: 'Keyword', value: `"${action.keyword}"` });
        metrics.push({ label: 'Match Type', value: action.matchType });
        metrics.push({ label: 'Suggested CPC', value: `$${action.suggestedCpc.toFixed(2)}`, highlight: true });
    }

    // Add from implementation details
    if (details?.budgetSpec) {
        if (metrics.length === 0) {
            metrics.push({ label: 'Daily Budget', value: `$${details.budgetSpec.dailyBudget}` });
        }
        if (details.budgetSpec.targetRoas) {
            metrics.push({ label: 'Target ROAS', value: `${details.budgetSpec.targetRoas}x`, highlight: true });
        }
    }

    if (details?.suggestedKeywords && details.suggestedKeywords.length > 0) {
        metrics.push({ label: 'Keywords', value: `${details.suggestedKeywords.length} suggested` });
    }

    if (details?.difficulty) {
        const diffLabel = details.difficulty.charAt(0).toUpperCase() + details.difficulty.slice(1);
        metrics.push({ label: 'Difficulty', value: diffLabel });
    }

    // Fill remaining slots with data points
    if (metrics.length < 3 && rec.dataPoints.length > 0) {
        for (const dp of rec.dataPoints) {
            if (metrics.length >= 3) break;
            const parts = dp.split(':');
            if (parts.length === 2) {
                metrics.push({ label: parts[0].trim(), value: parts[1].trim() });
            }
        }
    }

    return metrics.slice(0, 4);
}

export function ActionableChangeCard({
    recommendation,
    onImplementationGuide,
    onApply
}: ActionableChangeCardProps) {
    const platformConfig = getPlatformConfig(recommendation.platform === 'both' ? 'google' : recommendation.platform);
    const campaignType = getCampaignType(recommendation);
    const metrics = extractMetrics(recommendation);
    const hasGuide = !!recommendation.implementationDetails;

    return (
        <div className="bg-white rounded-2xl border border-gray-200 p-5 hover:shadow-lg hover:border-gray-300 transition-all">
            {/* Header */}
            <div className="flex items-center justify-between mb-4">
                <div className="flex items-center gap-2">
                    <span className={`w-6 h-6 rounded-full ${platformConfig.bg} flex items-center justify-center text-xs font-bold ${platformConfig.text}`}>
                        {platformConfig.letter}
                    </span>
                    <span className="text-xs font-medium text-gray-500 uppercase tracking-wider">
                        {campaignType}
                    </span>
                </div>
                <span className={`text-sm font-bold ${getScoreColor(recommendation.confidence)}`}>
                    Score: {recommendation.confidence}
                </span>
            </div>

            {/* Headline */}
            <h3 className="font-bold text-gray-900 mb-4 line-clamp-2">
                {recommendation.headline.replace(/^[^\w]+/, '')}
            </h3>

            {/* Metrics Grid */}
            {metrics.length > 0 && (
                <div className="grid grid-cols-2 gap-x-4 gap-y-2 mb-5">
                    {metrics.map((metric, idx) => (
                        <div key={idx} className="flex justify-between items-baseline">
                            <span className="text-sm text-gray-500">{metric.label}</span>
                            <span className={`text-sm font-semibold ${metric.highlight ? 'text-emerald-600' : 'text-gray-900'}`}>
                                {metric.value}
                            </span>
                        </div>
                    ))}
                </div>
            )}

            {/* Action Button - Always opens guide modal, which handles both cases */}
            <button
                onClick={onImplementationGuide}
                className="w-full py-3 px-4 rounded-xl bg-gray-100 hover:bg-gray-200 text-gray-700 font-medium transition-colors flex items-center justify-center gap-2"
            >
                {hasGuide ? 'Implementation Guide' : 'View Details'}
                {hasGuide ? <ArrowRight className="w-4 h-4" /> : <Eye className="w-4 h-4" />}
            </button>
        </div>
    );
}

import {
    TrendingUp,
    TrendingDown,
    DollarSign,
    Search,
    ShoppingBag,
    Target,
    ArrowRight,
    Check,
    X,
    Calendar,
    AlertTriangle,
    MinusCircle
} from 'lucide-react';
import {
    ActionableRecommendation,
    BudgetAction,
    KeywordAction,
    ProductAction,
    isBudgetAction,
    isKeywordAction,
    isProductAction
} from '../../types/ActionableTypes';

interface ActionableRecommendationCardProps {
    recommendation: ActionableRecommendation;
    onApply?: (recommendation: ActionableRecommendation) => void;
    onDismiss?: (recommendation: ActionableRecommendation) => void;
    onSchedule?: (recommendation: ActionableRecommendation) => void;
}

export function ActionableRecommendationCard({
    recommendation,
    onApply,
    onDismiss,
    onSchedule
}: ActionableRecommendationCardProps) {
    const { action, headline, explanation, dataPoints, priority } = recommendation;

    const getIcon = () => {
        if (isBudgetAction(action)) return <DollarSign className="w-5 h-5" />;
        if (isKeywordAction(action)) return <Search className="w-5 h-5" />;
        if (isProductAction(action)) return <ShoppingBag className="w-5 h-5" />;
        return <Target className="w-5 h-5" />;
    };

    const getColors = () => {
        if (priority === 1) return 'bg-red-50 border-red-200 text-red-700 hover:bg-red-100';
        if (isBudgetAction(action) && action.changeAmount > 0) return 'bg-green-50 border-green-200 text-green-700 hover:bg-green-100';
        if (isBudgetAction(action) && action.changeAmount < 0) return 'bg-amber-50 border-amber-200 text-amber-700 hover:bg-amber-100';
        return 'bg-blue-50 border-blue-200 text-blue-700 hover:bg-blue-100';
    };

    const getImpactText = () => {
        if (!recommendation.estimatedImpact) return null;
        const { revenueChange, roasChange, spendChange } = recommendation.estimatedImpact;

        if (revenueChange) return `+${revenueChange.toLocaleString('en-US', { style: 'currency', currency: 'USD' })} est. revenue`;
        if (roasChange) return `+${roasChange.toFixed(1)}x est. ROAS`;
        if (spendChange && spendChange < 0) return `${spendChange.toLocaleString('en-US', { style: 'currency', currency: 'USD' })} spend savings`;
        return null;
    };

    const renderActionDetails = () => {
        if (isBudgetAction(action)) {
            return (
                <div className="mt-3 flex items-center gap-4 text-sm">
                    <div className="flex flex-col">
                        <span className="text-gray-500 uppercase text-xs font-bold tracking-wider">Current</span>
                        <span className="font-mono text-gray-700">${action.currentBudget.toFixed(2)}</span>
                    </div>
                    <div className="flex flex-col">
                        <span className="text-gray-500 uppercase text-xs font-bold tracking-wider">Suggested</span>
                        <span className="font-mono font-bold text-green-600">${action.suggestedBudget.toFixed(2)}</span>
                    </div>
                    <div className="flex flex-col">
                        <span className="text-gray-500 uppercase text-xs font-bold tracking-wider">Change</span>
                        <span className={`font-mono font-bold ${action.changeAmount > 0 ? 'text-green-600' : 'text-amber-600'}`}>
                            {action.changeAmount > 0 ? '+' : ''}{action.changeAmount.toFixed(0)} (${Math.abs(action.changePercent)}%)
                        </span>
                    </div>
                </div>
            );
        }

        if (isKeywordAction(action)) {
            return (
                <div className="mt-3 flex items-center gap-4 text-sm">
                    <div className="flex flex-col">
                        <span className="text-gray-500 uppercase text-xs font-bold tracking-wider">Keyword</span>
                        <span className="font-mono text-gray-700 border px-1 rounded bg-gray-50">{action.keyword}</span>
                    </div>
                    <div className="flex flex-col">
                        <span className="text-gray-500 uppercase text-xs font-bold tracking-wider">Match</span>
                        <span className="text-gray-700">{action.matchType}</span>
                    </div>
                    <div className="flex flex-col">
                        <span className="text-gray-500 uppercase text-xs font-bold tracking-wider">Max CPC</span>
                        <span className="font-mono font-bold text-blue-600">${action.suggestedCpc.toFixed(2)}</span>
                    </div>
                </div>
            );
        }

        if (isProductAction(action)) {
            return (
                <div className="mt-3 flex items-center gap-4 text-sm">
                    <div className="flex flex-col">
                        <span className="text-gray-500 uppercase text-xs font-bold tracking-wider">Velocity</span>
                        <span className="font-mono text-gray-700">{action.salesVelocity?.toFixed(1)}/day</span>
                    </div>
                    {action.margin && (
                        <div className="flex flex-col">
                            <span className="text-gray-500 uppercase text-xs font-bold tracking-wider">Margin</span>
                            <span className="font-mono text-green-600">{action.margin.toFixed(0)}%</span>
                        </div>
                    )}
                </div>
            );
        }
        return null;
    };

    return (
        <div className="group relative bg-white/80 backdrop-blur-xl border border-white/20 shadow-sm hover:shadow-md rounded-2xl p-5 transition-all duration-300">
            {/* Glassmorphism gradient glow on hover */}
            <div className={`absolute inset-0 rounded-2xl opacity-0 group-hover:opacity-5 transition-opacity duration-300 ${getColors().split(' ')[0]}`}></div>

            <div className="relative flex justify-between items-start gap-4">
                <div className="flex-1">
                    <div className="flex items-center gap-2 mb-2">
                        <div className={`p-2 rounded-lg ${getColors()}`}>
                            {getIcon()}
                        </div>
                        <span className="text-xs font-bold uppercase tracking-wider text-gray-400">
                            {recommendation.platform} • {recommendation.category}
                        </span>
                        {priority === 1 && (
                            <span className="bg-red-100 text-red-700 text-xs px-2 py-0.5 rounded-full font-bold flex items-center gap-1">
                                <AlertTriangle className="w-3 h-3" /> Urgent
                            </span>
                        )}
                        {getImpactText() && (
                            <span className="bg-green-100 text-green-700 text-xs px-2 py-0.5 rounded-full font-bold flex items-center gap-1">
                                <TrendingUp className="w-3 h-3" /> {getImpactText()}
                            </span>
                        )}
                    </div>

                    <h3 className="text-lg font-bold text-gray-900 leading-tight mb-1">
                        {headline}
                    </h3>

                    <p className="text-gray-600 text-sm leading-relaxed mb-3">
                        {explanation}
                    </p>

                    {/* Data Points */}
                    {dataPoints.length > 0 && (
                        <div className="flex flex-wrap gap-2 mt-2">
                            {dataPoints.map((dp, idx) => (
                                <span key={idx} className="inline-flex items-center px-2 py-1 rounded bg-gray-100 text-gray-600 text-xs font-medium">
                                    {dp}
                                </span>
                            ))}
                        </div>
                    )}

                    {renderActionDetails()}
                </div>

                {/* Action Buttons */}
                <div className="flex flex-col gap-2 min-w-[120px]">
                    <button
                        onClick={() => onApply?.(recommendation)}
                        className="w-full py-2 px-3 bg-blue-600 hover:bg-blue-700 text-white text-sm font-semibold rounded-lg shadow-sm transition-colors flex items-center justify-center gap-2"
                    >
                        <Check className="w-4 h-4" /> Apply
                    </button>
                    {isBudgetAction(action) && (
                        <button
                            onClick={() => onSchedule?.(recommendation)}
                            className="w-full py-2 px-3 bg-white border border-gray-200 hover:bg-gray-50 text-gray-700 text-sm font-medium rounded-lg transition-colors flex items-center justify-center gap-2"
                        >
                            <Calendar className="w-4 h-4" /> Schedule
                        </button>
                    )}
                    <button
                        onClick={() => onDismiss?.(recommendation)}
                        className="w-full py-2 px-3 text-gray-400 hover:text-gray-600 hover:bg-gray-50 text-sm font-medium rounded-lg transition-colors flex items-center justify-center gap-2"
                    >
                        <X className="w-4 h-4" /> Dismiss
                    </button>
                </div>
            </div>

            {/* Confidence indicator */}
            <div className="absolute top-4 right-4" title={`Confidence: ${recommendation.confidence}%`}>
                <div className="relative w-8 h-8 flex items-center justify-center">
                    <svg className="w-full h-full transform -rotate-90">
                        <circle
                            cx="16"
                            cy="16"
                            r="14"
                            className="stroke-gray-100"
                            strokeWidth="3"
                            fill="none"
                        />
                        <circle
                            cx="16"
                            cy="16"
                            r="14"
                            className={`${recommendation.confidence > 80 ? 'stroke-green-500' : 'stroke-blue-500'}`}
                            strokeWidth="3"
                            fill="none"
                            strokeDasharray={88}
                            strokeDashoffset={88 - (88 * recommendation.confidence) / 100}
                        />
                    </svg>
                    <span className="absolute text-[10px] font-bold text-gray-500">
                        {recommendation.confidence}
                    </span>
                </div>
            </div>
        </div>
    );
}

import { useState, useEffect } from 'react';
import { Logger } from '../../utils/logger';
import { Lightbulb, Loader2 } from 'lucide-react';
import { Modal } from '../ui/Modal';
import { useAuth } from '../../context/AuthContext';
import { useAccount } from '../../context/AccountContext';

interface AdContextModalProps {
    isOpen: boolean;
    onClose: () => void;
    onSaved?: () => void;
}

/**
 * Modal for providing additional business context to AI ad suggestions.
 * Context is saved per-account and used by the AdOptimizer.
 */
export function AdContextModal({ isOpen, onClose, onSaved }: AdContextModalProps) {
    const { token } = useAuth();
    const { currentAccount } = useAccount();
    const [context, setContext] = useState('');
    const [loading, setLoading] = useState(true);
    const [saving, setSaving] = useState(false);
    const [error, setError] = useState<string | null>(null);

    useEffect(() => {
        if (isOpen && currentAccount) {
            fetchContext();
        }
    }, [isOpen, currentAccount]);

    async function fetchContext() {
        setLoading(true);
        setError(null);
        try {
            const res = await fetch('/api/dashboard/ad-suggestions/context', {
                headers: {
                    'Authorization': `Bearer ${token}`,
                    'x-account-id': currentAccount?.id || ''
                }
            });
            if (res.ok) {
                const data = await res.json();
                setContext(data.context || '');
            }
        } catch (err) {
            Logger.error('Failed to fetch context', { error: err });
        } finally {
            setLoading(false);
        }
    }

    async function handleSave() {
        setSaving(true);
        setError(null);
        try {
            const res = await fetch('/api/dashboard/ad-suggestions/context', {
                method: 'POST',
                headers: {
                    'Content-Type': 'application/json',
                    'Authorization': `Bearer ${token}`,
                    'x-account-id': currentAccount?.id || ''
                },
                body: JSON.stringify({ context })
            });

            if (res.ok) {
                onSaved?.();
                onClose();
            } else {
                const data = await res.json();
                setError(data.error || 'Failed to save');
            }
        } catch (err) {
            setError('Failed to save context');
        } finally {
            setSaving(false);
        }
    }

    return (
        <Modal
            isOpen={isOpen}
            onClose={onClose}
            title={
                <div className="flex items-center gap-3">
                    <div className="p-2 bg-purple-500 rounded-lg">
                        <Lightbulb size={20} className="text-white" />
                    </div>
                    <div>
                        <div className="font-semibold text-gray-900">Add Business Context</div>
                        <p className="text-sm text-gray-500 font-normal">Help AI give smarter suggestions</p>
                    </div>
                </div>
            }
            maxWidth="max-w-lg"
        >
            {loading ? (
                <div className="flex justify-center py-8">
                    <Loader2 className="w-8 h-8 animate-spin text-purple-500" />
                </div>
            ) : (
                <>
                    <label className="block text-sm font-medium text-gray-700 mb-2">
                        Your Notes & Context
                    </label>
                    <textarea
                        value={context}
                        onChange={(e) => setContext(e.target.value)}
                        placeholder="E.g., We're running a 30% off sale next week on summer products. Focus on our new arrivals. Our best margin is on jewelry..."
                        className="w-full h-40 px-4 py-3 border border-gray-300 rounded-xl focus:ring-2 focus:ring-purple-500 focus:border-purple-500 resize-none text-gray-800 placeholder:text-gray-400"
                        maxLength={1000}
                    />
                    <p className="text-xs text-gray-400 mt-2 text-right">
                        {context.length}/1000 characters
                    </p>

                    <div className="mt-4 p-4 bg-purple-50 rounded-lg border border-purple-100">
                        <h4 className="text-sm font-medium text-purple-800 mb-2">💡 Tips for better suggestions</h4>
                        <ul className="text-sm text-purple-700 space-y-1">
                            <li>• Mention upcoming sales or promotions</li>
                            <li>• Note seasonal priorities (e.g., "Push winter coats")</li>
                            <li>• Share margin preferences ("Focus on high-margin items")</li>
                            <li>• Flag products to avoid ("Don't promote discontinued line")</li>
                        </ul>
                    </div>

                    {error && (
                        <p className="mt-4 text-sm text-red-600">{error}</p>
                    )}
                </>
            )}

            {/* Footer */}
            <div className="flex justify-end gap-3 pt-4 mt-4 border-t">
                <button
                    onClick={onClose}
                    className="px-4 py-2 text-gray-700 hover:bg-gray-100 rounded-lg transition-colors"
                    disabled={saving}
                >
                    Cancel
                </button>
                <button
                    onClick={handleSave}
                    disabled={loading || saving}
                    className="px-4 py-2 bg-purple-600 text-white rounded-lg hover:bg-purple-700 transition-colors disabled:opacity-50 disabled:cursor-not-allowed flex items-center gap-2"
                >
                    {saving && <Loader2 size={16} className="animate-spin" />}
                    Save Context
                </button>
            </div>
        </Modal>
    );
}

import { useEffect, useState, useCallback } from 'react';
import { Logger } from '../../utils/logger';
import { useAuth } from '../../context/AuthContext';
import { useAccount } from '../../context/AccountContext';
import { GoogleAdsCampaigns } from './GoogleAdsCampaigns';
import { Loader2, Megaphone, Plus, RefreshCw, AlertCircle } from 'lucide-react';

interface AdAccount {
    id: string;
    platform: string;
    name: string;
    externalId: string;
}

/**
 * AdPerformanceView displays campaign performance for connected ad accounts.
 * Each account is shown as a sub-tab, with the campaign breakdown displayed below.
 */
export function AdPerformanceView() {
    const { token } = useAuth();
    const { currentAccount } = useAccount();
    const [accounts, setAccounts] = useState<AdAccount[]>([]);
    const [isLoading, setIsLoading] = useState(true);
    const [selectedAccountId, setSelectedAccountId] = useState<string | null>(null);

    /**
     * Initiate OAuth for reconnecting an expired ad account.
     * Why separate from settings: users land on /ads from the sidebar and
     * need to reconnect without navigating to settings first.
     */
    const handleReconnect = useCallback(async (accountId: string, platform: string) => {
        if (!currentAccount) return;
        try {
            const endpoint = platform === 'GOOGLE'
                ? '/api/oauth/google/authorize'
                : '/api/oauth/meta/ads/authorize';
            const params = new URLSearchParams({
                redirect: '/ads',
                reconnectId: accountId
            });
            const res = await fetch(`${endpoint}?${params.toString()}`, {
                headers: { 'Authorization': `Bearer ${token}`, 'X-Account-ID': currentAccount.id }
            });
            const data = await res.json();
            if (data.authUrl) window.location.href = data.authUrl;
        } catch (err) {
            Logger.error('Failed to initiate reconnect', { error: err });
        }
    }, [currentAccount, token]);

    useEffect(() => {
        fetchAccounts();
    }, [currentAccount, token]);

    async function fetchAccounts() {
        if (!currentAccount) return;
        try {
            const res = await fetch('/api/ads', {
                headers: { 'Authorization': `Bearer ${token}`, 'X-Account-ID': currentAccount.id }
            });
            const data = await res.json();
            // Filter out accounts with pending setup
            const activeAccounts = Array.isArray(data)
                ? data.filter((acc: AdAccount) => acc.externalId !== 'PENDING_SETUP')
                : [];
            setAccounts(activeAccounts);
            // Auto-select first account if none selected
            if (activeAccounts.length > 0 && !selectedAccountId) {
                setSelectedAccountId(activeAccounts[0].id);
            }
        } catch (err) {
            Logger.error('Failed to fetch ad accounts:', { error: err });
        } finally {
            setIsLoading(false);
        }
    }

    if (isLoading) {
        return (
            <div className="flex items-center justify-center h-64">
                <Loader2 className="w-8 h-8 animate-spin text-blue-500" />
            </div>
        );
    }

    if (accounts.length === 0) {
        return (
            <div className="text-center py-16 bg-gray-50 rounded-xl border border-dashed border-gray-300">
                <div className="w-16 h-16 mx-auto mb-4 bg-gray-100 rounded-full flex items-center justify-center">
                    <Megaphone className="w-8 h-8 text-gray-400" />
                </div>
                <h3 className="text-lg font-semibold text-gray-900 mb-2">No Ad Accounts Connected</h3>
                <p className="text-gray-500 mb-4">Connect your ad accounts to see campaign performance data.</p>
                <a
                    href="/marketing?tab=ads"
                    className="inline-flex items-center gap-2 px-4 py-2 bg-blue-600 text-white rounded-lg hover:bg-blue-700 transition-colors"
                >
                    <Plus size={18} />
                    Connect Ad Account
                </a>
            </div>
        );
    }

    const selectedAccount = accounts.find(acc => acc.id === selectedAccountId);

    return (
        <div className="space-y-6">
            {/* Sub-tabs for each ad account */}
            <div className="flex gap-2 overflow-x-auto pb-2">
