    rightActions = [
        { icon: <Archive size={20} />, label: 'Archive', color: 'bg-blue-500', onClick: () => { } },
        { icon: <Trash2 size={20} />, label: 'Delete', color: 'bg-rose-500', onClick: () => { } }
    ],
    className = ''
}: SwipeableListItemProps) {
    const [translateX, setTranslateX] = useState(0);
    const [isOpen, setIsOpen] = useState<'left' | 'right' | null>(null);
    const startX = useRef(0);
    const currentX = useRef(0);
    const isDragging = useRef(false);

    const ACTION_WIDTH = 72;
    const maxSwipeLeft = -rightActions.length * ACTION_WIDTH;
    const maxSwipeRight = leftActions.length * ACTION_WIDTH;

    const handleTouchStart = (e: React.TouchEvent) => {
        startX.current = e.touches[0].clientX;
        currentX.current = translateX;
        isDragging.current = true;
    };

    const handleTouchMove = (e: React.TouchEvent) => {
        if (!isDragging.current) return;

        const deltaX = e.touches[0].clientX - startX.current;
        let newX = currentX.current + deltaX;

        // Apply elastic resistance at boundaries
        if (newX > maxSwipeRight) {
            newX = maxSwipeRight + (newX - maxSwipeRight) * 0.2;
        } else if (newX < maxSwipeLeft) {
            newX = maxSwipeLeft + (newX - maxSwipeLeft) * 0.2;
        }

        setTranslateX(newX);
    };

    const handleTouchEnd = () => {
        isDragging.current = false;

        // Snap to open or closed state
        const threshold = ACTION_WIDTH / 2;

        if (translateX < -threshold && rightActions.length > 0) {
            setTranslateX(maxSwipeLeft);
            setIsOpen('right');
            if ('vibrate' in navigator) navigator.vibrate(5);
        } else if (translateX > threshold && leftActions.length > 0) {
            setTranslateX(maxSwipeRight);
            setIsOpen('left');
            if ('vibrate' in navigator) navigator.vibrate(5);
        } else {
            setTranslateX(0);
            setIsOpen(null);
        }
    };

    const handleClose = () => {
        setTranslateX(0);
        setIsOpen(null);
    };

    const handleActionClick = (action: SwipeAction) => {
        if ('vibrate' in navigator) navigator.vibrate(10);
        action.onClick();
        handleClose();
    };

    return (
        <div className={`relative overflow-hidden ${className}`}>
            {/* Left Actions (revealed on swipe right) */}
            {leftActions.length > 0 && (
                <div
                    className="absolute left-0 top-0 bottom-0 flex"
                    style={{ width: leftActions.length * ACTION_WIDTH }}
                >
                    {leftActions.map((action, index) => (
                        <button
                            key={index}
                            onClick={() => handleActionClick(action)}
                            className={`flex-1 flex flex-col items-center justify-center ${action.color} text-white active:opacity-80 transition-opacity`}
                        >
                            {action.icon}
                            <span className="text-[10px] mt-1 font-medium">{action.label}</span>
                        </button>
                    ))}
                </div>
            )}

            {/* Right Actions (revealed on swipe left) */}
            {rightActions.length > 0 && (
                <div
                    className="absolute right-0 top-0 bottom-0 flex"
                    style={{ width: rightActions.length * ACTION_WIDTH }}
                >
                    {rightActions.map((action, index) => (
                        <button
                            key={index}
                            onClick={() => handleActionClick(action)}
                            className={`flex-1 flex flex-col items-center justify-center ${action.color} text-white active:opacity-80 transition-opacity`}
                        >
                            {action.icon}
                            <span className="text-[10px] mt-1 font-medium">{action.label}</span>
                        </button>
                    ))}
                </div>
            )}

            {/* Main Content */}
            <div
                className="relative bg-slate-800/50 backdrop-blur-sm border border-white/10 transition-transform duration-200 ease-out"
                style={{
                    transform: `translateX(${translateX}px)`,
                    transitionDuration: isDragging.current ? '0ms' : '200ms'
                }}
                onTouchStart={handleTouchStart}
                onTouchMove={handleTouchMove}
                onTouchEnd={handleTouchEnd}
            >
                {children}

                {/* Close hint when open */}
                {isOpen && (
                    <button
                        onClick={handleClose}
                        className="absolute right-2 top-1/2 -translate-y-1/2 p-2 rounded-full bg-white/10 active:bg-white/20"
                    >
                        <MoreHorizontal size={16} className="text-slate-400" />
                    </button>
                )}
            </div>
        </div>
    );
}

/**
 * Simple swipe detection hook
 */
export function useSwipeGesture(
    onSwipeLeft?: () => void,
    onSwipeRight?: () => void,
    threshold = 50
) {
    const startX = useRef(0);

    const handleTouchStart = (e: React.TouchEvent) => {
        startX.current = e.touches[0].clientX;
    };

    const handleTouchEnd = (e: React.TouchEvent) => {
        const endX = e.changedTouches[0].clientX;
        const deltaX = endX - startX.current;

        if (Math.abs(deltaX) > threshold) {
            if (deltaX > 0 && onSwipeRight) {
                onSwipeRight();
            } else if (deltaX < 0 && onSwipeLeft) {
                onSwipeLeft();
            }
        }
    };

    return { handleTouchStart, handleTouchEnd };
}

/**
 * Plugin Step
 * 
 * Second step in onboarding: Download and configure the OverSeek WooCommerce plugin.
 * Includes plugin download, configuration copy, and verification.
 */

import React, { useState } from 'react';
import { Plug, ArrowRight, ArrowLeft, SkipForward, Download, Copy, Check, Store, ExternalLink, AlertCircle, Loader2 } from 'lucide-react';
import { OnboardingStepProps } from '../types';
import { useAuth } from '../../../context/AuthContext';
import { useAccount } from '../../../context/AccountContext';
import { api } from '../../../services/api';
import { Logger } from '../../../utils/logger';
import { getPublicApiUrl } from '../../../utils/url';

interface StoreVerificationResult {
    success: boolean;
    storeUrl?: string;
    storeName?: string;
    storeReachable: boolean;
    pluginInstalled: boolean;
    pluginVersion?: string;
    configured?: boolean;
    accountMatch?: boolean;
    trackingEnabled?: boolean;
    chatEnabled?: boolean;
    error?: string;
}

/**
 * Handles plugin download, configuration copy, and store verification.
 */
export function PluginStep({ draft, setDraft, onNext, onBack, onSkip, isSubmitting }: OnboardingStepProps) {
    const { token } = useAuth();
    const { currentAccount } = useAccount();
    const [configCopied, setConfigCopied] = useState(false);
    const [webhookCopied, setWebhookCopied] = useState(false);
    const [verifyStatus, setVerifyStatus] = useState<'idle' | 'loading' | 'success' | 'error'>('idle');
    const [verifyResult, setVerifyResult] = useState<StoreVerificationResult | null>(null);

    // Public API URL for external clients (derived from browser location)
    const publicApiUrl = getPublicApiUrl();

    // Guard: Account must exist before showing plugin config
    // Previously, accountId fallback used store name or 'pending' which broke APIs
    const hasValidAccount = Boolean(currentAccount?.id);

    // Generate the configuration JSON that users paste into the plugin
    // Only valid when account exists (accountId must be a UUID, not store name)
    const connectionConfig = hasValidAccount ? JSON.stringify({
        apiUrl: publicApiUrl,
        accountId: currentAccount!.id
    }, null, 2) : '';

    const handleDownload = () => {
        setDraft(prev => ({
            ...prev,
            plugin: { ...prev.plugin, downloaded: true }
        }));
    };

    const handleCopyConfig = () => {
        navigator.clipboard.writeText(connectionConfig);
        setConfigCopied(true);
        setDraft(prev => ({
            ...prev,
            plugin: { ...prev.plugin, configCopied: true }
        }));
        setTimeout(() => setConfigCopied(false), 2000);
    };

    const verifyStore = async () => {
        setVerifyStatus('loading');
        setVerifyResult(null);

        try {
            const result = await api.get<StoreVerificationResult>(
                '/api/tracking/verify-store',
                token || undefined,
                currentAccount?.id || ''
            );

            setVerifyResult(result);
            setVerifyStatus(result.success ? 'success' : 'error');

            if (result.success) {
                setDraft(prev => ({
                    ...prev,
                    plugin: {
                        ...prev.plugin,
                        verified: true,
                        pluginVersion: result.pluginVersion
                    }
                }));
            }
        } catch (error) {
            Logger.error('Store verification failed', { error });
            setVerifyStatus('error');
            setVerifyResult({
                success: false,
                storeReachable: false,
                pluginInstalled: false,
                error: 'Failed to verify store connection'
            });
        }
    };

    return (
        <div className="space-y-6">
            {/* Header */}
            <div className="text-center pb-4 border-b border-gray-100">
                <div className="inline-flex items-center justify-center w-16 h-16 rounded-2xl bg-purple-100 text-purple-600 mb-4">
                    <Plug size={32} />
                </div>
                <h2 className="text-2xl font-bold text-gray-900">Install the Plugin</h2>
                <p className="text-gray-500 mt-2">
                    The OverSeek plugin enables live tracking, chat, and order sync
                </p>
            </div>

            {/* Steps */}
            <div className="space-y-6">
                {/* Step 1: Download */}
                <div className="bg-blue-50 rounded-xl p-5 border border-blue-200">
                    <div className="flex items-start gap-4">
                        <div className="flex-shrink-0 w-8 h-8 rounded-full bg-blue-600 text-white flex items-center justify-center text-sm font-bold">
                            1
                        </div>
                        <div className="flex-1">
                            <h3 className="text-sm font-semibold text-gray-900 mb-1">Download the Plugin</h3>
                            <p className="text-xs text-gray-600 mb-3">
                                Download the OverSeek plugin ZIP file and install it on your WordPress site via Plugins → Add New → Upload Plugin.
                            </p>
                            <a
                                href={`${publicApiUrl}/uploads/plugins/overseek-wc-plugin.zip`}
                                download
                                onClick={handleDownload}
                                className="inline-flex items-center gap-2 px-4 py-2 bg-blue-600 text-white rounded-lg text-sm font-medium hover:bg-blue-700 transition-colors"
                            >
                                <Download size={16} />
                                Download Plugin
                            </a>
                            {draft.plugin.downloaded && (
                                <span className="ml-3 text-sm text-green-600 inline-flex items-center gap-1">
                                    <Check size={14} /> Downloaded
                                </span>
                            )}
                        </div>
                    </div>
                </div>

                {/* Step 2: Configure */}
                <div className="bg-slate-50 rounded-xl p-5 border border-slate-200">
                    <div className="flex items-start gap-4">
                        <div className="flex-shrink-0 w-8 h-8 rounded-full bg-slate-600 text-white flex items-center justify-center text-sm font-bold">
                            2
                        </div>
                        <div className="flex-1">
                            <h3 className="text-sm font-semibold text-gray-900 mb-1">Configure the Plugin</h3>
                            <p className="text-xs text-gray-600 mb-3">
                                After activating the plugin, go to OverSeek settings and paste this configuration:
                            </p>

                            {/* Guard: Only show config when account exists */}
                            {hasValidAccount ? (
                                <div className="relative group">
                                    <button
                                        onClick={handleCopyConfig}
                                        className={`absolute top-2 right-2 flex items-center gap-1.5 px-3 py-1.5 rounded-md text-xs font-medium transition-colors ${configCopied
                                            ? 'bg-green-100 text-green-700 border border-green-200'
                                            : 'bg-white text-gray-700 hover:bg-gray-50 border border-gray-200'
                                            }`}
                                    >
                                        {configCopied ? <Check size={14} /> : <Copy size={14} />}
                                        {configCopied ? 'Copied!' : 'Copy'}
                                    </button>
                                    <pre className="bg-slate-900 text-slate-100 p-4 pr-24 rounded-lg overflow-x-auto font-mono text-sm">
                                        <code>{connectionConfig}</code>
                                    </pre>
                                </div>
                            ) : (
                                <div className="p-4 bg-amber-50 border border-amber-200 rounded-lg">
                                    <div className="flex items-center gap-2 text-amber-800">
                                        <AlertCircle size={16} />
                                        <span className="text-sm font-medium">Store setup required</span>
                                    </div>
                                    <p className="text-xs text-amber-700 mt-1">
                                        Please complete the Store Setup step first to generate your configuration.
                                    </p>
                                </div>
                            )}
                        </div>
                    </div>
                </div>

                {/* Webhook URL Info */}
                {hasValidAccount && (
                    <div className="bg-indigo-50 rounded-xl p-5 border border-indigo-200">
                        <div className="flex items-start gap-4">
                            <div className="flex-shrink-0 w-8 h-8 rounded-full bg-indigo-600 text-white flex items-center justify-center text-sm font-bold">
                                ↻
                            </div>
                            <div className="flex-1">
                                <h3 className="text-sm font-semibold text-gray-900 mb-1">Webhook URL</h3>
                                <p className="text-xs text-gray-600 mb-3">
                                    To receive real-time order updates, add a webhook in WooCommerce → Settings → Advanced → Webhooks → Add Webhook. Use this URL as the <strong>Delivery URL</strong>:
                                </p>
                                <div className="relative group">
                                    <button
                                        onClick={() => {
                                            navigator.clipboard.writeText(`${publicApiUrl}/api/webhooks/${currentAccount!.id}`);
                                            setWebhookCopied(true);
                                            setTimeout(() => setWebhookCopied(false), 2000);
                                        }}
                                        className={`absolute top-2 right-2 flex items-center gap-1.5 px-3 py-1.5 rounded-md text-xs font-medium transition-colors ${webhookCopied
                                            ? 'bg-green-100 text-green-700 border border-green-200'
                                            : 'bg-white text-gray-700 hover:bg-gray-50 border border-gray-200'
                                            }`}
                                    >
                                        {webhookCopied ? <Check size={14} /> : <Copy size={14} />}
                                        {webhookCopied ? 'Copied!' : 'Copy'}
                                    </button>
                                    <pre className="bg-slate-900 text-slate-100 p-4 pr-24 rounded-lg overflow-x-auto font-mono text-xs break-all whitespace-pre-wrap">
                                        <code>{`${publicApiUrl}/api/webhooks/${currentAccount!.id}`}</code>
                                    </pre>
                                </div>
                                <p className="text-xs text-indigo-600 mt-2">
                                    Set topics to <strong>Order created</strong> and <strong>Order updated</strong> for real-time sync.
                                </p>
                            </div>
                        </div>
                    </div>
                )}

                {/* Step 3: Verify */}
                <div className="bg-green-50 rounded-xl p-5 border border-green-200">
                    <div className="flex items-start gap-4">
                        <div className="flex-shrink-0 w-8 h-8 rounded-full bg-green-600 text-white flex items-center justify-center text-sm font-bold">
                            3
                        </div>
                        <div className="flex-1">
                            <h3 className="text-sm font-semibold text-gray-900 mb-1">Verify Installation</h3>
                            <p className="text-xs text-gray-600 mb-3">
                                Click below to check if the plugin is installed and configured correctly.
                            </p>
                            <button
                                onClick={verifyStore}
                                disabled={verifyStatus === 'loading' || !hasValidAccount}
                                className="inline-flex items-center gap-2 px-4 py-2 bg-green-600 text-white rounded-lg text-sm font-medium hover:bg-green-700 disabled:opacity-50 transition-colors"
                            >
                                {verifyStatus === 'loading' ? (
                                    <Loader2 size={16} className="animate-spin" />
                                ) : (
                                    <Store size={16} />
                                )}
                                {verifyStatus === 'loading' ? 'Verifying...' : 'Verify Store Plugin'}
                            </button>

                            {/* Verification Result */}
                            {verifyResult && (
                                <div className={`mt-4 p-4 rounded-lg border ${verifyResult.success
                                    ? 'bg-green-100 border-green-300'
                                    : 'bg-amber-100 border-amber-300'
                                    }`}>
                                    <div className="flex items-start gap-3">
                                        {verifyResult.success ? (
                                            <Check className="w-5 h-5 text-green-600 shrink-0" />
                                        ) : (
                                            <AlertCircle className="w-5 h-5 text-amber-600 shrink-0" />
                                        )}
                                        <div className="text-sm">
                                            <p className={`font-semibold ${verifyResult.success ? 'text-green-800' : 'text-amber-800'}`}>
                                                {verifyResult.success ? 'Plugin Verified!' : 'Setup Required'}
                                            </p>
                                            {verifyResult.error && (
                                                <p className="text-amber-700 mt-1">{verifyResult.error}</p>
                                            )}
                                            {verifyResult.success && (
                                                <div className="grid grid-cols-2 gap-2 mt-2 text-xs">
                                                    <div className="flex items-center gap-2">
                                                        <span className="w-2 h-2 rounded-full bg-green-500" />
                                                        Plugin: {verifyResult.pluginVersion || 'Installed'}
                                                    </div>
                                                    <div className="flex items-center gap-2">
                                                        <span className={`w-2 h-2 rounded-full ${verifyResult.trackingEnabled ? 'bg-green-500' : 'bg-amber-500'}`} />
                                                        Tracking: {verifyResult.trackingEnabled ? 'Enabled' : 'Disabled'}
                                                    </div>
                                                </div>
                                            )}
                                        </div>
                                    </div>
                                </div>
                            )}
                        </div>
                    </div>
                </div>
            </div>

            {/* Navigation */}
            <div className="flex items-center justify-between pt-4 border-t border-gray-100">
                <button
                    type="button"
                    onClick={onBack}
                    className="flex items-center gap-2 px-4 py-2 text-gray-600 hover:text-gray-800 transition-colors font-medium"
                >
                    <ArrowLeft size={18} />
                    Back
                </button>

                <div className="flex items-center gap-3">
                    <button
                        type="button"
                        onClick={onSkip}
                        className="flex items-center gap-2 px-4 py-2 text-gray-500 hover:text-gray-700 transition-colors text-sm"
                    >
                        <SkipForward size={16} />
                        Skip for now
                    </button>
                    <button
                        type="button"
                        onClick={onNext}
                        disabled={isSubmitting}
                        className="flex items-center gap-2 px-6 py-3 bg-blue-600 text-white rounded-lg hover:bg-blue-700 disabled:opacity-50 transition-colors font-semibold shadow-lg shadow-blue-500/25"
                    >
                        Continue
                        <ArrowRight size={18} />
                    </button>
                </div>
            </div>
        </div>
    );
}

/**
 * Review Step
 * 
 * Final step in onboarding: Review configured integrations and launch.
 * Shows summary of completed/skipped steps with ability to go back.
 */

import React from 'react';
import { CheckCircle, SkipForward, ArrowLeft, Rocket, Store, Plug, Mail, TrendingUp, AlertCircle } from 'lucide-react';
import { OnboardingStepProps, ONBOARDING_STEPS, STEP_CONFIG } from '../types';

interface IntegrationStatus {
    step: number;
    label: string;
    icon: React.ElementType;
    isCompleted: boolean;
    isSkipped: boolean;
    details?: string;
}

/**
 * Shows a summary of all configured integrations and allows final confirmation.
 */
export function ReviewStep({ draft, setDraft, onNext, onBack, isSubmitting }: OnboardingStepProps) {
    // Build integration status list
    const integrations: IntegrationStatus[] = [
        {
            step: ONBOARDING_STEPS.STORE,
            label: 'WooCommerce Store',
            icon: Store,
            isCompleted: !!draft.store.name && !!draft.store.wooConsumerKey,
            isSkipped: false,
            details: draft.store.name || undefined
        },
        {
            step: ONBOARDING_STEPS.PLUGIN,
            label: 'OverSeek Plugin',
            icon: Plug,
            isCompleted: draft.plugin.verified,
            isSkipped: draft.skippedSteps.includes(ONBOARDING_STEPS.PLUGIN),
            details: draft.plugin.verified ? `v${draft.plugin.pluginVersion || 'Installed'}` : undefined
        },
        {
            step: ONBOARDING_STEPS.EMAIL,
            label: 'Email (SMTP)',
            icon: Mail,
            isCompleted: draft.email.enabled && draft.email.verified,
            isSkipped: draft.skippedSteps.includes(ONBOARDING_STEPS.EMAIL) || !draft.email.enabled,
            details: draft.email.verified ? draft.email.email : undefined
        },
        {
            step: ONBOARDING_STEPS.ADS,
            label: 'Ad Accounts',
            icon: TrendingUp,
            isCompleted: draft.ads.googleConnected || draft.ads.metaConnected,
            isSkipped: draft.skippedSteps.includes(ONBOARDING_STEPS.ADS),
            details: [
                draft.ads.googleConnected ? 'Google Ads' : null,
                draft.ads.metaConnected ? 'Meta Ads' : null
            ].filter(Boolean).join(', ') || undefined
        }
    ];

    const completedCount = integrations.filter(i => i.isCompleted).length;
    const skippedCount = integrations.filter(i => i.isSkipped && !i.isCompleted).length;

    return (
        <div className="space-y-6">
            {/* Header */}
            <div className="text-center pb-4 border-b border-gray-100">
                <div className="inline-flex items-center justify-center w-16 h-16 rounded-2xl bg-gradient-to-br from-blue-500 to-purple-600 text-white mb-4">
                    <Rocket size={32} />
                </div>
                <h2 className="text-2xl font-bold text-gray-900">Ready to Launch!</h2>
                <p className="text-gray-500 mt-2">
                    Review your setup and start using OverSeek
                </p>
            </div>

            {/* Summary Stats */}
            <div className="grid grid-cols-2 gap-4">
                <div className="bg-green-50 rounded-xl p-4 border border-green-200 text-center">
                    <div className="text-3xl font-bold text-green-600">{completedCount}</div>
                    <div className="text-sm text-green-700">Integrations Ready</div>
                </div>
                <div className="bg-amber-50 rounded-xl p-4 border border-amber-200 text-center">
                    <div className="text-3xl font-bold text-amber-600">{skippedCount}</div>
                    <div className="text-sm text-amber-700">Skipped (Optional)</div>
                </div>
            </div>

            {/* Integration List */}
            <div className="space-y-3">
                <h3 className="text-sm font-semibold text-gray-700 uppercase tracking-wide">Your Setup</h3>

                {integrations.map((integration) => {
                    const Icon = integration.icon;

                    return (
                        <div
                            key={integration.step}
                            className={`flex items-center gap-4 p-4 rounded-xl border transition-colors ${integration.isCompleted
                                ? 'bg-green-50 border-green-200'
                                : integration.isSkipped
                                    ? 'bg-amber-50 border-amber-200'
                                    : 'bg-gray-50 border-gray-200'
                                }`}
                        >
                            {/* Status Icon */}
                            <div className={`flex-shrink-0 w-10 h-10 rounded-xl flex items-center justify-center ${integration.isCompleted
                                ? 'bg-green-100 text-green-600'
                                : integration.isSkipped
                                    ? 'bg-amber-100 text-amber-600'
                                    : 'bg-gray-100 text-gray-400'
                                }`}>
                                {integration.isCompleted ? (
                                    <CheckCircle size={20} />
                                ) : integration.isSkipped ? (
                                    <SkipForward size={18} />
                                ) : (
                                    <Icon size={20} />
                                )}
                            </div>

                            {/* Label & Details */}
                            <div className="flex-1 min-w-0">
                                <div className={`text-sm font-semibold ${integration.isCompleted ? 'text-green-800' :
                                    integration.isSkipped ? 'text-amber-800' :
                                        'text-gray-600'
                                    }`}>
                                    {integration.label}
                                </div>
                                {integration.details && (
                                    <div className="text-xs text-gray-500 truncate mt-0.5">
                                        {integration.details}
                                    </div>
                                )}
                            </div>

                            {/* Status Badge */}
                            <div className={`flex-shrink-0 px-2.5 py-1 rounded-full text-xs font-medium ${integration.isCompleted
                                ? 'bg-green-100 text-green-700'
                                : integration.isSkipped
                                    ? 'bg-amber-100 text-amber-700'
                                    : 'bg-gray-100 text-gray-500'
                                }`}>
                                {integration.isCompleted ? 'Ready' : integration.isSkipped ? 'Skipped' : 'Pending'}
                            </div>
