                    );
                })}
            </div>

            {/* Skipped Items Notice */}
            {skippedCount > 0 && (
                <div className="bg-blue-50 border border-blue-200 rounded-lg p-4 flex gap-3">
                    <AlertCircle className="w-5 h-5 text-blue-600 flex-shrink-0 mt-0.5" />
