                    </div>
                </div>
            )}

            {/* Navigation */}
            <div className="flex items-center justify-between pt-4 border-t border-gray-100">
                <button
                    type="button"
                    onClick={onBack}
                    className="flex items-center gap-2 px-4 py-2 text-gray-600 hover:text-gray-800 transition-colors font-medium"
                >
                    <ArrowLeft size={18} />
                    Back
                </button>

                <button
                    type="button"
                    onClick={onNext}
                    disabled={isSubmitting}
                    className="flex items-center gap-2 px-8 py-3 bg-gradient-to-r from-blue-600 to-purple-600 text-white rounded-lg hover:from-blue-700 hover:to-purple-700 disabled:opacity-50 transition-all font-bold shadow-lg shadow-purple-500/25"
                >
                    {isSubmitting ? (
                        <>
                            <span className="animate-spin">⏳</span>
                            Completing Setup...
                        </>
                    ) : (
                        <>
                            <Rocket size={18} />
                            Complete Setup
                        </>
                    )}
                </button>
            </div>
        </div>
    );
}

/**
 * FraudBadge - Displays fraud risk score with color-coded indicator.
 */
import { useState, useEffect } from 'react';
import { Logger } from '../../utils/logger';
import { ShieldAlert, ShieldCheck, ShieldQuestion, AlertTriangle } from 'lucide-react';
import { useAuth } from '../../context/AuthContext';
import { useAccount } from '../../context/AccountContext';
import { cn } from '../../utils/cn';

interface FraudResult {
    score: number;
    level: 'low' | 'medium' | 'high';
    factors: string[];
}

interface FraudBadgeProps {
    orderId: string;
    className?: string;
}

export function FraudBadge({ orderId, className }: FraudBadgeProps) {
    const { token } = useAuth();
    const { currentAccount } = useAccount();
    const [result, setResult] = useState<FraudResult | null>(null);
    const [isLoading, setIsLoading] = useState(true);
    const [showTooltip, setShowTooltip] = useState(false);

    useEffect(() => {
        fetchFraudScore();
    }, [orderId, currentAccount]);

    const fetchFraudScore = async () => {
        if (!orderId || !token || !currentAccount) return;
        setIsLoading(true);
        try {
            const res = await fetch(`/api/orders/${orderId}/fraud-score`, {
                headers: {
                    'Authorization': `Bearer ${token}`,
                    'X-Account-ID': currentAccount.id
                }
            });
            if (res.ok) {
                setResult(await res.json());
            }
        } catch (e) {
            Logger.error('Failed to fetch fraud score:', { error: e });
        } finally {
            setIsLoading(false);
        }
    };

    if (isLoading) {
        return (
            <div className={cn("animate-pulse w-20 h-6 bg-gray-200 rounded", className)} />
        );
    }

    if (!result) return null;

    const config = {
        low: {
            bg: 'bg-green-100',
            text: 'text-green-700',
            border: 'border-green-200',
            icon: ShieldCheck,
            label: 'Low Risk'
        },
        medium: {
            bg: 'bg-yellow-100',
            text: 'text-yellow-700',
            border: 'border-yellow-200',
            icon: ShieldQuestion,
            label: 'Medium Risk'
        },
        high: {
            bg: 'bg-red-100',
            text: 'text-red-700',
            border: 'border-red-200',
            icon: ShieldAlert,
            label: 'High Risk'
        }
    };

    const { bg, text, border, icon: Icon, label } = config[result.level];

    return (
        <div className={cn("relative inline-block", className)}>
            <button
                onMouseEnter={() => setShowTooltip(true)}
                onMouseLeave={() => setShowTooltip(false)}
                className={cn(
                    "flex items-center gap-1.5 px-2.5 py-1 rounded-full border text-xs font-medium transition-colors",
                    bg, text, border
                )}
            >
                <Icon size={14} />
                <span>{label}</span>
                <span className="opacity-70">({result.score})</span>
            </button>

            {showTooltip && result.factors.length > 0 && (
                <div className="absolute z-50 top-full left-0 mt-1 w-64 p-3 bg-white border border-gray-200 rounded-lg shadow-lg text-left">
                    <p className="text-xs font-semibold text-gray-700 mb-2">Risk Factors:</p>
                    <ul className="space-y-1">
                        {result.factors.map((factor, i) => (
                            <li key={i} className="flex items-start gap-2 text-xs text-gray-600">
                                <AlertTriangle size={12} className="text-amber-500 mt-0.5 flex-shrink-0" />
                                {factor}
                            </li>
                        ))}
                    </ul>
                </div>
            )}
        </div>
    );
}

/**
 * FraudIcon - Compact fraud risk indicator for order lists.
 * Shows a small shield icon that fetches and displays risk level on hover.
 */
import { useState, useEffect } from 'react';
import { Logger } from '../../utils/logger';
import { ShieldAlert, ShieldCheck, ShieldQuestion } from 'lucide-react';
import { useAuth } from '../../context/AuthContext';
import { useAccount } from '../../context/AccountContext';
import { cn } from '../../utils/cn';

interface FraudResult {
    score: number;
    level: 'low' | 'medium' | 'high';
    factors: string[];
}

interface FraudIconProps {
    orderId: number | string;
    className?: string;
}

export function FraudIcon({ orderId, className }: FraudIconProps) {
    const { token } = useAuth();
    const { currentAccount } = useAccount();
    const [result, setResult] = useState<FraudResult | null>(null);
    const [isLoading, setIsLoading] = useState(false);
    const [hasFetched, setHasFetched] = useState(false);
    const [showTooltip, setShowTooltip] = useState(false);

    // Fetch on first hover to avoid loading all at once
    const handleMouseEnter = () => {
        setShowTooltip(true);
        if (!hasFetched && !isLoading) {
            fetchFraudScore();
        }
    };

    const fetchFraudScore = async () => {
        if (!orderId || !token || !currentAccount) return;
        setIsLoading(true);
        try {
            const res = await fetch(`/api/orders/${orderId}/fraud-score`, {
                headers: {
                    'Authorization': `Bearer ${token}`,
                    'X-Account-ID': currentAccount.id
                }
            });
            if (res.ok) {
                setResult(await res.json());
            }
        } catch (e) {
            Logger.error('Failed to fetch fraud score:', { error: e });
        } finally {
            setIsLoading(false);
            setHasFetched(true);
        }
    };

    const config = {
        low: {
            color: 'text-green-500',
            icon: ShieldCheck,
            label: 'Low Risk'
        },
        medium: {
            color: 'text-yellow-500',
            icon: ShieldQuestion,
            label: 'Medium Risk'
        },
        high: {
            color: 'text-red-500',
            icon: ShieldAlert,
            label: 'High Risk'
        }
    };

    // Default to neutral before fetching
    const level = result?.level || 'low';
    const { color, icon: Icon, label } = config[level];

    return (
        <div
            className={cn("relative inline-flex items-center", className)}
            onMouseEnter={handleMouseEnter}
            onMouseLeave={() => setShowTooltip(false)}
        >
            <Icon
                size={16}
                className={cn(
                    "transition-colors cursor-pointer",
                    hasFetched ? color : "text-gray-300"
                )}
            />

            {showTooltip && (
                <div className="absolute z-50 bottom-full left-1/2 -translate-x-1/2 mb-2 px-2 py-1 bg-gray-900 text-white text-xs rounded whitespace-nowrap">
                    {isLoading ? 'Loading...' : (
                        result ? `${label} (${result.score})` : 'Hover to check'
                    )}
                    <div className="absolute top-full left-1/2 -translate-x-1/2 border-4 border-transparent border-t-gray-900" />
                </div>
            )}
        </div>
    );
}

/**
 * OrderCOGSPanel - Displays COGS breakdown on order detail pages.
 *
 * Why gated client AND server side: The component returns null when the
 * user lacks `view_cogs`, and the API endpoint returns 403 independently.
 * Belt-and-braces for sensitive financial data.
 */

import { useState, useEffect } from 'react';
import { DollarSign, ChevronDown, ChevronUp, Loader2 } from 'lucide-react';
import { useAuth } from '../../context/AuthContext';
import { useAccount } from '../../context/AccountContext';
import { usePermissions } from '../../hooks/usePermissions';
import { formatCurrency } from '../../utils/format';
import { Logger } from '../../utils/logger';

interface COGSLineItem {
    productId: number;
    variationId: number;
    name: string;
    sku: string;
    quantity: number;
    unitCOGS: number;
    lineCOGS: number;
    lineRevenue: number;
}

interface COGSData {
    items: COGSLineItem[];
    totalCOGS: number;
    totalRevenue: number;
    paymentFees: number;
    grossProfit: number;
    margin: number;
}

interface OrderCOGSPanelProps {
    orderId: string;
    currency?: string;
}

/** Collapsible COGS breakdown card for order detail pages */
export function OrderCOGSPanel({ orderId, currency }: OrderCOGSPanelProps) {
    const { token } = useAuth();
    const { currentAccount } = useAccount();
    const { hasPermission } = usePermissions();
    const canViewCogs = hasPermission('view_cogs');

    const [data, setData] = useState<COGSData | null>(null);
    const [loading, setLoading] = useState(false);
    const [expanded, setExpanded] = useState(true);

    useEffect(() => {
        if (!canViewCogs || !orderId || !currentAccount || !token) return;
        fetchCOGS();
    }, [orderId, currentAccount, token, canViewCogs]);

    async function fetchCOGS() {
        setLoading(true);
        try {
            const res = await fetch(`/api/orders/${orderId}/cogs`, {
                headers: {
                    'Authorization': `Bearer ${token}`,
                    'X-Account-ID': currentAccount?.id || ''
                }
            });
            if (res.ok) {
                setData(await res.json());
            }
        } catch (err) {
            Logger.error('Failed to fetch order COGS', { error: err });
        } finally {
            setLoading(false);
        }
    }

    // Permission gate — nothing rendered for unauthorized users
    if (!canViewCogs) return null;

    const fmt = (v: number) => formatCurrency(v, currency || currentAccount?.currency || 'USD');

    return (
        <div className="bg-white rounded-xl shadow-xs border border-gray-200 overflow-hidden">
            {/* Header */}
            <button
                onClick={() => setExpanded(!expanded)}
                className="w-full flex items-center justify-between p-4 border-b border-gray-100 hover:bg-gray-50/50 transition-colors"
            >
                <div className="flex items-center gap-2 font-semibold text-gray-900">
                    <DollarSign size={18} className="text-emerald-500" />
                    COGS Breakdown
                </div>
                {expanded ? <ChevronUp size={16} className="text-gray-400" /> : <ChevronDown size={16} className="text-gray-400" />}
            </button>

            {expanded && (
                <div className="p-4">
                    {loading ? (
                        <div className="flex items-center justify-center py-6 text-gray-400 text-sm">
                            <Loader2 size={16} className="animate-spin mr-2" /> Loading…
                        </div>
                    ) : !data || data.items.length === 0 ? (
                        <p className="text-sm text-gray-500 italic py-4 text-center">No COGS data available</p>
                    ) : (
                        <>
                            {/* Per-item breakdown */}
                            <div className="space-y-2 mb-4">
                                {data.items.map((item, idx) => (
                                    <div key={idx} className="flex items-start justify-between text-sm gap-2">
                                        <div className="min-w-0 flex-1">
                                            <div className="font-medium text-gray-800 truncate">{item.name}</div>
                                            <div className="text-xs text-gray-400">
                                                {item.sku ? `SKU: ${item.sku} · ` : ''}
                                                {item.quantity} × {fmt(item.unitCOGS)}
                                            </div>
                                        </div>
                                        <span className="text-gray-700 font-medium whitespace-nowrap">{fmt(item.lineCOGS)}</span>
                                    </div>
                                ))}
                            </div>

                            {/* Summary */}
                            <div className="border-t border-gray-100 pt-3 space-y-1.5 text-sm">
                                <div className="flex justify-between">
                                    <span className="text-gray-500">Total COGS</span>
                                    <span className="font-medium text-gray-800">{fmt(data.totalCOGS)}</span>
                                </div>
                                {data.paymentFees > 0 && (
                                    <div className="flex justify-between">
                                        <span className="text-gray-500">Payment Fees</span>
                                        <span className="font-medium text-gray-800">{fmt(data.paymentFees)}</span>
                                    </div>
                                )}
                                <div className="flex justify-between pt-1.5 border-t border-dashed border-gray-200">
                                    <span className="font-semibold text-gray-900">Gross Profit</span>
                                    <div className="flex items-center gap-2">
                                        <span className={`font-bold ${data.grossProfit >= 0 ? 'text-emerald-600' : 'text-red-600'}`}>
                                            {fmt(data.grossProfit)}
                                        </span>
                                        <span className={`text-xs px-1.5 py-0.5 rounded-full font-medium ${data.margin >= 0
                                                ? 'bg-emerald-50 text-emerald-700 border border-emerald-200'
                                                : 'bg-red-50 text-red-700 border border-red-200'
                                            }`}>
                                            {data.margin >= 0 ? '+' : ''}{data.margin.toFixed(1)}%
                                        </span>
                                    </div>
                                </div>
                            </div>
                        </>
                    )}
                </div>
            )}
        </div>
    );
}

/**
 * OrderMetaSection Component
 * 
 * Displays categorized metadata from WooCommerce order line items.
 * Categories: Product Options (variations), Custom Fields, and Uploaded Files (images).
 * Extracted from OrderDetailPage for reusability.
 */

import { useState } from 'react';
import { ChevronDown, ChevronUp, Palette, FileText, Image as ImageIcon, Settings } from 'lucide-react';
import { fixMojibake } from '../../utils/format';


interface MetaCategory {
    id: string;
    label: string;
    icon: React.ReactNode;
    color: string;
    bgColor: string;
    items: Array<{ key: string; value: string; imageUrl?: string | null }>;
}

interface OrderMetaSectionProps {
    metaData: Array<{ key: string; value: string; display_key?: string; display_value?: string }>;
    onImageClick: (url: string) => void;
}

interface ImageThumbnailProps {
    item: { key: string; value: string; imageUrl?: string | null };
    onImageClick: (url: string) => void;
}


/**
 * Extracts an image URL from a meta value.
 * Handles compound values like "filename.webp | https://example.com/path/to/image.webp"
 * @returns The URL if found, null otherwise.
 */
export function extractImageUrl(value: string): string | null {
    if (typeof value !== 'string') return null;

    const imagePattern = /\.(jpg|jpeg|png|gif|webp|svg|bmp)/i;

    // Check if the value itself is a direct image URL
    if (imagePattern.test(value) && value.startsWith('http')) {
        return value;
    }

    // Look for URLs within the value (handles "filename | url" format)
    const urlMatch = value.match(/(https?:\/\/[^\s|]+)/g);
    if (urlMatch) {
        for (const url of urlMatch) {
            if (imagePattern.test(url)) {
                return url.trim();
            }
        }
    }

    return null;
}

/**
 * Extracts ALL image URLs from a meta value.
 * WooCommerce can store multiple images per meta entry (newline or pipe separated).
 * @returns An array of all found image URLs.
 */
export function extractAllImageUrls(value: string): string[] {
    if (typeof value !== 'string') return [];

    const imagePattern = /\.(jpg|jpeg|png|gif|webp|svg|bmp)/i;
    const urls: string[] = [];

    const urlMatches = value.match(/(https?:\/\/[^\s|,\n]+)/g);
    if (urlMatches) {
        for (const url of urlMatches) {
            const cleanUrl = url.trim();
            if (imagePattern.test(cleanUrl) && !urls.includes(cleanUrl)) {
                urls.push(cleanUrl);
            }
        }
    }

    return urls;
}


/**
 * Displays a clickable thumbnail image with hover label.
 * Falls back to a text badge if the image fails to load.
 */
export function ImageThumbnail({ item, onImageClick }: ImageThumbnailProps) {
    const [imgError, setImgError] = useState(false);

    if (!item.imageUrl || imgError) {
        return (
            <div className="flex items-center gap-1 px-2 py-1 bg-gray-100 rounded text-xs text-gray-500">
                <FileText size={12} />
                <span>{item.key}</span>
            </div>
        );
    }

    return (
        <div className="group relative">
            <div
                className="cursor-zoom-in rounded-lg overflow-hidden border-2 border-transparent hover:border-purple-400 transition-all shadow-sm hover:shadow-md"
                onClick={() => onImageClick(item.imageUrl!)}
            >
                <img
                    src={item.imageUrl}
                    alt={item.key}
                    onError={() => setImgError(true)}
                    className="h-16 w-16 object-cover hover:scale-105 transition-transform"
                />
            </div>
            <div className="absolute -bottom-1 left-1/2 -translate-x-1/2 px-1.5 py-0.5 bg-gray-900/80 text-white text-[9px] rounded capitalize opacity-0 group-hover:opacity-100 transition-opacity whitespace-nowrap">
                {item.key}
            </div>
        </div>
    );
}

/**
 * Displays WooCommerce order item metadata in categorized sections.
 * Categories are collapsible and display data in appropriate formats (key-value or image gallery).
 */
export function OrderMetaSection({ metaData, onImageClick }: OrderMetaSectionProps) {
    const [expandedCategories, setExpandedCategories] = useState<Set<string>>(new Set(['variations', 'custom']));

    // Filter out hidden meta and categorize
    const filteredMeta = metaData.filter(m => !m.key.startsWith('_'));

    if (filteredMeta.length === 0) return null;

    // Categorize metadata
    const categories: MetaCategory[] = [];

    // Variations/Attributes (pa_ prefix or common variation keys)
    const variations = filteredMeta.filter(m =>
        m.key.startsWith('pa_') ||
        ['size', 'color', 'colour', 'variant', 'style', 'material', 'weight'].some(k =>
            m.key.toLowerCase().includes(k)
        )
    );

    // Uploads/Images
    const uploads = filteredMeta.filter(m => {
        const url = extractImageUrl(m.value);
        return url !== null;
    });

    // Custom fields (everything else)
    const customFields = filteredMeta.filter(m =>
        !variations.includes(m) && !uploads.includes(m)
    );

    if (variations.length > 0) {
        categories.push({
            id: 'variations',
            label: 'Product Options',
            icon: <Palette size={12} />,
            color: 'text-purple-700',
            bgColor: 'bg-purple-50 border-purple-200',
            items: variations.map(m => ({
                key: fixMojibake(m.display_key || m.key.replace('pa_', '').replace(/_/g, ' ')),
                value: fixMojibake(m.display_value || m.value),
                imageUrl: null
            }))
        });
    }

    if (customFields.length > 0) {
        categories.push({
            id: 'custom',
            label: 'Custom Fields',
            icon: <Settings size={12} />,
            color: 'text-blue-700',
            bgColor: 'bg-blue-50 border-blue-200',
            items: customFields.map(m => ({
                key: fixMojibake(m.display_key || m.key.replace(/_/g, ' ')),
                value: fixMojibake(m.display_value || m.value),
                imageUrl: null
            }))
        });
    }

    if (uploads.length > 0) {
        // Flatten uploads: each image URL becomes its own item
        const uploadItems: Array<{ key: string; value: string; imageUrl: string | null }> = [];
        for (const m of uploads) {
            const imageUrls = extractAllImageUrls(m.value);
            const baseKey = fixMojibake(m.display_key || m.key.replace(/_/g, ' '));
            if (imageUrls.length > 0) {
                imageUrls.forEach((url, idx) => {
                    uploadItems.push({
                        key: imageUrls.length > 1 ? `${baseKey} (${idx + 1})` : baseKey,
                        value: fixMojibake(m.display_value || m.value),
                        imageUrl: url
                    });
                });
            } else {
                uploadItems.push({
                    key: baseKey,
                    value: fixMojibake(m.display_value || m.value),
                    imageUrl: extractImageUrl(m.value)
                });
            }
        }
        categories.push({
            id: 'uploads',
            label: 'Uploaded Files',
            icon: <ImageIcon size={12} />,
            color: 'text-amber-700',
            bgColor: 'bg-amber-50 border-amber-200',
            items: uploadItems
        });
    }

    const toggleCategory = (id: string) => {
        setExpandedCategories(prev => {
            const next = new Set(prev);
            if (next.has(id)) {
                next.delete(id);
            } else {
                next.add(id);
            }
            return next;
        });
    };

    return (
        <div className="mt-3 space-y-2">
            {categories.map(category => {
                const isExpanded = expandedCategories.has(category.id);

                return (
                    <div key={category.id} className={`rounded-lg border overflow-hidden ${category.bgColor}`}>
                        {/* Category Header */}
                        <button
                            onClick={() => toggleCategory(category.id)}
                            className="w-full px-3 py-2 flex items-center justify-between hover:bg-white/30 transition-colors"
                        >
                            <div className={`flex items-center gap-2 text-xs font-semibold ${category.color}`}>
                                {category.icon}
                                <span className="capitalize">{category.label}</span>
                                <span className="px-1.5 py-0.5 rounded-full bg-white/60 text-[10px] font-bold">
                                    {category.items.length}
                                </span>
                            </div>
                            {isExpanded ? (
                                <ChevronUp size={14} className={category.color} />
                            ) : (
                                <ChevronDown size={14} className={category.color} />
                            )}
                        </button>

                        {/* Category Content */}
                        {isExpanded && (
                            <div className="px-3 pb-3 bg-white/40">
                                {category.id === 'uploads' ? (
                                    // Image Gallery View
                                    <div className="flex flex-wrap gap-2 pt-2">
                                        {category.items.map((item, idx) => (
                                            <ImageThumbnail
                                                key={idx}
                                                item={item}
                                                onImageClick={onImageClick}
                                            />
                                        ))}
                                    </div>
                                ) : (
                                    // Key-Value List View
                                    <div className="grid gap-1.5 pt-2">
                                        {category.items.map((item, idx) => (
                                            <div key={idx} className="flex items-baseline gap-2 text-xs">
                                                <span className="font-medium text-gray-600 capitalize min-w-[80px]">
                                                    {item.key}:
                                                </span>
                                                <span className="text-gray-900 break-all whitespace-pre-line">
                                                    {item.value.startsWith('http') ? (
                                                        <a
                                                            href={item.value}
                                                            target="_blank"
                                                            rel="noopener noreferrer"
                                                            className="text-blue-600 hover:underline"
                                                        >
                                                            {item.value.length > 40 ? item.value.slice(0, 40) + '...' : item.value}
                                                        </a>
                                                    ) : (
                                                        item.value
                                                    )}
                                                </span>
                                            </div>
                                        ))}
                                    </div>
                                )}
                            </div>
                        )}
                    </div>
                );
            })}
        </div>
    );
}

/**
 * OrderStatusTabs - A modern horizontal tab filter for order statuses.
 * 
 * Why: Replaces the basic dropdown with a premium horizontal pill/tab filter
 * matching the WooCommerce-style "All | Processing | Completed | ..." design
 * but with OverSeek's glassmorphism aesthetic.
 */

import { useEffect, useState, useMemo } from 'react';
import { useAuth } from '../../context/AuthContext';
import { useAccount } from '../../context/AccountContext';
import { ORDER_STATUS_CONFIG, getStatusConfig } from '../../utils/orderStatus';
import { Loader2 } from 'lucide-react';

interface StatusCounts {
    total: number;
    counts: Record<string, number>;
}

interface OrderStatusTabsProps {
    selectedStatus: string;
    onStatusChange: (status: string) => void;
}

/** Ordered list of statuses to display in the tabs */
const TAB_STATUSES = [
    'all',
    'pending',
    'processing',
    'on-hold',
    'completed',
    'cancelled',
    'refunded',
    'failed'
] as const;

export function OrderStatusTabs({ selectedStatus, onStatusChange }: OrderStatusTabsProps) {
    const { token } = useAuth();
    const { currentAccount } = useAccount();
    const [statusCounts, setStatusCounts] = useState<StatusCounts | null>(null);
    const [isLoading, setIsLoading] = useState(true);

    useEffect(() => {
        if (!currentAccount || !token) return;

        const fetchCounts = async () => {
            try {
                const res = await fetch('/api/sync/orders/status-counts', {
                    headers: {
                        'Authorization': `Bearer ${token}`,
                        'X-Account-ID': currentAccount.id
                    }
                });

                if (res.ok) {
                    const data = await res.json();
                    setStatusCounts(data);
                }
            } catch {
                // Silent fail - tabs still work without counts
            } finally {
                setIsLoading(false);
            }
        };

        fetchCounts();
    }, [currentAccount, token]);

    const tabs = useMemo(() => {
        return TAB_STATUSES.map(status => {
            if (status === 'all') {
                return {
                    value: 'all',
                    label: 'All',
                    count: statusCounts?.total ?? null,
                    color: 'gray'
                };
            }

            const config = getStatusConfig(status);
            return {
                value: status,
                label: config.label,
                count: statusCounts?.counts[status] ?? null,
                color: status
            };
        });
    }, [statusCounts]);

    const getTabStyles = (status: string, isActive: boolean) => {
        const baseStyles = 'group relative flex items-center gap-1.5 px-3 py-2 text-sm font-medium rounded-lg transition-all duration-200 cursor-pointer select-none whitespace-nowrap';

        if (isActive) {
            // Active state - filled with status color
            const colorMap: Record<string, string> = {
                all: 'bg-slate-800 text-white shadow-md',
                pending: 'bg-amber-500 text-white shadow-md shadow-amber-200/50',
                processing: 'bg-blue-500 text-white shadow-md shadow-blue-200/50',
                'on-hold': 'bg-orange-500 text-white shadow-md shadow-orange-200/50',
                completed: 'bg-emerald-500 text-white shadow-md shadow-emerald-200/50',
                cancelled: 'bg-red-500 text-white shadow-md shadow-red-200/50',
                refunded: 'bg-purple-500 text-white shadow-md shadow-purple-200/50',
                failed: 'bg-red-600 text-white shadow-md shadow-red-200/50'
            };
            return `${baseStyles} ${colorMap[status] || colorMap.all}`;
        }

        // Inactive state - subtle with hover effect
        return `${baseStyles} text-gray-600 hover:text-gray-900 hover:bg-gray-100`;
    };

    const getCountStyles = (status: string, isActive: boolean) => {
        if (isActive) {
            return 'bg-white/25 text-white/90 text-xs px-1.5 py-0.5 rounded-md font-medium tabular-nums';
        }

        // Inactive - subtle badge
        return 'bg-gray-200/70 text-gray-500 text-xs px-1.5 py-0.5 rounded-md font-medium tabular-nums group-hover:bg-gray-300/70';
    };

    if (isLoading) {
        return (
            <div className="flex items-center gap-2 px-4 py-3 bg-white/60 backdrop-blur-sm rounded-xl border border-gray-200/60 shadow-sm">
                <Loader2 size={16} className="animate-spin text-gray-400" />
                <span className="text-sm text-gray-500">Loading statuses...</span>
            </div>
        );
    }

    return (
        <div className="bg-white/60 backdrop-blur-sm rounded-xl border border-gray-200/60 shadow-sm overflow-hidden">
            <div className="flex items-center gap-1 p-1.5 overflow-x-auto scrollbar-thin scrollbar-thumb-gray-300" role="tablist">
                {tabs.map((tab) => {
                    const isActive = selectedStatus === tab.value;
                    return (
                        <button
                            key={tab.value}
                            role="tab"
                            aria-selected={isActive}
                            onClick={() => onStatusChange(tab.value)}
                            className={getTabStyles(tab.value, isActive)}
                        >
                            <span>{tab.label}</span>
                            {tab.count !== null && (
                                <span className={getCountStyles(tab.value, isActive)}>
                                    {tab.count.toLocaleString()}
                                </span>
                            )}
                        </button>
                    );
                })}
            </div>
        </div>
    );
}

import { useState, useEffect, useRef } from 'react';
import { Tag, Plus, X, ChevronDown, Search, Loader2 } from 'lucide-react';
import { Logger } from '../../utils/logger';
import { useAuth } from '../../context/AuthContext';
import { useAccount } from '../../context/AccountContext';

interface TagMapping {
    productTag: string;
    orderTag: string;
    enabled: boolean;
    color?: string;
}

interface OrderTagPanelProps {
    orderId: string;
    currentTags: string[];
    lastUpdate?: string;
    onTagsChange: (tags: string[]) => void;
    onRefresh?: () => void;
}

/**
 * Sidebar panel for managing order tags.
 * Displays current tags with single-click removal and a dropdown to add available tags.
 */
export function OrderTagPanel({ orderId, currentTags, lastUpdate, onTagsChange, onRefresh }: OrderTagPanelProps) {
    const { token } = useAuth();
    const { currentAccount } = useAccount();

    const [mappings, setMappings] = useState<TagMapping[]>([]);
    const [isLoading, setIsLoading] = useState(true);
    const [isUpdating, setIsUpdating] = useState(false);
    const [showAddDropdown, setShowAddDropdown] = useState(false);
    const [searchQuery, setSearchQuery] = useState('');
    const dropdownRef = useRef<HTMLDivElement>(null);

    useEffect(() => {
        if (currentAccount && token) {
            loadMappings();
        }
    }, [currentAccount, token]);

    // Close dropdown on outside click
    useEffect(() => {
        function handleClickOutside(event: MouseEvent) {
            if (dropdownRef.current && !dropdownRef.current.contains(event.target as Node)) {
                setShowAddDropdown(false);
                setSearchQuery('');
            }
        }
        document.addEventListener('mousedown', handleClickOutside);
        return () => document.removeEventListener('mousedown', handleClickOutside);
    }, []);

    async function loadMappings() {
        if (!currentAccount || !token) return;
        setIsLoading(true);
        try {
            const res = await fetch(`/api/accounts/${currentAccount.id}/tag-mappings`, {
                headers: { 'Authorization': `Bearer ${token}` }
            });
            if (res.ok) {
                const data = await res.json();
                setMappings((data.mappings || []).filter((m: TagMapping) => m.enabled));
            }
        } catch (error) {
            Logger.error('Failed to load tag mappings', { error });
        } finally {
            setIsLoading(false);
        }
    }

    /** Gets available tags that aren't already applied to this order */
    function getAvailableTags(): TagMapping[] {
        const appliedTags = new Set(currentTags.map(t => t.toLowerCase()));
        return mappings.filter(m => !appliedTags.has(m.orderTag.toLowerCase()));
    }

    /** Filtered available tags based on search */
    function getFilteredAvailableTags(): TagMapping[] {
        const available = getAvailableTags();
        if (!searchQuery.trim()) return available;
        return available.filter(m =>
            m.orderTag.toLowerCase().includes(searchQuery.toLowerCase())
        );
    }

    /** Gets color for a tag from mappings */
    function getTagColor(tagName: string): string {
        const mapping = mappings.find(m => m.orderTag.toLowerCase() === tagName.toLowerCase());
        return mapping?.color || '#6B7280';
    }

    async function addTag(tagName: string) {
        if (!currentAccount || !token || isUpdating) return;
        setIsUpdating(true);
        setShowAddDropdown(false);
        setSearchQuery('');

        try {
            const headers: HeadersInit = {
                'Authorization': `Bearer ${token}`,
                'X-Account-ID': currentAccount.id,
                'Content-Type': 'application/json'
            };

            if (lastUpdate) {
                headers['X-Order-Version'] = lastUpdate;
            }

            const res = await fetch(`/api/orders/${orderId}/tags`, {
                method: 'POST',
                headers,
                body: JSON.stringify({ tag: tagName })
            });

            if (res.status === 409) {
                Logger.warn('Order conflict detected, refreshing...');
                alert('This order has been modified by another user. Refreshing...');
                if (onRefresh) onRefresh();
                return;
            }

            if (res.ok) {
                const data = await res.json();
                onTagsChange(data.tags);
            }
        } catch (error) {
            Logger.error('Failed to add tag', { error });
        } finally {
            setIsUpdating(false);
        }
    }

    async function removeTag(tagName: string) {
        if (!currentAccount || !token || isUpdating) return;
        setIsUpdating(true);

        try {
            const headers: HeadersInit = {
                'Authorization': `Bearer ${token}`,
                'X-Account-ID': currentAccount.id
            };

            if (lastUpdate) {
                headers['X-Order-Version'] = lastUpdate;
            }

            const res = await fetch(`/api/orders/${orderId}/tags/${encodeURIComponent(tagName)}`, {
                method: 'DELETE',
                headers
            });

            if (res.status === 409) {
                Logger.warn('Order conflict detected, refreshing...');
                alert('This order has been modified by another user. Refreshing...');
                if (onRefresh) onRefresh();
                return;
            }

            if (res.ok) {
                const data = await res.json();
                onTagsChange(data.tags);
            }
        } catch (error) {
            Logger.error('Failed to remove tag', { error });
        } finally {
            setIsUpdating(false);
        }
    }

    const availableTags = getFilteredAvailableTags();
    const hasAvailableTags = getAvailableTags().length > 0;

    return (
        <div className="bg-white rounded-xl shadow-xs border border-gray-200 p-5 space-y-4">
            <div className="font-semibold text-gray-900 flex items-center justify-between border-b border-gray-100 pb-3">
                <div className="flex items-center gap-2">
                    <Tag size={18} className="text-blue-500" />
                    Tags
                </div>

                {/* Add Tag Button */}
                {hasAvailableTags && (
                    <div className="relative" ref={dropdownRef}>
                        <button
                            onClick={() => setShowAddDropdown(!showAddDropdown)}
                            disabled={isUpdating || isLoading}
                            className="flex items-center gap-1 text-xs bg-blue-50 text-blue-600 px-2 py-1 rounded-md hover:bg-blue-100 transition-colors disabled:opacity-50"
                        >
                            <Plus size={14} />
                            Add
                            <ChevronDown size={12} className={`transition-transform ${showAddDropdown ? 'rotate-180' : ''}`} />
                        </button>

                        {showAddDropdown && (
                            <div className="absolute right-0 mt-2 w-56 bg-white rounded-lg shadow-lg border border-gray-200 z-50">
                                {/* Search input */}
                                <div className="p-2 border-b border-gray-100">
                                    <div className="relative">
                                        <Search size={12} className="absolute left-2.5 top-1/2 -translate-y-1/2 text-gray-400" />
                                        <input
                                            type="text"
                                            placeholder="Search tags..."
                                            value={searchQuery}
                                            onChange={(e) => setSearchQuery(e.target.value)}
                                            className="w-full pl-7 pr-2 py-1.5 text-xs border border-gray-200 rounded-md focus:ring-2 focus:ring-blue-500 focus:border-blue-500"
                                            autoFocus
                                        />
                                    </div>
                                </div>

                                {/* Tag list */}
                                <div className="max-h-48 overflow-y-auto py-1">
                                    {availableTags.length === 0 ? (
                                        <div className="px-3 py-2 text-xs text-gray-500 text-center">
                                            {searchQuery ? 'No matching tags' : 'No tags available'}
                                        </div>
                                    ) : (
                                        availableTags.map(mapping => (
                                            <button
                                                key={mapping.orderTag}
                                                onClick={() => addTag(mapping.orderTag)}
                                                className="w-full text-left px-3 py-2 text-xs hover:bg-blue-50 flex items-center gap-2 transition-colors"
                                            >
                                                <span
                                                    className="w-3 h-3 rounded-sm flex-shrink-0"
                                                    style={{ backgroundColor: mapping.color || '#6B7280' }}
                                                />
                                                <span className="truncate">{mapping.orderTag}</span>
                                            </button>
                                        ))
                                    )}
                                </div>
                            </div>
                        )}
                    </div>
                )}
            </div>

            {/* Tags Display */}
            {isLoading ? (
                <div className="flex items-center justify-center py-4">
                    <Loader2 size={20} className="animate-spin text-gray-400" />
                </div>
            ) : currentTags.length === 0 ? (
                <div className="text-sm text-gray-500 text-center py-2">
                    {mappings.length === 0 ? (
                        <span>Configure tag mappings in Settings</span>
                    ) : (
                        <span>No tags applied</span>
                    )}
                </div>
            ) : (
                <div className="flex flex-wrap gap-2">
                    {currentTags.map((tag) => {
                        const color = getTagColor(tag);
                        return (
                            <span
                                key={tag}
                                className="inline-flex items-center gap-1 px-2.5 py-1 rounded-md text-sm text-white group"
                                style={{ backgroundColor: color }}
                            >
                                {tag}
                                <button
                                    onClick={() => removeTag(tag)}
                                    disabled={isUpdating}
                                    className="ml-0.5 p-0.5 rounded hover:bg-white/20 opacity-70 hover:opacity-100 transition-opacity disabled:opacity-50"
                                    title="Remove tag"
                                >
                                    {isUpdating ? (
                                        <Loader2 size={12} className="animate-spin" />
                                    ) : (
                                        <X size={12} />
                                    )}
                                </button>
                            </span>
                        );
                    })}
                </div>
            )}
        </div>
    );
}

