                                        : 'hover:bg-gray-50 border-gray-100 text-gray-600'
                                        }`}
                                >
                                    <input
                                        type="checkbox"
                                        checked={metrics.includes(m.value)}
                                        onChange={() => toggleMetric(m.value)}
                                        className="sr-only"
                                    />
                                    <span className="opacity-60">{METRIC_ICONS[m.value]}</span>
                                    <span className="font-medium text-xs">{m.label}</span>
                                </label>
                            ))}
                        </div>
                    </div>

                    {/* Conversion Metrics */}
                    <div>
                        <div className="text-[10px] font-bold text-gray-400 uppercase tracking-wider mb-1.5 flex items-center gap-1">
                            <Percent size={10} /> Conversion
                        </div>
                        <div className="grid grid-cols-2 gap-1.5">
                            {conversionMetrics.map(m => (
                                <label
                                    key={m.value}
                                    className={`flex items-center gap-2 px-2.5 py-2 rounded-lg cursor-pointer border text-sm transition-all ${metrics.includes(m.value)
                                        ? 'bg-purple-50 border-purple-200 text-purple-700 shadow-xs'
                                        : 'hover:bg-gray-50 border-gray-100 text-gray-600'
                                        }`}
                                >
                                    <input
                                        type="checkbox"
                                        checked={metrics.includes(m.value)}
                                        onChange={() => toggleMetric(m.value)}
                                        className="sr-only"
                                    />
                                    <span className="opacity-60">{METRIC_ICONS[m.value]}</span>
                                    <span className="font-medium text-xs">{m.label}</span>
                                </label>
                            ))}
                        </div>
                    </div>
                </div>

                {/* Generate Button */}
                <button
                    onClick={onGenerate}
                    disabled={isLoading || metrics.length === 0}
                    className="w-full bg-linear-to-r from-blue-600 to-blue-700 text-white py-3 rounded-xl hover:from-blue-700 hover:to-blue-800 transition-all disabled:opacity-50 disabled:cursor-not-allowed font-semibold text-sm shadow-lg shadow-blue-500/20 hover:shadow-blue-500/30"
                >
                    {isLoading ? (
                        <span className="flex items-center justify-center gap-2">
                            <span className="w-4 h-4 border-2 border-white/30 border-t-white rounded-full animate-spin" />
                            Generating...
                        </span>
                    ) : 'Generate Report'}
                </button>
            </div>
        </div>
    );
}

import React, { useState, useEffect } from 'react';
import { Plus, Trash2, Save, X } from 'lucide-react';

export interface SegmentRule {
    field: string;
    operator: string;
    value: string;
}

export interface SegmentCriteria {
    type: 'AND' | 'OR';
    rules: SegmentRule[];
}

interface SegmentBuilderProps {
    initialCriteria?: SegmentCriteria;
    onSave: (criteria: SegmentCriteria) => void;
    onCancel: () => void;
    isSaving?: boolean;
}

const FIELDS = [
    { label: 'Total Spent', value: 'totalSpent', type: 'number' },
    { label: 'Orders Count', value: 'ordersCount', type: 'number' },
    { label: 'Email', value: 'email', type: 'text' },
    { label: 'First Name', value: 'firstName', type: 'text' },
    { label: 'Last Name', value: 'lastName', type: 'text' }
];

const OPERATORS = {
    number: [
        { label: 'Greater Than', value: 'gt' },
        { label: 'Less Than', value: 'lt' },
        { label: 'Equals', value: 'eq' },
        { label: 'Greater or Equal', value: 'gte' },
        { label: 'Less or Equal', value: 'lte' }
    ],
    text: [
        { label: 'Contains', value: 'contains' },
        { label: 'Equals', value: 'equals' },
        { label: 'Starts With', value: 'startsWith' }
    ]
};

export function SegmentBuilder({ initialCriteria, onSave, onCancel, isSaving }: SegmentBuilderProps) {
    const [criteria, setCriteria] = useState<SegmentCriteria>(initialCriteria || { type: 'AND', rules: [] });

    const addRule = () => {
        setCriteria({
            ...criteria,
            rules: [...criteria.rules, { field: 'totalSpent', operator: 'gt', value: '' }]
        });
    };

    const updateRule = (index: number, updates: Partial<SegmentRule>) => {
        const newRules = [...criteria.rules];
        newRules[index] = { ...newRules[index], ...updates };

        // Reset operator if field changes and type mismatch
        if (updates.field) {
            const fieldType = FIELDS.find(f => f.value === updates.field)?.type;
            const currentOp = newRules[index].operator;
            // Basic check, could be smarter
            if (fieldType === 'number' && ['contains', 'startsWith'].includes(currentOp)) {
                newRules[index].operator = 'gt';
            }
            if (fieldType === 'text' && ['gt', 'lt'].includes(currentOp)) {
                newRules[index].operator = 'contains';
            }
        }

        setCriteria({ ...criteria, rules: newRules });
    };

    const removeRule = (index: number) => {
        const newRules = criteria.rules.filter((_, i) => i !== index);
        setCriteria({ ...criteria, rules: newRules });
    };

    const getOperators = (fieldValue: string) => {
        const type = FIELDS.find(f => f.value === fieldValue)?.type || 'text';
        return OPERATORS[type as keyof typeof OPERATORS];
    };

    return (
        <div className="bg-white p-6 rounded-lg border border-gray-200 shadow-xs space-y-6">
            <div className="flex items-center justify-between">
                <h3 className="text-lg font-medium text-gray-900">Segment Rules</h3>
                <div className="flex items-center gap-2">
                    <span className="text-sm text-gray-500">Match</span>
                    <select
                        className="bg-gray-50 border border-gray-300 rounded-sm px-2 py-1 text-sm focus:outline-hidden focus:ring-2 focus:ring-blue-500"
                        value={criteria.type}
                        onChange={(e) => setCriteria({ ...criteria, type: e.target.value as 'AND' | 'OR' })}
                    >
                        <option value="AND">All (AND)</option>
                        <option value="OR">Any (OR)</option>
                    </select>
                    <span className="text-sm text-gray-500">of the following conditions:</span>
                </div>
            </div>

            <div className="space-y-4">
                {criteria.rules.map((rule, index) => (
                    <div key={index} className="flex items-center gap-3 p-3 bg-gray-50 rounded-lg border border-gray-100 group">
                        <select
                            className="flex-1 bg-white border border-gray-300 rounded-sm px-3 py-2 text-sm focus:outline-hidden focus:ring-2 focus:ring-blue-500"
                            value={rule.field}
                            onChange={(e) => updateRule(index, { field: e.target.value })}
                        >
                            {FIELDS.map(f => (
                                <option key={f.value} value={f.value}>{f.label}</option>
                            ))}
                        </select>

                        <select
                            className="w-40 bg-white border border-gray-300 rounded-sm px-3 py-2 text-sm focus:outline-hidden focus:ring-2 focus:ring-blue-500"
                            value={rule.operator}
                            onChange={(e) => updateRule(index, { operator: e.target.value })}
                        >
                            {getOperators(rule.field).map(op => (
                                <option key={op.value} value={op.value}>{op.label}</option>
                            ))}
                        </select>

                        <input
                            type="text"
                            className="flex-1 bg-white border border-gray-300 rounded-sm px-3 py-2 text-sm focus:outline-hidden focus:ring-2 focus:ring-blue-500"
                            placeholder="Value"
                            value={rule.value}
                            onChange={(e) => updateRule(index, { value: e.target.value })}
                        />

                        <button
                            onClick={() => removeRule(index)}
                            className="p-2 text-gray-400 hover:text-red-500 hover:bg-red-50 rounded-sm transition-colors"
                        >
                            <Trash2 size={16} />
                        </button>
                    </div>
                ))}

                {criteria.rules.length === 0 && (
                    <div className="text-center py-8 text-gray-400 bg-gray-50 rounded-lg border border-dashed border-gray-200">
                        No rules defined. This segment will match all customers.
                    </div>
                )}

                <button
                    onClick={addRule}
                    className="flex items-center gap-2 text-blue-600 hover:text-blue-700 text-sm font-medium px-2 py-1 rounded-sm hover:bg-blue-50 transition-colors"
                >
                    <Plus size={16} />
                    Add Condition
                </button>
            </div>

            <div className="flex items-center justify-end gap-3 pt-4 border-t border-gray-100">
                <button
                    onClick={onCancel}
                    className="px-4 py-2 text-gray-700 hover:bg-gray-100 rounded-lg text-sm font-medium transition-colors"
                >
                    Cancel
                </button>
                <button
                    onClick={() => onSave(criteria)}
                    disabled={isSaving}
                    className="flex items-center gap-2 px-4 py-2 bg-blue-600 text-white rounded-lg text-sm font-medium hover:bg-blue-700 transition-colors disabled:opacity-50"
                >
                    {isSaving ? <span className="animate-spin">⌛</span> : <Save size={16} />}
                    Save Segment
                </button>
            </div>
        </div>
    );
}

/**
 * AdAccountCard
 * 
 * Individual ad account display card with insights and actions.
 */
import { Facebook, Loader2, Trash2, RefreshCw, Pencil, AlertCircle } from 'lucide-react';
import { formatCurrency, formatCompact, formatNumber } from '../../utils/format';

interface AdAccount {
    id: string;
    platform: string;
    name: string;
    externalId: string;
}

interface AdInsights {
    spend: number;
    impressions: number;
    clicks: number;
    roas: number;
    currency: string;
}

interface AdAccountCardProps {
    account: AdAccount;
    insights?: AdInsights;
    isLoadingInsights: boolean;
    error?: string;
    onRefresh: () => void;
    onEdit: () => void;
    onDisconnect: () => void;
    onCompleteSetup: () => void;
    onReconnect: () => void;
}

/**
 * Google icon SVG component.
 */
function GoogleIcon({ className }: { className?: string }) {
    return (
        <svg className={className} viewBox="0 0 24 24" fill="currentColor">
            <path d="M22.56 12.25c0-.78-.07-1.53-.2-2.25H12v4.26h5.92c-.26 1.37-1.04 2.53-2.21 3.31v2.77h3.57c2.08-1.92 3.28-4.74 3.28-8.09z" />
            <path d="M12 23c2.97 0 5.46-.98 7.28-2.66l-3.57-2.77c-.98.66-2.23 1.06-3.71 1.06-2.86 0-5.29-1.93-6.16-4.53H2.18v2.84C3.99 20.53 7.7 23 12 23z" />
            <path d="M5.84 14.09c-.22-.66-.35-1.36-.35-2.09s.13-1.43.35-2.09V7.07H2.18C1.43 8.55 1 10.22 1 12s.43 3.45 1.18 4.93l2.85-2.22.81-.62z" />
            <path d="M12 5.38c1.62 0 3.06.56 4.21 1.64l3.15-3.15C17.45 2.09 14.97 1 12 1 7.7 1 3.99 3.47 2.18 7.07l3.66 2.84c.87-2.6 3.3-4.53 6.16-4.53z" />
        </svg>
    );
}

export function AdAccountCard({
    account,
    insights,
    isLoadingInsights,
    error,
    onRefresh,
    onEdit,
    onDisconnect,
    onCompleteSetup,
    onReconnect
}: AdAccountCardProps) {
    const isPending = account.externalId === 'PENDING_SETUP';

    return (
        <div className={`bg-white rounded-xl shadow-xs border p-4 ${isPending ? 'border-amber-300' : error ? 'border-red-200' : 'border-gray-200'}`}>
            <div className="flex justify-between items-start">
                <div className="flex items-center gap-3">
                    <div className={`p-2 rounded-lg ${account.platform === 'META' ? 'bg-blue-50 text-blue-600' : 'bg-red-50 text-red-600'}`}>
                        {account.platform === 'META' ? <Facebook size={20} /> : <GoogleIcon className="w-5 h-5" />}
                    </div>
                    <div>
                        <h3 className="font-semibold text-gray-900">{account.name}</h3>
                        <p className="text-xs text-gray-500 font-mono">{isPending ? 'Setup not complete' : account.externalId}</p>
                    </div>
                </div>
                <div className="flex items-center gap-2">
                    {isPending ? (
                        <button
                            onClick={onCompleteSetup}
                            className="bg-amber-100 text-amber-800 text-xs px-2 py-1 rounded-full hover:bg-amber-200"
                        >Complete Setup</button>
                    ) : (
                        <>
                            {error && <span className="bg-red-100 text-red-800 text-xs px-2 py-1 rounded-full">Error</span>}
                            {!error && <span className="bg-green-100 text-green-800 text-xs px-2 py-1 rounded-full">Active</span>}
                            <button
                                onClick={onRefresh}
                                disabled={isLoadingInsights}
                                className="p-1 text-gray-400 hover:text-blue-600 hover:bg-blue-50 rounded-sm disabled:opacity-50"
                                title="Refresh data"
                            >
                                <RefreshCw size={16} className={isLoadingInsights ? 'animate-spin' : ''} />
                            </button>
                            <button onClick={onEdit} className="p-1 text-gray-400 hover:text-blue-600 hover:bg-blue-50 rounded-sm" title="Edit credentials">
                                <Pencil size={16} />
                            </button>
                        </>
                    )}
                    <button onClick={onDisconnect} className="p-1 text-gray-400 hover:text-red-600 hover:bg-red-50 rounded-sm" title="Disconnect">
                        <Trash2 size={16} />
                    </button>
                </div>
            </div>

            {/* Insights Row */}
            {!isPending && insights && (
                <div className="mt-4 pt-4 border-t grid grid-cols-4 gap-4 text-sm">
                    <div>
                        <p className="text-xs text-gray-500 uppercase">Spend (30d)</p>
                        <p className="font-semibold">{formatCurrency(insights.spend, insights.currency || 'USD')}</p>
                    </div>
                    <div>
                        <p className="text-xs text-gray-500 uppercase">ROAS</p>
                        <p className="font-semibold">{(insights.roas || 0).toFixed(2)}x</p>
                    </div>
                    <div>
                        <p className="text-xs text-gray-500 uppercase">Impressions</p>
                        <p className="font-medium text-gray-700">{formatCompact(insights.impressions)}</p>
                    </div>
                    <div>
                        <p className="text-xs text-gray-500 uppercase">Clicks</p>
                        <p className="font-medium text-gray-700">{formatNumber(insights.clicks)}</p>
                    </div>
                </div>
            )}

            {/* Error Display */}
            {error && (
                <div className="mt-4 p-3 bg-red-50 border border-red-200 rounded-lg">
                    <div className="flex items-start justify-between gap-2">
                        <div className="flex items-start gap-2">
                            <AlertCircle className="text-red-500 shrink-0 mt-0.5" size={16} />
                            <div className="text-sm text-red-700">
                                <p className="font-medium">Failed to load data</p>
                                <p className="text-xs mt-1 text-red-600">{error}</p>
                            </div>
                        </div>
                        <button
                            onClick={onReconnect}
                            className="flex items-center gap-1.5 px-3 py-1.5 bg-blue-600 text-white text-xs font-medium rounded-lg hover:bg-blue-700 shrink-0"
                        >
                            <RefreshCw size={14} />
                            Reconnect
                        </button>
                    </div>
                </div>
            )}
        </div>
    );
}

export type { AdAccount, AdInsights };

/**
 * AdAccountModals
 * 
 * Edit and Pending Setup modals for ad account settings.
 */
import { Loader2, Pencil, X, Check, AlertCircle } from 'lucide-react';
import { Modal } from '../ui/Modal';

interface AdAccount {
    id: string;
    platform: string;
    name: string;
    externalId: string;
}

interface EditForm {
    name: string;
    externalId: string;
    accessToken: string;
    refreshToken: string;
}

interface EditAdAccountModalProps {
    account: AdAccount | null;
    form: EditForm;
    onFormChange: (form: EditForm) => void;
    onClose: () => void;
    onSave: () => void;
    isSaving: boolean;
}

export function EditAdAccountModal({
    account,
    form,
    onFormChange,
    onClose,
    onSave,
    isSaving
}: EditAdAccountModalProps) {
    if (!account) return null;

    return (
        <Modal
            isOpen={!!account}
            onClose={onClose}
            title={
                <div className="flex items-center gap-2">
                    <Pencil size={18} className="text-blue-600" />
                    <span>Edit {account.platform} Account</span>
                </div>
            }
            maxWidth="max-w-md"
        >
            <div className="space-y-4">
                <div>
                    <label className="block text-sm font-medium text-gray-700 mb-1">Account Name</label>
                    <input
                        type="text"
                        className="w-full p-2 border rounded-lg"
                        value={form.name}
                        onChange={e => onFormChange({ ...form, name: e.target.value })}
                    />
                </div>
                <div>
                    <label className="block text-sm font-medium text-gray-700 mb-1">
                        {account.platform === 'GOOGLE' ? 'Customer ID' : 'Ad Account ID'}
                    </label>
                    <input
                        type="text"
                        className="w-full p-2 border rounded-lg"
                        placeholder={account.externalId}
                        value={form.externalId}
                        onChange={e => onFormChange({ ...form, externalId: e.target.value })}
                    />
                </div>
                <div>
                    <label className="block text-sm font-medium text-gray-700 mb-1">New Access Token (leave blank to keep current)</label>
                    <input
                        type="password"
                        className="w-full p-2 border rounded-lg"
                        placeholder="Enter new access token..."
                        value={form.accessToken}
                        onChange={e => onFormChange({ ...form, accessToken: e.target.value })}
                    />
                    {account.platform === 'GOOGLE' && (
                        <p className="text-xs text-gray-500 mt-1">
                            To refresh expired tokens, disconnect and reconnect your account using the OAuth flow.
                        </p>
                    )}
                </div>
                {account.platform === 'GOOGLE' && (
                    <div>
                        <label className="block text-sm font-medium text-gray-700 mb-1">New Refresh Token (leave blank to keep current)</label>
                        <input
                            type="password"
                            className="w-full p-2 border rounded-lg"
                            placeholder="Enter new refresh token..."
                            value={form.refreshToken}
                            onChange={e => onFormChange({ ...form, refreshToken: e.target.value })}
