            {/* ── Utilities ──────────────────────────────── */}
            <div className="border-t border-slate-200 dark:border-slate-700 pt-5">
                <h3 className="text-sm font-semibold text-slate-700 dark:text-slate-300 uppercase tracking-wider mb-3 flex items-center gap-2">
                    <Database size={14} />
