 * - snap points support
 */

interface BottomSheetProps {
    isOpen: boolean;
    onClose: () => void;
    title?: string;
    children: ReactNode;
    snapPoints?: number[];
}

export function BottomSheet({ isOpen, onClose, title, children, snapPoints = [0.5] }: BottomSheetProps) {
    const sheetRef = useRef<HTMLDivElement>(null);
    const [dragY, setDragY] = useState(0);
    const [startY, setStartY] = useState(0);
    const [isDragging, setIsDragging] = useState(false);

    useEffect(() => {
        if (isOpen) {
            document.body.style.overflow = 'hidden';
        } else {
            document.body.style.overflow = '';
        }
        return () => {
            document.body.style.overflow = '';
        };
    }, [isOpen]);

    const handleTouchStart = (e: React.TouchEvent) => {
        setStartY(e.touches[0].clientY);
        setIsDragging(true);
    };

    const handleTouchMove = (e: React.TouchEvent) => {
        if (!isDragging) return;
        const currentY = e.touches[0].clientY;
        const diff = currentY - startY;
        if (diff > 0) {
            setDragY(diff);
        }
    };

    const handleTouchEnd = () => {
        setIsDragging(false);
        if (dragY > 100) {
            // Haptic feedback
            if ('vibrate' in navigator) {
                navigator.vibrate(10);
            }
            onClose();
        }
        setDragY(0);
    };

    if (!isOpen) return null;

    return (
        <div className="fixed inset-0 z-[100]">
            {/* Backdrop */}
            <div
                className="absolute inset-0 bg-black/50 transition-opacity"
                style={{ opacity: Math.max(0, 1 - dragY / 200) }}
                onClick={onClose}
            />

            {/* Sheet */}
            <div
                ref={sheetRef}
                className="absolute bottom-0 left-0 right-0 bg-white rounded-t-3xl max-h-[90vh] overflow-hidden"
                style={{
                    transform: `translateY(${dragY}px)`,
                    transition: isDragging ? 'none' : 'transform 0.3s ease-out',
                    paddingBottom: 'env(safe-area-inset-bottom)'
                }}
            >
                {/* Handle */}
                <div
                    className="flex justify-center pt-3 pb-2 cursor-grab active:cursor-grabbing"
                    onTouchStart={handleTouchStart}
                    onTouchMove={handleTouchMove}
                    onTouchEnd={handleTouchEnd}
                >
                    <div className="w-10 h-1 bg-gray-300 rounded-full" />
                </div>

                {/* Header */}
                {title && (
                    <div className="flex items-center justify-between px-4 pb-3 border-b border-gray-100">
                        <h2 className="text-lg font-bold text-gray-900">{title}</h2>
                        <button
                            onClick={onClose}
                            className="p-2 -mr-2 rounded-full hover:bg-gray-100 active:bg-gray-200"
                        >
                            <X size={20} className="text-gray-500" />
                        </button>
                    </div>
                )}

                {/* Content */}
                <div className="overflow-y-auto max-h-[70vh] p-4">
                    {children}
                </div>
            </div>
        </div>
    );
}

import { ChevronLeft, ChevronRight, ChevronsLeft, ChevronsRight } from 'lucide-react';
import { cn } from '../../utils/cn';

interface PaginationProps {
    currentPage: number;
    totalPages: number;
    onPageChange: (page: number) => void;
    itemsPerPage?: number;
    onItemsPerPageChange?: (limit: number) => void;
    allowItemsPerPage?: boolean;
    className?: string;
}

export function Pagination({
    currentPage,
    totalPages,
    onPageChange,
    itemsPerPage,
    onItemsPerPageChange,
    allowItemsPerPage = false,
    className
}: PaginationProps) {
    const isFirstPage = currentPage <= 1;
    const isLastPage = currentPage >= totalPages;

    const Button = ({
        onClick,
        disabled,
        children,
        title
    }: {
        onClick: () => void;
        disabled: boolean;
        children: React.ReactNode;
        title: string;
    }) => (
        <button
            onClick={onClick}
            disabled={disabled}
            title={title}
            className={cn(
                "p-2 border border-slate-200 rounded-lg text-slate-600 bg-white hover:bg-slate-50 transition-colors disabled:opacity-50 disabled:cursor-not-allowed",
                "focus:outline-hidden focus:ring-2 focus:ring-blue-500/20"
            )}
        >
            {children}
        </button>
    );

    return (
        <div className={cn("flex flex-wrap items-center justify-between gap-4 p-4 pr-24 bg-slate-50 border-t border-slate-100", className)}>
            {/* Items Per Page Selector */}
            <div className="flex items-center gap-2 text-sm text-slate-600">
                {allowItemsPerPage && itemsPerPage && onItemsPerPageChange && (
                    <>
                        <span className="text-xs text-slate-500 font-medium uppercase tracking-wide">Rows:</span>
                        <select
                            value={itemsPerPage}
                            onChange={(e) => onItemsPerPageChange(Number(e.target.value))}
                            className="bg-white border border-slate-200 text-slate-700 text-sm rounded-md focus:ring-blue-500 focus:border-blue-500 block p-1.5 outline-hidden"
                        >
                            {[15, 25, 50, 100].map((pageSize) => (
                                <option key={pageSize} value={pageSize}>
                                    {pageSize}
                                </option>
                            ))}
                        </select>
                    </>
                )}
            </div>

            {/* Pagination Controls */}
            <div className="flex items-center gap-2">
                <Button
                    onClick={() => onPageChange(1)}
                    disabled={isFirstPage}
                    title="First Page"
                >
                    <ChevronsLeft size={16} />
                </Button>

                <Button
                    onClick={() => onPageChange(currentPage - 1)}
                    disabled={isFirstPage}
                    title="Previous Page"
                >
                    <ChevronLeft size={16} />
                </Button>

                <span className="text-sm font-medium text-slate-600 min-w-[100px] text-center">
                    Page <span className="text-slate-900">{currentPage}</span> of <span className="text-slate-900">{Math.max(1, totalPages)}</span>
                </span>

                <Button
                    onClick={() => onPageChange(currentPage + 1)}
                    disabled={isLastPage}
                    title="Next Page"
                >
                    <ChevronRight size={16} />
                </Button>

                <Button
                    onClick={() => onPageChange(totalPages)}
                    disabled={isLastPage}
                    title="Last Page"
                >
                    <ChevronsRight size={16} />
                </Button>
            </div>
        </div>
    );
}

import { useState, useRef, useEffect, useCallback } from 'react';
import { Bookmark, ChevronDown, Plus, Trash2, X, Check } from 'lucide-react';
import { cn } from '../../utils/cn';
import { useSavedViews, SavedView } from '../../hooks/useSavedViews';
import { Toast, ToastType } from './Toast';

interface SavedViewsDropdownProps {
    /** Context for the saved views (e.g., 'orders', 'customers') */
    context: string;
    /** Current filter state to save when creating a new view */
    currentFilters: Record<string, unknown>;
    /** Callback when a view is applied */
    onApplyView: (filters: Record<string, unknown>) => void;
    /** Additional CSS classes */
    className?: string;
}

/**
 * SavedViewsDropdown - UI for managing saved filter presets.
 * Allows users to save, select, rename, and delete filter views.
 * 
 * @example
 * <SavedViewsDropdown
 *   context="orders"
 *   currentFilters={{ status: 'processing', tags: ['priority'] }}
 *   onApplyView={(filters) => setFilters(filters)}
 * />
 */
export function SavedViewsDropdown({
    context,
    currentFilters,
    onApplyView,
    className
}: SavedViewsDropdownProps) {
    const { views, activeView, saveCurrentView, applyView, removeView, clearActiveView } = useSavedViews(context);

    const [isOpen, setIsOpen] = useState(false);
    const [isCreating, setIsCreating] = useState(false);
    const [newViewName, setNewViewName] = useState('');
    const [confirmDeleteId, setConfirmDeleteId] = useState<string | null>(null);

    const [toastMessage, setToastMessage] = useState('');
    const [toastVisible, setToastVisible] = useState(false);
    const [toastType, setToastType] = useState<ToastType>('error');
    const showToast = useCallback((message: string, type: ToastType = 'error') => {
        setToastMessage(message); setToastType(type); setToastVisible(true);
    }, []);

    const dropdownRef = useRef<HTMLDivElement>(null);
    const inputRef = useRef<HTMLInputElement>(null);

    // Close dropdown when clicking outside
    useEffect(() => {
        function handleClickOutside(event: MouseEvent) {
            if (dropdownRef.current && !dropdownRef.current.contains(event.target as Node)) {
                setIsOpen(false);
                setIsCreating(false);
                setConfirmDeleteId(null);
            }
        }

        document.addEventListener('mousedown', handleClickOutside);
        return () => document.removeEventListener('mousedown', handleClickOutside);
    }, []);

    // Focus input when creating
    useEffect(() => {
        if (isCreating && inputRef.current) {
            inputRef.current.focus();
        }
    }, [isCreating]);

    const handleSaveView = () => {
        if (!newViewName.trim()) { showToast('View name is required'); return; }

        const savedView = saveCurrentView(newViewName.trim(), currentFilters);
        setNewViewName('');
        setIsCreating(false);
        showToast('View saved', 'success');
    };

    const handleApplyView = (view: SavedView) => {
        applyView(view.id);
        onApplyView(view.filters);
        setIsOpen(false);
    };

    const handleClearView = () => {
        clearActiveView();
        setIsOpen(false);
    };

    const handleDeleteView = (viewId: string, e: React.MouseEvent) => {
        e.stopPropagation();
        if (confirmDeleteId === viewId) {
            removeView(viewId);
            setConfirmDeleteId(null);
        } else {
            setConfirmDeleteId(viewId);
        }
    };

    const hasActiveFilters = Object.values(currentFilters).some(
        (v) => v !== null && v !== undefined && v !== '' && v !== 'all' &&
            !(Array.isArray(v) && v.length === 0)
    );

    return (
        <>
            <div ref={dropdownRef} className={cn("relative", className)}>
                {/* Trigger Button */}
                <button
                    onClick={() => setIsOpen(!isOpen)}
                    className={cn(
                        "flex items-center gap-2 px-3 py-2 rounded-lg border transition-all text-sm font-medium",
                        activeView
                            ? "bg-blue-50 border-blue-200 text-blue-700 hover:bg-blue-100"
                            : "bg-white border-gray-300 text-gray-700 hover:bg-gray-50"
                    )}
                >
                    <Bookmark size={16} className={activeView ? "fill-blue-600" : ""} />
                    <span className="hidden sm:inline">
                        {activeView ? activeView.name : 'Saved Views'}
                    </span>
                    {views.length > 0 && !activeView && (
                        <span className="bg-gray-200 text-gray-600 text-xs px-1.5 py-0.5 rounded-full">
                            {views.length}
                        </span>
                    )}
                    <ChevronDown
                        size={14}
                        className={cn("transition-transform", isOpen && "rotate-180")}
                    />
                </button>

                {/* Dropdown Menu */}
                {isOpen && (
                    <div className="absolute right-0 mt-2 w-72 bg-white border border-gray-200 rounded-xl shadow-lg z-30 overflow-hidden">
                        {/* Header */}
                        <div className="px-4 py-3 border-b border-gray-100 bg-gray-50">
                            <div className="flex items-center justify-between">
                                <span className="text-xs font-semibold text-gray-500 uppercase tracking-wide">
                                    Saved Views
                                </span>
                                {activeView && (
                                    <button
                                        onClick={handleClearView}
                                        className="text-xs text-blue-600 hover:underline"
                                    >
                                        Clear filter
                                    </button>
                                )}
                            </div>
                        </div>

                        {/* Views List */}
                        <div className="max-h-64 overflow-y-auto">
                            {views.length === 0 && !isCreating ? (
                                <div className="px-4 py-6 text-center text-gray-500">
                                    <Bookmark size={24} className="mx-auto mb-2 text-gray-300" />
                                    <p className="text-sm">No saved views yet</p>
                                    <p className="text-xs text-gray-400 mt-1">
                                        Save your current filters for quick access
                                    </p>
                                </div>
                            ) : (
                                views.map((view) => (
                                    <div
                                        key={view.id}
                                        onClick={() => handleApplyView(view)}
                                        className={cn(
                                            "flex items-center justify-between px-4 py-3 cursor-pointer transition-colors group",
                                            activeView?.id === view.id
                                                ? "bg-blue-50"
                                                : "hover:bg-gray-50"
                                        )}
                                    >
                                        <div className="flex items-center gap-3 min-w-0">
                                            {activeView?.id === view.id && (
                                                <Check size={14} className="text-blue-600 shrink-0" />
                                            )}
                                            <div className="min-w-0">
                                                <p className={cn(
                                                    "text-sm font-medium truncate",
                                                    activeView?.id === view.id ? "text-blue-700" : "text-gray-900"
                                                )}>
                                                    {view.name}
                                                </p>
                                                {view.isDefault && (
                                                    <span className="text-xs text-gray-400">Default</span>
                                                )}
                                            </div>
                                        </div>

                                        {!view.isDefault && (
                                            <button
                                                onClick={(e) => handleDeleteView(view.id, e)}
                                                className={cn(
                                                    "p-1.5 rounded transition-colors shrink-0",
                                                    confirmDeleteId === view.id
                                                        ? "bg-red-100 text-red-600"
                                                        : "text-gray-400 hover:text-red-500 hover:bg-red-50 opacity-0 group-hover:opacity-100"
                                                )}
                                                title={confirmDeleteId === view.id ? "Click again to confirm" : "Delete view"}
                                            >
                                                <Trash2 size={14} />
                                            </button>
                                        )}
                                    </div>
                                ))
                            )}
                        </div>

                        {/* Create New View */}
                        <div className="border-t border-gray-100">
                            {isCreating ? (
                                <div className="px-4 py-3">
                                    <div className="flex items-center gap-2">
                                        <input
                                            ref={inputRef}
                                            type="text"
                                            value={newViewName}
                                            onChange={(e) => setNewViewName(e.target.value)}
                                            onKeyDown={(e) => {
                                                if (e.key === 'Enter') handleSaveView();
                                                if (e.key === 'Escape') {
                                                    setIsCreating(false);
                                                    setNewViewName('');
                                                }
                                            }}
                                            placeholder="View name..."
                                            className="flex-1 px-3 py-2 text-sm border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-blue-500 outline-none"
                                        />
                                        <button
                                            onClick={handleSaveView}
                                            disabled={!newViewName.trim()}
                                            className="p-2 bg-blue-600 text-white rounded-lg hover:bg-blue-700 transition-colors disabled:opacity-50 disabled:cursor-not-allowed"
                                        >
                                            <Check size={16} />
                                        </button>
                                        <button
                                            onClick={() => {
                                                setIsCreating(false);
                                                setNewViewName('');
                                            }}
                                            className="p-2 text-gray-500 hover:text-gray-700 hover:bg-gray-100 rounded-lg transition-colors"
                                        >
                                            <X size={16} />
                                        </button>
                                    </div>
                                </div>
                            ) : (
                                <button
                                    onClick={() => setIsCreating(true)}
                                    disabled={!hasActiveFilters}
                                    className={cn(
                                        "w-full flex items-center gap-2 px-4 py-3 text-sm font-medium transition-colors",
                                        hasActiveFilters
                                            ? "text-blue-600 hover:bg-blue-50"
                                            : "text-gray-400 cursor-not-allowed"
                                    )}
                                >
                                    <Plus size={16} />
                                    Save current view
                                </button>
                            )}
                        </div>
                    </div>
                )}
            </div>

            <Toast message={toastMessage} isVisible={toastVisible} onClose={() => setToastVisible(false)} type={toastType} />
        </>);
}

import { cn } from '../../utils/cn';

interface SkeletonProps {
    /** Additional CSS classes */
    className?: string;
    /** Width (e.g., 'w-24', '100px') */
    width?: string;
    /** Height (e.g., 'h-4', '20px') */
    height?: string;
    /** Whether to use rounded corners */
    rounded?: 'none' | 'sm' | 'md' | 'lg' | 'full';
}

/**
 * Skeleton - Base animated placeholder for loading states.
 * Use instead of spinners for data-heavy screens to improve perceived performance.
 * 
 * @example
 * <Skeleton className="w-32 h-4" />
 */
export function Skeleton({
    className,
    width,
    height,
    rounded = 'md'
}: SkeletonProps) {
    const roundedClasses = {
        none: '',
        sm: 'rounded-sm',
        md: 'rounded-md',
        lg: 'rounded-lg',
        full: 'rounded-full'
    };

    return (
        <div
            className={cn(
                "animate-pulse bg-gradient-to-r from-slate-200 via-slate-100 to-slate-200 dark:from-slate-700 dark:via-slate-600 dark:to-slate-700 bg-[length:200%_100%]",
                roundedClasses[rounded],
                className
            )}
            style={{
                width: width || undefined,
                height: height || undefined
            }}
        />
    );
}

/**
 * SkeletonText - Text line placeholder with realistic proportions
 */
export function SkeletonText({
    lines = 1,
    className
}: {
    lines?: number;
    className?: string;
}) {
    return (
        <div className={cn("space-y-2", className)}>
            {Array.from({ length: lines }).map((_, i) => (
                <Skeleton
                    key={i}
                    className={cn(
                        "h-4",
                        // Last line is shorter for realism
                        i === lines - 1 && lines > 1 ? "w-3/4" : "w-full"
                    )}
                />
            ))}
        </div>
    );
}

/**
 * SkeletonAvatar - Circular avatar placeholder
 */
export function SkeletonAvatar({
    size = 'md',
    className
}: {
    size?: 'sm' | 'md' | 'lg';
    className?: string;
}) {
    const sizeClasses = {
        sm: 'w-8 h-8',
        md: 'w-10 h-10',
        lg: 'w-12 h-12'
    };

    return (
        <Skeleton
            className={cn(sizeClasses[size], className)}
            rounded="full"
        />
    );
}

/**
 * TableRowSkeleton - Complete table row skeleton for data tables
 */
export function TableRowSkeleton({
    columns = 5,
    className,
    showAvatar = false
}: {
    columns?: number;
    className?: string;
    showAvatar?: boolean;
}) {
    return (
        <tr className={cn("animate-pulse", className)}>
            {Array.from({ length: columns }).map((_, i) => (
                <td key={i} className="px-6 py-4">
                    {i === 0 && showAvatar ? (
                        <div className="flex items-center gap-3">
                            <SkeletonAvatar size="md" />
                            <div className="space-y-2">
                                <Skeleton className="h-4 w-24" />
                                <Skeleton className="h-3 w-32" />
                            </div>
                        </div>
                    ) : (
                        <Skeleton
                            className="h-4"
                            width={`${60 + Math.random() * 40}%`}
                        />
                    )}
                </td>
            ))}
        </tr>
    );
}

/**
 * TableSkeleton - Multiple rows of table skeletons
 */
export function TableSkeleton({
    rows = 5,
    columns = 5,
    showAvatar = false
}: {
    rows?: number;
    columns?: number;
    showAvatar?: boolean;
}) {
    return (
        <>
            {Array.from({ length: rows }).map((_, i) => (
                <TableRowSkeleton
                    key={i}
                    columns={columns}
                    showAvatar={showAvatar}
                />
            ))}
        </>
    );
}

/**
 * CardSkeleton - Dashboard card loading state
 */
export function CardSkeleton({ className }: { className?: string }) {
    return (
        <div className={cn(
            "bg-white dark:bg-slate-800/90 rounded-2xl border border-slate-200/80 dark:border-slate-700/50 p-6 animate-pulse",
            "shadow-[0_1px_3px_rgba(0,0,0,0.05),0_1px_2px_rgba(0,0,0,0.03)] dark:shadow-[0_1px_3px_rgba(0,0,0,0.2)]",
            className
        )}>
            <div className="flex items-center justify-between mb-4">
                <Skeleton className="h-5 w-32" />
                <Skeleton className="h-10 w-10" rounded="lg" />
            </div>
            <Skeleton className="h-8 w-24 mb-2" />
            <Skeleton className="h-4 w-28" />
        </div>
    );
}

import { useEffect, useState } from 'react';
import { Logger } from '../../utils/logger';
import { useAccount } from '../../context/AccountContext';
import { useAuth } from '../../context/AuthContext';
import { api } from '../../services/api';
import { Globe, Monitor, Smartphone, Tablet, Clock } from 'lucide-react';
import { WidgetProps } from './WidgetRegistry';

interface StatsData {
    countries: { country: string; sessions: number }[];
    devices: { type: string; sessions: number }[];
    browsers: { name: string; sessions: number }[];
    totalSessions: number;
    avgSessionDuration: number;
}

interface AnalyticsStatsWidgetProps {
    days?: number;
}

export const AnalyticsStatsWidget = ({ className, dateRange }: WidgetProps) => {
    const { currentAccount } = useAccount();
    const { token } = useAuth();
    const [stats, setStats] = useState<StatsData | null>(null);
    const [loading, setLoading] = useState(true);

    useEffect(() => {
        const fetchStats = async () => {
            if (!currentAccount || !token) return;
            try {
                const data = await api.get<StatsData>(`/api/tracking/stats?startDate=${dateRange.startDate}&endDate=${dateRange.endDate}`, token, currentAccount.id);
                setStats(data);
            } catch (error) {
                Logger.error('Failed to fetch stats:', { error: error });
            } finally {
                setLoading(false);
            }
        };
        fetchStats();
    }, [currentAccount, token, dateRange]);

    if (loading) {
        return <div className={`p-4 text-sm text-slate-500 dark:text-slate-400 ${className}`}>Loading stats...</div>;
    }

    if (!stats) {
        return <div className={`p-4 text-sm text-slate-500 dark:text-slate-400 ${className}`}>No data available</div>;
    }

    const formatDuration = (seconds: number) => {
        if (seconds < 60) return `${seconds}s`;
        const mins = Math.floor(seconds / 60);
        const secs = seconds % 60;
        return `${mins}m ${secs}s`;
    };

    const getDeviceIcon = (type: string) => {
        switch (type) {
            case 'mobile': return <Smartphone className="w-4 h-4" />;
            case 'tablet': return <Tablet className="w-4 h-4" />;
            default: return <Monitor className="w-4 h-4" />;
        }
    };

    return (
        <div className={`p-4 space-y-4 ${className}`}>
            {/* Summary Stats */}
            <div className="grid grid-cols-2 gap-4">
                <div className="bg-blue-50 dark:bg-blue-900/20 rounded-lg p-3">
                    <div className="text-xs text-blue-600 dark:text-blue-400 font-medium">Total Sessions</div>
                    <div className="text-2xl font-bold text-blue-700 dark:text-blue-300">{stats.totalSessions.toLocaleString()}</div>
                </div>
                <div className="bg-purple-50 dark:bg-purple-900/20 rounded-lg p-3">
                    <div className="text-xs text-purple-600 dark:text-purple-400 font-medium flex items-center gap-1">
                        <Clock className="w-3 h-3" /> Avg Duration
                    </div>
                    <div className="text-2xl font-bold text-purple-700 dark:text-purple-300">{formatDuration(stats.avgSessionDuration)}</div>
                </div>
            </div>

            {/* Top Countries */}
            <div>
                <div className="text-xs font-semibold text-slate-500 dark:text-slate-400 uppercase mb-2 flex items-center gap-1">
                    <Globe className="w-3 h-3" /> Top Countries
                </div>
                <div className="space-y-1">
                    {stats.countries.slice(0, 5).map((c, i) => (
                        <div key={c.country} className="flex items-center justify-between text-sm">
                            <span className="text-slate-700 dark:text-slate-300">{c.country}</span>
                            <span className="text-slate-500 dark:text-slate-400">{c.sessions}</span>
                        </div>
                    ))}
                </div>
            </div>

            {/* Devices */}
            <div>
                <div className="text-xs font-semibold text-slate-500 dark:text-slate-400 uppercase mb-2">Devices</div>
                <div className="flex gap-2">
                    {stats.devices.map(d => (
