interface CartItem {
    productId: number;
    variationId?: number;
    name: string;
    sku?: string;
    thumbnail?: string;
    quantity: number;
    price: number;
    total: number;
}

interface CartSession {
    id: string;
    visitorId: string;
    email?: string | null;
    cartValue: number;
    cartItems: CartItem[];
    itemCount: number;
    currency: string;
    lastActiveAt: string;
    country?: string | null;
    city?: string | null;
    customerName?: string | null;
