import React, { createContext, useContext, useEffect, useState } from 'react';
import { io, Socket } from 'socket.io-client';
import { useAuth } from './AuthContext';
import { useAccount } from './AccountContext';
import { Logger } from '../utils/logger';

interface SocketContextType {
    socket: Socket | null;
    isConnected: boolean;
}

const SocketContext = createContext<SocketContextType>({
    socket: null,
    isConnected: false
});

export const useSocket = () => useContext(SocketContext);

export const SocketProvider = ({ children }: { children: React.ReactNode }) => {
    const { token } = useAuth();
    const { currentAccount } = useAccount();
    const [socket, setSocket] = useState<Socket | null>(null);
    const [isConnected, setIsConnected] = useState(false);

    useEffect(() => {
        if (!token || !currentAccount) {
            if (socket) {
                socket.disconnect();
                setSocket(null);
            }
            return;
        }

        // Initialize socket
        // Assume API is on same host/port in dev relative to proxy, 
        // OR define env. But setup usually proxies /api.
        // If create-react-app or vite sends /api -> localhost:3000, 
        // socket.io client usually needs full URL if not same origin serving.
        // Assuming Vite proxy setting handles /socket.io or we use hardcoded port for now.
        // Let's assume standard behavior:
        // Connect to relative path so Vite proxy handles it
        const newSocket = io('/', {
            path: '/socket.io',
            auth: { token },
            query: { accountId: currentAccount.id }
        });

        newSocket.on('connect', () => {
            Logger.debug('Socket connected', { accountId: currentAccount.id });
            setIsConnected(true);
            newSocket.emit('join:account', currentAccount.id);
        });

        newSocket.on('disconnect', () => {
            Logger.debug('Socket disconnected');
            setIsConnected(false);
        });

        setSocket(newSocket);

        return () => {
            newSocket.disconnect();
        };
    }, [token, currentAccount?.id]);

    return (
        <SocketContext.Provider value={{ socket, isConnected }}>
            {children}
        </SocketContext.Provider>
    );
};

import { createContext, useContext, useState, useEffect, ReactNode, useCallback } from 'react';
import { Logger } from '../utils/logger';
import { useAccount } from './AccountContext';
import { useAuth } from './AuthContext';
import { useSocket } from './SocketContext';
import { useVisibilityPolling } from '../hooks/useVisibilityPolling';


export interface SyncJob {
    id: string;
    queue: string;
    progress: number;
    data: unknown;
}

export interface SyncLog {
    id: string;
    entityType: string;
    status: 'SUCCESS' | 'FAILED' | 'IN_PROGRESS';
    itemsProcessed: number;
    errorMessage?: string;
    startedAt: string;
    completedAt?: string | null;
    /** Enriched fields from /health endpoint */
    triggerSource?: string;
    retryCount?: number;
    errorCode?: string;
    friendlyError?: string;
    nextRetryAt?: string | null;
    willRetry?: boolean;
    maxAttempts?: number;
}

export interface SyncState {
    id: string;
    accountId: string;
    entityType: string;
    lastSyncedAt: string | null;
    cursor: string | null;
    updatedAt: string;
}

/** Summary returned by the /health endpoint */
export interface SyncHealthSummary {
    lastSuccessAt: string | null;
    lastFailureAt: string | null;
    failureRate24h: number;
    activeJobs: number;
    circuitBreaker?: {
        isOpen: boolean;
        byEntity: Record<string, boolean>;
    };
}


interface SyncStatusContextType {
    isSyncing: boolean;
    activeJobs: SyncJob[];
    syncState: SyncState[];
    logs: SyncLog[];
    healthSummary: SyncHealthSummary | null;

    controlSync: (action: 'pause' | 'resume' | 'cancel', queueName?: string, jobId?: string) => Promise<void>;
    runSync: (types?: string[], incremental?: boolean) => Promise<void>;
    retrySync: (entityType: string, logId?: string) => Promise<void>;
    resetCircuit: (entityType?: string) => Promise<void>;
    reindexOrders: () => Promise<{ totalIndexed: number }>;
    refreshStatus: () => void;
}

const SyncStatusContext = createContext<SyncStatusContextType | undefined>(undefined);

/**
 * Why: Centralises all sync-related API calls and real-time state so
 * every component (sidebar, settings panel, overlays) shares one
 * source of truth without duplicating fetch logic.
 */
export function SyncStatusProvider({ children }: { children: ReactNode }) {
    const { token } = useAuth();
    const { currentAccount } = useAccount();
    const { socket } = useSocket();
    const [activeJobs, setActiveJobs] = useState<SyncJob[]>([]);
    const [syncState, setSyncState] = useState<SyncState[]>([]);
    const [logs, setLogs] = useState<SyncLog[]>([]);
    const [isSyncing, setIsSyncing] = useState(false);
    const [healthSummary, setHealthSummary] = useState<SyncHealthSummary | null>(null);


    /** Helper to build auth headers */
    const headers = useCallback(() => {
        if (!currentAccount?.id || !token) return null;
        return {
            'Content-Type': 'application/json',
            Authorization: `Bearer ${token}`,
            'x-account-id': currentAccount.id,
        };
    }, [currentAccount?.id, token]);

    const fetchStatus = useCallback(async () => {
        const h = headers();
        if (!h || !currentAccount?.id) return;

        try {
            // Fetch active jobs
            const url = new URL('/api/sync/active', window.location.origin);
            url.searchParams.append('accountId', currentAccount.id);
            const res = await fetch(url.toString(), { headers: h });
            if (res.ok) {
                const data = await res.json();
                setActiveJobs(data);
                setIsSyncing(data.length > 0);
            }

            // Fetch health (includes enriched logs with retry info)
            const healthRes = await fetch(`/api/sync/health?accountId=${currentAccount.id}`, { headers: h });
            if (healthRes.ok) {
                const data = await healthRes.json();
                setSyncState(data.state || []);
                setLogs(data.recent || []);
                setHealthSummary(data.summary || null);
            } else {
                // Fallback to basic status if health endpoint isn't available
                const stateRes = await fetch(`/api/sync/status?accountId=${currentAccount.id}`, { headers: h });
                if (stateRes.ok) {
                    const data = await stateRes.json();
                    setSyncState(data.state || []);
                    setLogs(data.logs || []);
                }
            }
        } catch (error) {
            Logger.error('Failed to fetch sync status', { error });
        }
    }, [currentAccount?.id, headers]);

    // Listen for Socket.IO sync events (real-time updates)
    useEffect(() => {
        if (!socket) return;

        const handleSyncStarted = (_data: { accountId: string; type: string }) => {
            setIsSyncing(true);
            fetchStatus();
        };

        const handleSyncCompleted = (_data: { accountId: string; type: string; status: string; error?: string }) => {
            fetchStatus();
        };

        socket.on('sync:started', handleSyncStarted);
        socket.on('sync:completed', handleSyncCompleted);

        return () => {
            socket.off('sync:started', handleSyncStarted);
            socket.off('sync:completed', handleSyncCompleted);
        };
    }, [socket, fetchStatus]);

    /** Why 120s: Socket events handle real-time sync updates (started/completed).
     *  Polling is just a fallback for missed events — 30s was unnecessarily aggressive.
     *  This eliminates ~6 API calls/minute per active user. */
    useVisibilityPolling(fetchStatus, 120_000, [fetchStatus], 'sync-context');

    const controlSync = async (action: 'pause' | 'resume' | 'cancel', queueName?: string, jobId?: string) => {
        const h = headers();
        if (!h || !currentAccount?.id) return;

        try {
            const res = await fetch('/api/sync/control', {
                method: 'POST',
                headers: h,
                body: JSON.stringify({ accountId: currentAccount.id, action, queueName, jobId })
            });

            if (!res.ok) {
                const errorData = await res.json().catch(() => ({ message: 'Unknown error' }));
                throw new Error(`Control action failed: ${errorData.message || res.statusText}`);
            }

            fetchStatus();
        } catch (error) {
            Logger.error(`Failed to ${action} sync`, { error });
            throw error;
        }
    };

    const runSync = async (types?: string[], incremental: boolean = true) => {
        const h = headers();
        if (!h || !currentAccount?.id) return;

        try {
            await fetch('/api/sync/manual', {
                method: 'POST',
                headers: h,
                body: JSON.stringify({ accountId: currentAccount.id, types, incremental })
            });
            fetchStatus();
        } catch (error) {
            Logger.error('Failed to start sync', { error });
            throw error;
        }
    };

    /** Retry a specific failed entity type */
    const retrySync = async (entityType: string, logId?: string) => {
        const h = headers();
        if (!h || !currentAccount?.id) return;

        try {
            const res = await fetch('/api/sync/retry', {
                method: 'POST',
                headers: h,
                body: JSON.stringify({ entityType, logId })
            });

            if (!res.ok) {
                const errorData = await res.json().catch(() => ({ error: 'Unknown error' }));
                throw new Error(errorData.error || res.statusText);
            }

            fetchStatus();
        } catch (error) {
            Logger.error('Failed to retry sync', { error });
            throw error;
        }
    };

    /**
     * Reset the circuit breaker for the current account.
     * Writes synthetic SUCCESS logs to break the consecutive-failure streak,
     * then kicks off an immediate incremental sync.
     */
    const resetCircuit = async (entityType?: string) => {
        const h = headers();
        if (!h || !currentAccount?.id) return;

        try {
            const res = await fetch('/api/sync/reset-circuit', {
                method: 'POST',
                headers: h,
                body: JSON.stringify({ entityType })
            });

            if (!res.ok) {
                const errorData = await res.json().catch(() => ({ error: 'Unknown error' }));
                throw new Error(errorData.error || res.statusText);
            }

            fetchStatus();
        } catch (error) {
            Logger.error('Failed to reset circuit breaker', { error });
            throw error;
        }
    };

    /** Rebuild ES search index from Postgres source of truth */
    const reindexOrders = async (): Promise<{ totalIndexed: number }> => {
        const h = headers();
        if (!h || !currentAccount?.id) throw new Error('Please select an account before reindexing');

        const res = await fetch('/api/sync/orders/reindex', {
            method: 'POST',
            headers: h,
            body: JSON.stringify({ accountId: currentAccount.id })
        });

        if (!res.ok) {
            const errorData = await res.json().catch(() => ({ error: 'Reindex failed' }));
            throw new Error(errorData.error || res.statusText);
        }

        const data = await res.json();
        fetchStatus();
        return data;
    };

    return (
        <SyncStatusContext.Provider value={{
            isSyncing, activeJobs, syncState, logs, healthSummary,
            controlSync, runSync, retrySync, resetCircuit, reindexOrders, refreshStatus: fetchStatus
        }}>
            {children}
        </SyncStatusContext.Provider>
    );
}

export function useSyncStatus() {
    const context = useContext(SyncStatusContext);
    if (!context) {
        throw new Error('useSyncStatus must be used within a SyncStatusProvider');
    }
    return context;
}

import { createContext, useContext, useEffect, useState, ReactNode } from 'react';

type Theme = 'light' | 'dark' | 'system';

interface ThemeContextValue {
    /** Current theme setting */
    theme: Theme;
    /** Resolved theme (never 'system', always 'light' or 'dark') */
    resolvedTheme: 'light' | 'dark';
    /** Set the theme */
    setTheme: (theme: Theme) => void;
    /** Toggle between light and dark */
    toggleTheme: () => void;
}

const ThemeContext = createContext<ThemeContextValue | undefined>(undefined);

const STORAGE_KEY = 'overseek-theme';

/**
 * Determines the resolved theme based on preference and system settings.
 */
function getResolvedTheme(theme: Theme): 'light' | 'dark' {
    if (theme === 'system') {
        return window.matchMedia('(prefers-color-scheme: dark)').matches ? 'dark' : 'light';
    }
    return theme;
}

interface ThemeProviderProps {
    children: ReactNode;
    /** Default theme if none is saved */
    defaultTheme?: Theme;
}

/**
 * ThemeProvider - Manages app-wide theme state.
 * Syncs to localStorage and responds to system preference changes.
 * 
 * @example
 * // In App.tsx
 * <ThemeProvider>
 *   <App />
 * </ThemeProvider>
 * 
 * // In any component
 * const { theme, toggleTheme } = useTheme();
 */
export function ThemeProvider({ children, defaultTheme = 'system' }: ThemeProviderProps) {
    const [theme, setThemeState] = useState<Theme>(() => {
        // Read from localStorage on mount
        if (typeof window !== 'undefined') {
            const stored = localStorage.getItem(STORAGE_KEY) as Theme | null;
            return stored || defaultTheme;
        }
        return defaultTheme;
    });

    const [resolvedTheme, setResolvedTheme] = useState<'light' | 'dark'>(() =>
        getResolvedTheme(theme)
    );

    // Apply theme to document
    useEffect(() => {
        const resolved = getResolvedTheme(theme);

        // Defer state update to avoid cascading renders
        const timeoutId = setTimeout(() => {
            setResolvedTheme(resolved);
        }, 0);

        // Apply class to document root for Tailwind dark mode
        document.documentElement.classList.remove('light', 'dark');
        document.documentElement.classList.add(resolved);

        // Also set data attribute for CSS selectors
        document.documentElement.setAttribute('data-theme', resolved);

        return () => clearTimeout(timeoutId);
    }, [theme]);

    // Listen for system preference changes when theme is 'system'
    useEffect(() => {
        if (theme !== 'system') return;

        const mediaQuery = window.matchMedia('(prefers-color-scheme: dark)');

        const handleChange = (e: MediaQueryListEvent) => {
            setResolvedTheme(e.matches ? 'dark' : 'light');
            document.documentElement.classList.remove('light', 'dark');
            document.documentElement.classList.add(e.matches ? 'dark' : 'light');
        };

        mediaQuery.addEventListener('change', handleChange);
        return () => mediaQuery.removeEventListener('change', handleChange);
    }, [theme]);

    const setTheme = (newTheme: Theme) => {
        setThemeState(newTheme);
        localStorage.setItem(STORAGE_KEY, newTheme);
    };

    const toggleTheme = () => {
        const newTheme = resolvedTheme === 'light' ? 'dark' : 'light';
        setTheme(newTheme);
    };

    return (
        <ThemeContext.Provider value={{ theme, resolvedTheme, setTheme, toggleTheme }}>
            {children}
        </ThemeContext.Provider>
    );
}

/**
 * useTheme - Hook to access and control the current theme.
 */
export function useTheme() {
    const context = useContext(ThemeContext);
    if (!context) {
        throw new Error('useTheme must be used within a ThemeProvider');
    }
    return context;
}

