import { useCallback, useEffect, useMemo, useRef, useState } from 'react';

type QueryKey = readonly unknown[];

type QueryCacheEntry<T> = {
    data: T;
    updatedAt: number;
    keyParts: QueryKey;
};

const queryCache = new Map<string, QueryCacheEntry<unknown>>();
const queryListeners = new Map<string, Set<() => void>>();

function keyToString(key: QueryKey): string {
    return JSON.stringify(key);
}

function notifyKey(keyString: string): void {
    const listeners = queryListeners.get(keyString);
    if (!listeners) return;
    for (const listener of listeners) listener();
}

function subscribeKey(keyString: string, cb: () => void): () => void {
    const listeners = queryListeners.get(keyString) ?? new Set<() => void>();
    listeners.add(cb);
    queryListeners.set(keyString, listeners);

    return () => {
        const current = queryListeners.get(keyString);
        if (!current) return;
        current.delete(cb);
        if (current.size === 0) queryListeners.delete(keyString);
    };
}

function startsWithPrefix(keyParts: QueryKey, prefix: QueryKey): boolean {
    if (prefix.length > keyParts.length) return false;
    for (let i = 0; i < prefix.length; i += 1) {
        if (keyParts[i] !== prefix[i]) return false;
    }
    return true;
}

export function invalidateQuery(prefix: QueryKey): void {
    for (const [keyString, entry] of queryCache.entries()) {
        if (startsWithPrefix(entry.keyParts, prefix)) {
            queryCache.delete(keyString);
            notifyKey(keyString);
        }
    }
}

interface UseApiQueryOptions<TData> {
    queryKey: QueryKey;
    queryFn: () => Promise<TData>;
    enabled?: boolean;
    staleTime?: number;
    refetchOnWindowFocus?: boolean;
}

interface UseApiQueryResult<TData> {
    data: TData | undefined;
    isLoading: boolean;
    error: Error | null;
    refetch: () => Promise<TData | undefined>;
}

export function useApiQuery<TData>({
    queryKey,
    queryFn,
    enabled = true,
    staleTime = 0,
    refetchOnWindowFocus = true,
}: UseApiQueryOptions<TData>): UseApiQueryResult<TData> {
    const keyString = useMemo(() => keyToString(queryKey), [queryKey]);
    const [data, setData] = useState<TData | undefined>(() => {
        const cached = queryCache.get(keyString) as QueryCacheEntry<TData> | undefined;
        return cached?.data;
    });
    const [isLoading, setIsLoading] = useState<boolean>(() => enabled && !queryCache.has(keyString));
    const [error, setError] = useState<Error | null>(null);
    const fetchSeqRef = useRef(0);

    const executeFetch = useCallback(async (force = false): Promise<TData | undefined> => {
        if (!enabled) {
            setIsLoading(false);
            return undefined;
        }

        const cached = queryCache.get(keyString) as QueryCacheEntry<TData> | undefined;
        const isFresh = Boolean(cached && (Date.now() - cached.updatedAt) < staleTime);
        if (!force && isFresh) {
            setData(cached?.data);
            setIsLoading(false);
            setError(null);
            return cached?.data;
        }

        const seq = fetchSeqRef.current + 1;
        fetchSeqRef.current = seq;
        setIsLoading(true);

        try {
            const result = await queryFn();
            if (fetchSeqRef.current !== seq) return undefined;

            queryCache.set(keyString, {
                data: result,
                updatedAt: Date.now(),
                keyParts: queryKey,
            });
            setData(result);
            setError(null);
            setIsLoading(false);
            return result;
        } catch (err) {
            if (fetchSeqRef.current !== seq) return undefined;

            setError(err instanceof Error ? err : new Error(String(err)));
            setIsLoading(false);
            throw err;
        }
    }, [enabled, keyString, queryFn, queryKey, staleTime]);

    useEffect(() => {
        let cancelled = false;

        executeFetch().catch(() => {
            if (cancelled) return;
        });

        return () => {
            cancelled = true;
        };
    }, [executeFetch]);

    useEffect(() => {
        const unsubscribe = subscribeKey(keyString, () => {
            executeFetch(true).catch(() => {
                // Intentionally swallowed: consumers rely on state flags.
            });
        });

        return unsubscribe;
    }, [executeFetch, keyString]);

    useEffect(() => {
        if (!refetchOnWindowFocus) return;

        const handleFocus = () => {
            executeFetch().catch(() => {
                // Intentionally swallowed: consumers rely on state flags.
            });
        };

        window.addEventListener('focus', handleFocus);
        return () => window.removeEventListener('focus', handleFocus);
    }, [executeFetch, refetchOnWindowFocus]);

    const refetch = useCallback(() => executeFetch(true), [executeFetch]);

    return { data, isLoading, error, refetch };
}

interface MutateCallbacks<TData> {
    onSuccess?: (data: TData) => void;
    onError?: (error: Error) => void;
}

interface UseApiMutationOptions<TData, TVariables> {
    mutationFn: (variables: TVariables) => Promise<TData>;
    invalidateQueries?: QueryKey[];
    onSuccess?: (data: TData, variables: TVariables) => void;
}

interface UseApiMutationResult<TData, TVariables> {
    mutate: (variables?: TVariables, callbacks?: MutateCallbacks<TData>) => void;
    mutateAsync: (variables?: TVariables) => Promise<TData>;
    isPending: boolean;
    error: Error | null;
}

export function useApiMutation<TData, TVariables = void>({
    mutationFn,
    invalidateQueries: invalidatePrefixes = [],
    onSuccess,
}: UseApiMutationOptions<TData, TVariables>): UseApiMutationResult<TData, TVariables> {
    const [isPending, setIsPending] = useState(false);
    const [error, setError] = useState<Error | null>(null);

    const mutateAsync = useCallback(async (variables?: TVariables): Promise<TData> => {
        setIsPending(true);
        setError(null);

        try {
            const data = await mutationFn(variables as TVariables);
            for (const prefix of invalidatePrefixes) invalidateQuery(prefix);
            onSuccess?.(data, variables as TVariables);
            setIsPending(false);
            return data;
        } catch (err) {
            const parsed = err instanceof Error ? err : new Error(String(err));
            setError(parsed);
            setIsPending(false);
            throw parsed;
        }
    }, [invalidatePrefixes, mutationFn, onSuccess]);

    const mutate = useCallback((variables?: TVariables, callbacks?: MutateCallbacks<TData>) => {
        mutateAsync(variables)
            .then((data) => {
                callbacks?.onSuccess?.(data);
            })
            .catch((err) => {
                const parsed = err instanceof Error ? err : new Error(String(err));
                callbacks?.onError?.(parsed);
            });
    }, [mutateAsync]);

    return { mutate, mutateAsync, isPending, error };
}

import { useCallback, useEffect, useState } from 'react';
import { Logger } from '../utils/logger';

/**
 * Background Fetch status
 */
type BackgroundFetchStatus = 'pending' | 'success' | 'fail' | 'aborted';

interface BackgroundFetchProgress {
    id: string;
    downloaded: number;
    total: number;
    status: BackgroundFetchStatus;
}

/**
 * Hook for Background Fetch API
 *
 * Enables large file downloads/uploads that survive app close.
 * Falls back to regular fetch for unsupported browsers.
 *
 * @example
 * ```tsx
 * const { startBackgroundFetch, isSupported } = useBackgroundFetch();
 *
 * // Download large file in background
 * const result = await startBackgroundFetch(
 *   'video-export',
 *   ['/api/exports/video/123'],
 *   { title: 'Exporting video...', icons: [{ src: '/icons/icon-96.png' }] }
 * );
 * ```
 */
export function useBackgroundFetch() {
    const [isSupported] = useState(() => {
        if (typeof navigator === 'undefined') return false;
        return 'serviceWorker' in navigator;
    });

    const [activeFetches, setActiveFetches] = useState<Map<string, BackgroundFetchProgress>>(new Map());

    /**
     * Starts a background fetch operation.
     * Falls back to regular fetch on unsupported browsers.
     */
    const startBackgroundFetch = useCallback(async (
        id: string,
        requests: (string | Request)[],
        options?: {
            title?: string;
            icons?: Array<{ src: string; sizes?: string; type?: string }>;
            downloadTotal?: number;
        }
    ): Promise<Response[] | null> => {
        // Check for Background Fetch support
        const registration = await navigator.serviceWorker?.ready;

        // @ts-expect-error - backgroundFetch not in TypeScript types
        if (!registration?.backgroundFetch) {
            Logger.debug('[BackgroundFetch] Not supported, falling back to regular fetch');
            // Fallback to regular fetch
            try {
                const responses = await Promise.all(
                    requests.map(req => fetch(req))
                );
                return responses;
            } catch (err) {
                Logger.error('[BackgroundFetch] Fallback fetch failed:', { error: err });
                return null;
            }
        }

        try {
            // @ts-expect-error - backgroundFetch not in TypeScript types
            const bgFetch = await registration.backgroundFetch.fetch(id, requests, {
                title: options?.title || 'Downloading...',
                icons: options?.icons || [],
                downloadTotal: options?.downloadTotal
            });

            // Track progress
            setActiveFetches(prev => {
                const next = new Map(prev);
                next.set(id, {
                    id,
                    downloaded: 0,
                    total: options?.downloadTotal || 0,
                    status: 'pending'
                });
                return next;
            });

            // Listen for progress
            bgFetch.addEventListener('progress', () => {
                setActiveFetches(prev => {
                    const next = new Map(prev);
                    next.set(id, {
                        id,
                        downloaded: bgFetch.downloaded,
                        total: bgFetch.downloadTotal,
                        status: 'pending'
                    });
                    return next;
                });
            });

            Logger.debug('[BackgroundFetch] Started:', { id, requestCount: requests.length });

            // Wait for completion
            const result = await bgFetch.result;
            const records = await bgFetch.matchAll();
            const responses = await Promise.all(records.map((r: { responseReady: Promise<Response> }) => r.responseReady));

            // Update status
            setActiveFetches(prev => {
                const next = new Map(prev);
                next.set(id, {
                    id,
                    downloaded: bgFetch.downloaded,
                    total: bgFetch.downloadTotal,
                    status: result as BackgroundFetchStatus
                });
                return next;
            });

            return responses;
        } catch (err) {
            Logger.error('[BackgroundFetch] Failed:', { id, error: err });
            setActiveFetches(prev => {
                const next = new Map(prev);
                next.set(id, {
                    id,
                    downloaded: 0,
                    total: 0,
                    status: 'fail'
                });
                return next;
            });
            return null;
        }
    }, []);

    /**
     * Aborts an active background fetch.
     */
    const abortBackgroundFetch = useCallback(async (id: string): Promise<boolean> => {
        try {
            const registration = await navigator.serviceWorker?.ready;
            // @ts-expect-error - backgroundFetch not in TypeScript types
            const bgFetch = await registration?.backgroundFetch?.get(id);
            if (bgFetch) {
                await bgFetch.abort();
                setActiveFetches(prev => {
                    const next = new Map(prev);
                    next.delete(id);
                    return next;
                });
                return true;
            }
            return false;
        } catch (err) {
            Logger.warn('[BackgroundFetch] Abort failed:', { id, error: err });
            return false;
        }
    }, []);

    /**
     * Gets progress for a specific background fetch.
     */
    const getProgress = useCallback((id: string): BackgroundFetchProgress | undefined => {
        return activeFetches.get(id);
    }, [activeFetches]);

    return {
        startBackgroundFetch,
        abortBackgroundFetch,
        getProgress,
        activeFetches,
        isSupported
    };
}

