import { useEffect, useState, useRef, useCallback } from 'react';

/**
 * Unique identifier for this browser tab instance.
 * Generated once per page load to ensure consistent identity.
 */
const TAB_ID = `tab-${Date.now()}-${Math.random().toString(36).substring(2, 9)}`;

/**
 * Heartbeat interval for leader election (ms).
 * Leader broadcasts heartbeat at this interval; followers detect leader loss after 2x this value.
 */
const HEARTBEAT_INTERVAL = 2000;
const LEADER_TIMEOUT = HEARTBEAT_INTERVAL * 2.5;

interface TabMessage {
    type: 'heartbeat' | 'claim' | 'resign';
    tabId: string;
    timestamp: number;
}

/**
 * Hook for cross-tab leader election using BroadcastChannel.
 * Only ONE tab becomes the leader; others become followers.
 * 
 * Uses lowest-ID-wins algorithm with heartbeat-based failure detection.
 * 
 * @param channelName - Unique channel name for this leader election group
 * @returns { isLeader, tabId } - Whether this tab is the leader and its unique ID
 * 
 * @example
 * const { isLeader, tabId } = useTabLeader('overseek-polling');
 * if (isLeader) {
 *   // Only this tab should poll the API
 * }
 */
export function useTabLeader(channelName: string): { isLeader: boolean; tabId: string } {
    const [isLeader, setIsLeader] = useState(false);
    const channelRef = useRef<BroadcastChannel | null>(null);
    const knownTabsRef = useRef<Map<string, number>>(new Map());
    const heartbeatIntervalRef = useRef<ReturnType<typeof setInterval> | null>(null);
    const leaderCheckIntervalRef = useRef<ReturnType<typeof setInterval> | null>(null);

    /**
     * Determines if this tab should be leader based on lowest-ID-wins algorithm.
     * Why: Deterministic election without coordination overhead.
     */
    const determineLeadership = useCallback(() => {
        const now = Date.now();
        // Filter out stale tabs (no heartbeat within timeout)
        const activeTabs: string[] = [];
        knownTabsRef.current.forEach((timestamp, tabId) => {
            if (now - timestamp < LEADER_TIMEOUT) {
                activeTabs.push(tabId);
            } else {
                knownTabsRef.current.delete(tabId);
            }
        });

        // Add self if not present
        if (!activeTabs.includes(TAB_ID)) {
            activeTabs.push(TAB_ID);
        }

        // Lowest ID wins
        activeTabs.sort();
        const shouldBeLeader = activeTabs[0] === TAB_ID;

        setIsLeader(shouldBeLeader);
    }, []);

    /**
     * Broadcasts a heartbeat message to all tabs.
     */
    const sendHeartbeat = useCallback(() => {
        if (channelRef.current) {
            const message: TabMessage = {
                type: 'heartbeat',
                tabId: TAB_ID,
                timestamp: Date.now(),
            };
            channelRef.current.postMessage(message);
        }
        // Update own timestamp
        knownTabsRef.current.set(TAB_ID, Date.now());
    }, []);

    useEffect(() => {
        // BroadcastChannel not supported in all environments (e.g., SSR, older browsers)
        if (typeof BroadcastChannel === 'undefined') {
            // Fallback: this tab is always leader
            setIsLeader(true);
            return;
        }

        const channel = new BroadcastChannel(channelName);
        channelRef.current = channel;

        // Handle incoming messages
        channel.onmessage = (event: MessageEvent<TabMessage>) => {
            const { type, tabId, timestamp } = event.data;

            if (type === 'heartbeat' || type === 'claim') {
                knownTabsRef.current.set(tabId, timestamp);
                determineLeadership();
            } else if (type === 'resign') {
                knownTabsRef.current.delete(tabId);
                determineLeadership();
            }
        };

        // Register self immediately
        knownTabsRef.current.set(TAB_ID, Date.now());

        // Claim leadership candidacy on mount
        const claimMessage: TabMessage = {
            type: 'claim',
            tabId: TAB_ID,
            timestamp: Date.now(),
        };
        channel.postMessage(claimMessage);

        // Start heartbeat
        heartbeatIntervalRef.current = setInterval(sendHeartbeat, HEARTBEAT_INTERVAL);

        // Periodically check for stale leaders
        leaderCheckIntervalRef.current = setInterval(determineLeadership, HEARTBEAT_INTERVAL);

        // Initial leadership determination
        determineLeadership();

        // Cleanup on unmount
        return () => {
            // Notify other tabs this tab is leaving
            if (channelRef.current) {
                const resignMessage: TabMessage = {
                    type: 'resign',
                    tabId: TAB_ID,
                    timestamp: Date.now(),
                };
                channelRef.current.postMessage(resignMessage);
                channelRef.current.close();
            }

            if (heartbeatIntervalRef.current) {
                clearInterval(heartbeatIntervalRef.current);
            }
            if (leaderCheckIntervalRef.current) {
                clearInterval(leaderCheckIntervalRef.current);
            }
        };
    }, [channelName, determineLeadership, sendHeartbeat]);

    return { isLeader, tabId: TAB_ID };
}

import { useCallback, useState, useEffect } from 'react';

/**
 * Hook for View Transitions API
 *
 * Provides smooth, native-like page transition animations.
 * Falls back gracefully on unsupported browsers.
 *
 * @example
 * ```tsx
 * const { startViewTransition, isSupported } = useViewTransition();
 *
 * // Wrap navigation in a transition
 * startViewTransition(() => {
 *   navigate('/new-page');
 * });
 * ```
 */
export function useViewTransition() {
    const [isSupported] = useState(() => 'startViewTransition' in document);
    const [isTransitioning, setIsTransitioning] = useState(false);

    /**
     * Starts a view transition, wrapping the DOM update callback.
     * Falls back to immediate execution on unsupported browsers.
     */
    const startViewTransition = useCallback(async (updateCallback: () => void | Promise<void>) => {
        // Unsupported browsers - execute immediately
        if (!isSupported || !('startViewTransition' in document)) {
            await updateCallback();
            return;
        }

        setIsTransitioning(true);

        try {
            const transition = document.startViewTransition(async () => {
                await updateCallback();
            });

            await transition.finished;
        } catch {
            // Transition failed - DOM update should still have occurred
        } finally {
            setIsTransitioning(false);
        }
    }, [isSupported]);

    return {
        startViewTransition,
        isSupported,
        isTransitioning
    };
}

/**
 * CSS helper to add to your stylesheets for View Transitions.
 *
 * Add these styles to enable smooth page transitions:
 *
 * ```css
 * @view-transition {
 *   navigation: auto;
 * }
 *
 * ::view-transition-old(root) {
 *   animation: 150ms ease-out fade-out;
 * }
 *
 * ::view-transition-new(root) {
 *   animation: 150ms ease-in fade-in;
 * }
 *
 * @keyframes fade-out {
 *   from { opacity: 1; }
 *   to { opacity: 0; }
 * }
 *
 * @keyframes fade-in {
 *   from { opacity: 0; }
 *   to { opacity: 1; }
 * }
 * ```
 */

import React, { useState } from 'react';
import { NavLink, Outlet } from 'react-router-dom';
import {
    BarChart3, DollarSign, GitBranch,
    TrendingUp, Search, LogOut, Download
} from 'lucide-react';
import { DateRangeFilter } from '../components/analytics/DateRangeFilter';

const navItems = [
    { to: '/analytics', label: 'Overview', icon: BarChart3, end: true },
    { to: '/analytics/revenue', label: 'Revenue', icon: DollarSign },
    { to: '/analytics/attribution', label: 'Attribution', icon: GitBranch },
    { to: '/analytics/cohorts', label: 'Cohorts', icon: TrendingUp },
];

interface AnalyticsLayoutProps {
    days: number;
    setDays: (days: number) => void;
}

export const AnalyticsLayout: React.FC<AnalyticsLayoutProps> = ({ days, setDays }) => {
    return (
        <div className="h-full flex flex-col">
            {/* Sub Navigation */}
            <div className="bg-white border-b border-gray-200 px-6 py-3">
                <div className="flex items-center justify-between">
                    <div className="flex items-center gap-1">
                        {navItems.map(item => (
                            <NavLink
                                key={item.to}
                                to={item.to}
                                end={item.end}
                                className={({ isActive }) =>
                                    `flex items-center gap-2 px-4 py-2 text-sm font-medium rounded-lg transition-all ${isActive
                                        ? 'bg-blue-50 text-blue-600'
                                        : 'text-gray-600 hover:bg-gray-50 hover:text-gray-900'
                                    }`
                                }
                            >
                                <item.icon className="w-4 h-4" />
                                {item.label}
                            </NavLink>
                        ))}
                    </div>
                    <div className="flex items-center gap-3">
                        <DateRangeFilter value={days} onChange={setDays} />
                        <a
                            href={`/api/tracking/export?days=${days}`}
                            className="flex items-center gap-2 px-3 py-1.5 text-xs font-medium text-gray-600 hover:text-gray-900 bg-gray-100 hover:bg-gray-200 rounded-lg transition-colors"
                        >
                            <Download className="w-3.5 h-3.5" />
                            Export
                        </a>
                    </div>
                </div>
            </div>

            {/* Page Content */}
            <div className="flex-1 overflow-y-auto bg-gray-50/50">
                <Outlet context={{ days }} />
            </div>
        </div>
    );
};

export default AnalyticsLayout;

import { useEffect, useState } from 'react';
import { Logger } from '../utils/logger';
import { useNavigate } from 'react-router-dom';
import { useAuth } from '../context/AuthContext';
import { useAccount } from '../context/AccountContext';
import { Search, Users, Loader2, Mail, ShoppingBag, Calendar, RefreshCw } from 'lucide-react';
import { Pagination } from '../components/ui/Pagination';
import { TableSkeleton } from '../components/ui/Skeleton';
import { EmptyState } from '../components/ui/EmptyState';
import { RelativeTime } from '../components/ui/RelativeTime';
import { formatDate, formatCurrency } from '../utils/format';

interface Customer {
    id: string;
    firstName: string;
    lastName: string;
    email: string;
    totalSpent: number;
    ordersCount: number;
    dateCreated: string;
}

export function CustomersPage() {
    const navigate = useNavigate();
    const { token } = useAuth();
    const { currentAccount } = useAccount();
    const [customers, setCustomers] = useState<Customer[]>([]);
    const [isLoading, setIsLoading] = useState(true);
    const [searchQuery, setSearchQuery] = useState('');
    const [page, setPage] = useState(1);
    const [limit, setLimit] = useState(20);
    const [totalPages, setTotalPages] = useState(1);
    const [totalItems, setTotalItems] = useState(0);

    const [debouncedQuery, setDebouncedQuery] = useState('');
    const currency = currentAccount?.currency || 'USD';

    useEffect(() => {
        const timer = setTimeout(() => {
            setDebouncedQuery(searchQuery);
            setPage(1);
        }, 500);
        return () => clearTimeout(timer);
    }, [searchQuery]);

    useEffect(() => {
        fetchCustomers();
    }, [currentAccount, token, debouncedQuery, page, limit]);

    async function fetchCustomers() {
        if (!currentAccount || !token) return;

        setIsLoading(true);
        try {
            const params = new URLSearchParams({
                page: page.toString(),
                limit: limit.toString(),
                q: debouncedQuery
            });

            const res = await fetch(`/api/customers?${params}`, {
                headers: {
                    'Authorization': `Bearer ${token}`,
                    'X-Account-ID': currentAccount.id
                }
            });

            if (res.ok) {
                const data = await res.json();
                setCustomers(data.customers);
                setTotalPages(data.totalPages);
                setTotalItems(data.total);
            }
        } catch (err) {
            Logger.error('An error occurred', { error: err });
        } finally {
            setIsLoading(false);
        }
    }

    return (
        <div className="space-y-6">
            <div className="flex flex-col sm:flex-row justify-between items-start sm:items-center gap-4">
                <div>
                    <h1 className="text-xl md:text-2xl font-bold text-gray-900">Customers</h1>
                    <p className="text-sm text-gray-500">View and manage your customer base</p>
                </div>
                <div className="flex flex-col sm:flex-row items-stretch sm:items-center gap-3 w-full sm:w-auto">
                    <button
                        onClick={() => navigate('/customers/segments')}
                        className="flex items-center justify-center gap-2 px-4 py-2 bg-white text-gray-700 border border-gray-300 rounded-lg hover:bg-gray-50 transition-colors font-medium text-sm"
                    >
                        <Users size={16} />
                        Segments
                    </button>
                    <div className="relative flex-1 sm:flex-none">
                        <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-gray-400" size={18} />
                        <input
                            type="text"
                            placeholder="Search customers..."
                            className="w-full sm:w-64 pl-10 pr-4 py-2 border border-gray-300 rounded-lg outline-hidden focus:ring-2 focus:ring-blue-500"
                            value={searchQuery}
                            onChange={(e) => setSearchQuery(e.target.value)}
                        />
                    </div>
                </div>
            </div>

            <div className="bg-white rounded-xl shadow-xs border border-gray-200 overflow-hidden">
                <div className="overflow-x-auto">
                    <table className="w-full text-left border-collapse min-w-[600px]">
                        <thead>
                            <tr className="bg-gray-50 border-b border-gray-200 text-xs uppercase text-gray-500 font-semibold">
                                <th className="px-3 md:px-6 py-3 md:py-4">Customer</th>
                                <th className="px-3 md:px-6 py-3 md:py-4">Contact</th>
                                <th className="px-3 md:px-6 py-3 md:py-4">Orders</th>
                                <th className="px-3 md:px-6 py-3 md:py-4">Total Spent</th>
                                <th className="px-3 md:px-6 py-3 md:py-4">Joined</th>
                            </tr>
                        </thead>
                        <tbody className="divide-y divide-gray-100">
                            {isLoading ? (
                                <TableSkeleton rows={8} columns={5} showAvatar />
                            ) : customers.length === 0 ? (
                                <tr><td colSpan={5}>
                                    <EmptyState
                                        icon={<Users size={48} />}
                                        title="No customers found"
                                        description="Customers will appear here once they place orders. Try syncing your store data."
                                    />
                                </td></tr>
                            ) : (
                                customers.map((customer) => (
                                    <tr key={customer.id} className="hover:bg-gray-50 transition-colors cursor-pointer" onClick={() => {
                                        navigate(`/customers/${encodeURIComponent(customer.id)}`)
                                    }}>

                                        <td className="px-6 py-4">
                                            <div className="flex items-center gap-3" title={customer.email}>
                                                <div className="w-10 h-10 rounded-full bg-blue-100 text-blue-600 flex items-center justify-center font-bold text-sm">
                                                    {customer.firstName?.[0]}{customer.lastName?.[0]}
                                                </div>
                                                <div>
                                                    <div className="font-medium text-gray-900">{customer.firstName} {customer.lastName}</div>
                                                </div>
                                            </div>
                                        </td>
                                        <td className="px-6 py-4 text-sm text-gray-500">
                                            <div className="flex items-center gap-2">
                                                <Mail size={14} />
                                                {customer.email}
                                            </div>
                                        </td>
                                        <td className="px-6 py-4 text-sm text-gray-500">
                                            <div
                                                className="flex items-center gap-2 cursor-default"
                                                title={`Total spent: ${formatCurrency(customer.totalSpent, currency)} across ${customer.ordersCount} order${customer.ordersCount !== 1 ? 's' : ''}`}
                                            >
                                                <ShoppingBag size={14} />
                                                {customer.ordersCount} order{customer.ordersCount !== 1 ? 's' : ''}
                                            </div>
                                        </td>
                                        <td className="px-6 py-4 font-medium text-gray-900">
                                            <span
                                                title={`${customer.ordersCount} order${customer.ordersCount !== 1 ? 's' : ''} · Avg ${formatCurrency(customer.ordersCount > 0 ? customer.totalSpent / customer.ordersCount : 0, currency)}`}
                                                className="cursor-default border-b border-dotted border-gray-300"
                                            >
                                                {formatCurrency(customer.totalSpent, currency)}
                                            </span>
                                        </td>
                                        <td className="px-6 py-4 text-sm text-gray-500">
                                            <div className="flex items-center gap-2">
                                                <Calendar size={14} />
                                                <div>
                                                    <div>{formatDate(customer.dateCreated)}</div>
                                                    <RelativeTime date={customer.dateCreated} />
                                                </div>
                                            </div>
                                        </td>
                                    </tr>
                                ))
                            )}
                        </tbody>
                    </table>
                </div>
                {!isLoading && customers.length > 0 && (
                    <Pagination
                        currentPage={page}
                        totalPages={totalPages}
                        onPageChange={setPage}
                        itemsPerPage={limit}
                        onItemsPerPageChange={(newLimit) => {
                            setLimit(newLimit);
                            setPage(1);
                        }}
                        allowItemsPerPage={true}
                    />
                )}
            </div>
        </div >
    );
}

import { useState } from 'react';
import { getHelpCollections } from '../../data/helpContent';
import { HelpSearch } from '../../components/HelpCenter/HelpSearch';
import { useNavigate } from 'react-router-dom';
import { BookOpen, Box, Settings, Map, FileText, HelpCircle, TrendingUp, Users, ShoppingCart, MessageSquare, Tag, Compass, Package, Truck, BarChart2 } from 'lucide-react';

const ICON_MAP: Record<string, any> = {
    'Box': Box,
    'Settings': Settings,
    'Map': Map,
    'FileText': FileText,
    'TrendingUp': TrendingUp,
    'Users': Users,
    'ShoppingCart': ShoppingCart,
    'MessageSquare': MessageSquare,
    'Tag': Tag,
    'Compass': Compass,
    'Package': Package,
    'Truck': Truck,
    'BarChart2': BarChart2,
    'default': BookOpen
};

export function HelpCenterHome() {
    const navigate = useNavigate();
    // Use static content - no API call needed
    const collections = getHelpCollections();

    return (
        <div className="max-w-7xl mx-auto">
            {/* Header Section */}
            <div className="text-center py-12 px-4 mb-10 bg-linear-to-b from-white to-gray-50/50 rounded-2xl border border-gray-100 shadow-xs">
                <h1 className="text-3xl md:text-4xl font-bold text-gray-900 mb-4 tracking-tight">How can we help you?</h1>
                <p className="text-gray-500 mb-8 max-w-lg mx-auto text-lg leading-relaxed">Search for answers or browse our help guide collections.</p>
                <div className="flex justify-center">
                    <HelpSearch />
                </div>
            </div>

            {/* Collections Grid */}
            <div className="pb-12">
                <h2 className="text-xl font-semibold text-gray-900 mb-6 px-1">Help Collections</h2>
