/**
 * SeoPage — Standalone page for SEO keyword insights and tracking.
 *
 * Premium design: gradient header, glass pill tabs, animated tab content.
 * Why a separate page: SEO tracking has enough depth to warrant its own
 * space separate from the Marketing hub.
 *
 * Why selectedSiteUrl lives here: both the Overview and Tracker tabs
 * benefit from a shared domain context so users don't have to re-select
 * when switching tabs.
 */

import { useState, useEffect } from 'react';
import { Target, TrendingUp, Globe, ChevronDown } from 'lucide-react';
import { ErrorBoundary } from '../components/ui/ErrorBoundary';
import { SeoKeywordsPanel } from '../components/Seo/SeoKeywordsPanel';
import { KeywordTrackerPanel } from '../components/Seo/KeywordTrackerPanel';
import { useSearchConsoleStatus, useSetDefaultSite } from '../hooks/useSeoKeywords';

type TabId = 'overview' | 'tracker';

const tabs = [
    { id: 'overview' as TabId, label: 'SEO Overview', icon: Target },
    { id: 'tracker' as TabId, label: 'Keyword Tracker', icon: TrendingUp },
];

/**
 * Extract a human-readable label from a GSC siteUrl.
 * "sc-domain:example.com" → "example.com"
 * "https://example.com/" → "example.com"
 */
function prettySiteUrl(raw: string): string {
    return raw
        .replace(/^sc-domain:/, '')
        .replace(/^https?:\/\//, '')
        .replace(/\/$/, '');
}

export function SeoPage() {
    const [activeTab, setActiveTab] = useState<TabId>('overview');
    const status = useSearchConsoleStatus();
    const sites = status.data?.sites ?? [];
    const [selectedSiteUrl, setSelectedSiteUrl] = useState<string | undefined>();
    const setDefaultSite = useSetDefaultSite();

    /** Initialize from the persisted default, falling back to first site */
    useEffect(() => {
        if (sites.length > 0 && !selectedSiteUrl) {
            const defaultUrl = status.data?.defaultSiteUrl;
            // Use the persisted default if it's still in the connected sites list
            const validDefault = defaultUrl && sites.some((s: { siteUrl: string }) => s.siteUrl === defaultUrl);
            setSelectedSiteUrl(validDefault ? defaultUrl : sites[0].siteUrl);
        }
    }, [sites, selectedSiteUrl, status.data?.defaultSiteUrl]);

    return (
        <div className="space-y-8">
            {/* Hero Header with mesh background */}
            <div className="relative overflow-hidden rounded-2xl bg-gradient-to-br from-slate-50 via-blue-50/50 to-violet-50/30 dark:from-slate-900 dark:via-blue-950/30 dark:to-violet-950/20 border border-slate-200/60 dark:border-slate-700/40 px-8 py-8">
                {/* Decorative gradient orbs */}
                <div className="absolute -top-20 -right-20 w-64 h-64 bg-blue-400/10 dark:bg-blue-500/5 rounded-full blur-3xl" />
                <div className="absolute -bottom-16 -left-16 w-48 h-48 bg-violet-400/10 dark:bg-violet-500/5 rounded-full blur-3xl" />

                <div className="relative z-10 flex flex-col sm:flex-row sm:items-center sm:justify-between gap-4">
                    <div className="flex flex-col gap-2">
                        <h1 className="text-3xl font-bold tracking-tight text-gradient">
                            SEO & Organic Search
                        </h1>
                        <p className="text-slate-500 dark:text-slate-400 max-w-lg">
                            Monitor organic search performance, track keyword rankings, and discover growth opportunities.
                        </p>
                    </div>

                    {/* Domain selector — only visible when GSC is connected */}
                    {sites.length > 0 && (
                        <div className="shrink-0">
                            {sites.length === 1 ? (
                                /* Single site: static badge */
                                <div className="inline-flex items-center gap-2 px-4 py-2 rounded-xl bg-white/70 dark:bg-slate-800/60 backdrop-blur-sm border border-slate-200/60 dark:border-slate-700/40 text-sm font-medium text-slate-700 dark:text-slate-300">
                                    <Globe size={14} className="text-blue-500" />
                                    {prettySiteUrl(sites[0].siteUrl)}
                                </div>
                            ) : (
                                /* Multiple sites: dropdown selector */
                                <div className="relative inline-flex items-center">
                                    <Globe size={14} className="absolute left-3 text-blue-500 pointer-events-none z-10" />
                                    <select
                                        id="seo-domain-selector"
                                        value={selectedSiteUrl ?? ''}
                                        onChange={e => {
                                            const url = e.target.value;
                                            setSelectedSiteUrl(url);
                                            setDefaultSite.mutate(url);
                                        }}
                                        className="appearance-none pl-8 pr-8 py-2 rounded-xl bg-white/70 dark:bg-slate-800/60 backdrop-blur-sm border border-slate-200/60 dark:border-slate-700/40 text-sm font-medium text-slate-700 dark:text-slate-300 cursor-pointer hover:border-blue-300 dark:hover:border-blue-600 transition-colors focus:outline-none focus:ring-2 focus:ring-blue-500/30"
                                    >
                                        {sites.map((site: { id: string; siteUrl: string }) => (
                                            <option key={site.id} value={site.siteUrl}>
                                                {prettySiteUrl(site.siteUrl)}
                                            </option>
                                        ))}
                                    </select>
                                    <ChevronDown size={14} className="absolute right-2.5 text-slate-400 pointer-events-none" />
                                </div>
                            )}
                        </div>
                    )}
                </div>
            </div>

            {/* Glass Pill Tabs */}
            <div className="flex bg-slate-100/80 dark:bg-slate-800/60 backdrop-blur-sm p-1 rounded-xl border border-slate-200/50 dark:border-slate-700/40 w-fit">
                {tabs.map(tab => {
                    const Icon = tab.icon;
                    const isActive = activeTab === tab.id;
                    return (
                        <button
                            key={tab.id}
                            onClick={() => setActiveTab(tab.id)}
                            className={`flex items-center gap-2 px-5 py-2.5 font-medium text-sm rounded-lg transition-all duration-200 ${isActive
                                ? 'bg-white dark:bg-slate-700 text-slate-900 dark:text-slate-100 shadow-sm'
                                : 'text-slate-500 dark:text-slate-400 hover:text-slate-700 dark:hover:text-slate-300'
                                }`}
                        >
                            <Icon size={16} />
                            {tab.label}
                        </button>
                    );
                })}
            </div>

            {/* Animated Tab Content */}
            <div key={activeTab} className="animate-fade-slide-up">
                {activeTab === 'overview' && (
                    <ErrorBoundary>
                        <SeoKeywordsPanel siteUrl={selectedSiteUrl} />
                    </ErrorBoundary>
                )}

                {activeTab === 'tracker' && (
                    <ErrorBoundary>
                        <KeywordTrackerPanel />
                    </ErrorBoundary>
                )}
            </div>
        </div>
    );
}

import { useEffect, useState } from 'react';
import { Logger } from '../../utils/logger';
import { useAuth } from '../../context/AuthContext';
import {
    Sparkles,
    Save,
    Loader2,
    Check,
    AlertCircle,
    ChevronDown,
    ChevronUp,
    Info
} from 'lucide-react';

interface AIPrompt {
    id: string;
    name: string;
    description: string;
    content: string;
    updatedAt: string;
}

interface PromptConfig {
    id: string;
    name: string;
    description: string;
    placeholder: string;
    helpText?: string;
}

/**
 * Defines all available AI prompt configurations.
 * Add new prompts here as needed in the future.
 */
const PROMPT_CONFIGS: PromptConfig[] = [
    {
        id: 'product_description',
        name: 'Product Description Generator',
        description: 'Generate compelling product descriptions for WooCommerce products',
        placeholder: 'You are a skilled copywriter. Rewrite and improve the following product description.\n\nProduct Name: {{product_name}}\nCategory: {{category}}\nCurrent Description: {{current_description}}\nShort Description: {{short_description}}\n\nWrite an improved description that is:\n- Engaging and persuasive\n- SEO-friendly\n- 150-200 words\n- Maintains the key product information\n\nIMPORTANT: Return the description as valid HTML. Use proper HTML tags:\n- Use <p> for paragraphs\n- Use <h3> or <h4> for section headings if appropriate\n- Use <ul> and <li> for feature lists\n- Use <strong> or <em> for emphasis\n\nDo NOT include any markdown. Only return the HTML content, no wrapping code blocks.',
        helpText: 'Available variables: {{product_name}}, {{category}}, {{current_description}}, {{short_description}}'
    },
    {
        id: 'customer_email',
        name: 'Customer Email Response',
        description: 'Draft professional email responses to customer inquiries',
        placeholder: 'You are a helpful customer service representative. Draft a professional response to the following customer inquiry:\n\nCustomer Message: {{message}}\nOrder Details: {{order_details}}\n\nBe:\n- Polite and empathetic\n- Clear and concise\n- Solution-oriented',
        helpText: 'Available variables: {{message}}, {{order_details}}, {{customer_name}}'
    },
    {
        id: 'review_reply',
        name: 'Review Reply Generator',
        description: 'Generate thoughtful replies to customer reviews',
        placeholder: 'You are responding to a customer review on behalf of the store. Generate a professional and warm reply:\n\nReview Rating: {{rating}}/5\nReview Text: {{review_text}}\nProduct: {{product_name}}\n\nGuidelines:\n- Thank the customer\n- Address specific points mentioned\n- If negative, offer solution\n- Keep it under 100 words',
        helpText: 'Available variables: {{rating}}, {{review_text}}, {{product_name}}, {{customer_name}}'
    },
    {
        id: 'seo_meta',
        name: 'SEO Meta Generator',
        description: 'Generate SEO-optimized meta titles and descriptions',
        placeholder: 'Generate SEO meta content for the following page:\n\nPage Type: {{page_type}}\nPrimary Keyword: {{keyword}}\nContent Summary: {{summary}}\n\nProvide:\n1. Meta Title (50-60 characters)\n2. Meta Description (150-160 characters)\n\nEnsure keywords are naturally incorporated.',
        helpText: 'Available variables: {{page_type}}, {{keyword}}, {{summary}}'
    },
    {
        id: 'inbox_draft_reply',
        name: 'Inbox Draft Reply Generator',
        description: 'Generate draft replies for customer conversations in the inbox',
        placeholder: 'You are a helpful customer service agent. Draft a professional reply to the customer based on the conversation history and customer context.\n\nCONVERSATION HISTORY:\n{{conversation_history}}\n\nCUSTOMER DETAILS:\n{{customer_details}}\n\nSTORE POLICIES:\n{{policies}}\n\nGuidelines:\n- Be polite, empathetic, and professional\n- Reference specific order details if mentioned in the conversation\n- Follow store policies when applicable\n- Keep response concise but complete\n- Address all customer concerns raised\n\nIMPORTANT: Return the reply as valid HTML. Use:\n- <p> for paragraphs\n- <strong> for emphasis\n- <ul>/<li> for lists if needed\n\nDo NOT include markdown, code blocks, or any wrapping. Only return the HTML content of the reply.',
        helpText: 'Available variables: {{conversation_history}}, {{customer_details}}, {{policies}}'
    }
];


/**
 * Super Admin page for managing AI prompts across the platform.
 * Prompts are stored in the database and used by various AI features.
 */
export function AdminAIPromptsPage() {
    const { token } = useAuth();
    const [prompts, setPrompts] = useState<AIPrompt[]>([]);
    const [loading, setLoading] = useState(true);
    const [saving, setSaving] = useState<string | null>(null);
    const [formData, setFormData] = useState<Record<string, string>>({});
    const [message, setMessage] = useState<{ type: 'success' | 'error'; text: string } | null>(null);
    const [expandedPanels, setExpandedPanels] = useState<Record<string, boolean>>({});

    useEffect(() => {
        fetchPrompts();
        // Expand all panels by default
        const initialExpanded: Record<string, boolean> = {};
        PROMPT_CONFIGS.forEach(config => {
            initialExpanded[config.id] = true;
        });
        setExpandedPanels(initialExpanded);
    }, [token]);

    /**
     * Fetches all AI prompts from the server.
     */
    async function fetchPrompts() {
        try {
            const res = await fetch('/api/admin/ai-prompts', {
                headers: { Authorization: `Bearer ${token}` }
            });

            if (!res.ok) {
                // If endpoint doesn't exist yet, just use empty data
                setPrompts([]);
                initializeFormData([]);
                return;
            }

            const data = await res.json();
            setPrompts(data);
            initializeFormData(data);
        } catch (err) {
            Logger.error('Failed to fetch AI prompts:', { error: err });
            setPrompts([]);
            initializeFormData([]);
        } finally {
            setLoading(false);
        }
    }

    /**
     * Initializes form data with existing prompts or placeholders.
     */
    function initializeFormData(existingPrompts: AIPrompt[]) {
        const initial: Record<string, string> = {};
        PROMPT_CONFIGS.forEach(config => {
            const existing = existingPrompts.find(p => p.id === config.id);
            initial[config.id] = existing?.content || '';
        });
        setFormData(initial);
    }

    /**
     * Saves a single prompt to the server.
     */
    async function handleSave(promptId: string) {
        setSaving(promptId);
        setMessage(null);

        const content = formData[promptId]?.trim();
        if (!content) {
            setMessage({ type: 'error', text: 'Prompt content cannot be empty' });
            setSaving(null);
            return;
        }

        try {
            const res = await fetch(`/api/admin/ai-prompts/${promptId}`, {
                method: 'PUT',
                headers: {
                    'Content-Type': 'application/json',
                    Authorization: `Bearer ${token}`
                },
                body: JSON.stringify({ content })
            });

            if (res.ok) {
                const config = PROMPT_CONFIGS.find(c => c.id === promptId);
                setMessage({ type: 'success', text: `${config?.name || 'Prompt'} saved successfully` });
                fetchPrompts();
            } else {
                const err = await res.json();
                setMessage({ type: 'error', text: err.error || 'Failed to save prompt' });
            }
        } catch (err) {
            setMessage({ type: 'error', text: 'Network error while saving' });
        } finally {
            setSaving(null);
        }
    }

    /**
     * Resets a prompt to its default placeholder value.
     */
    function handleResetToDefault(promptId: string) {
        const config = PROMPT_CONFIGS.find(c => c.id === promptId);
        if (config) {
            setFormData(prev => ({
                ...prev,
                [promptId]: config.placeholder
            }));
        }
    }

    /**
     * Toggles panel expansion state.
     */
    function togglePanel(promptId: string) {
        setExpandedPanels(prev => ({
            ...prev,
            [promptId]: !prev[promptId]
        }));
    }

    /**
     * Gets the last updated date for a prompt.
     */
    function getLastUpdated(promptId: string): string | null {
        const prompt = prompts.find(p => p.id === promptId);
        return prompt?.updatedAt ? new Date(prompt.updatedAt).toLocaleDateString() : null;
    }

    /**
     * Checks if a prompt has been configured.
     */
    function isConfigured(promptId: string): boolean {
        return prompts.some(p => p.id === promptId);
    }

    if (loading) {
        return (
            <div className="flex items-center justify-center py-12">
                <Loader2 className="animate-spin text-gray-400" size={32} />
            </div>
        );
    }

    return (
        <div className="max-w-4xl">
            {/* Header */}
            <div className="flex items-center gap-3 mb-6">
                <Sparkles className="text-purple-600" size={28} />
                <h1 className="text-2xl font-bold text-slate-800">AI Prompts</h1>
            </div>

            <p className="text-slate-600 mb-6">
                Configure AI prompts used throughout the platform. These prompts define how AI generates
                content for various features like product descriptions, email responses, and more.
            </p>

            {/* Global Message */}
            {message && (
                <div className={`mb-6 p-4 rounded-lg flex items-center gap-2 ${message.type === 'success' ? 'bg-green-50 text-green-800' : 'bg-red-50 text-red-800'
                    }`}>
                    {message.type === 'success' ? <Check size={18} /> : <AlertCircle size={18} />}
                    {message.text}
                </div>
            )}

            {/* Prompt Panels */}
            <div className="space-y-4">
                {PROMPT_CONFIGS.map((config) => {
                    const isExpanded = expandedPanels[config.id];
                    const configured = isConfigured(config.id);
                    const lastUpdated = getLastUpdated(config.id);

                    return (
                        <div
                            key={config.id}
                            className="bg-white rounded-xl border border-slate-200 shadow-xs overflow-hidden"
                        >
                            {/* Panel Header - Clickable to expand/collapse */}
                            <button
                                onClick={() => togglePanel(config.id)}
                                className="w-full p-5 flex items-center justify-between bg-linear-to-r from-slate-50 to-white hover:from-slate-100 transition-colors"
                            >
                                <div className="flex items-center gap-3">
                                    <Sparkles className="text-purple-500" size={20} />
                                    <div className="text-left">
                                        <div className="flex items-center gap-2">
                                            <h3 className="font-semibold text-slate-900">{config.name}</h3>
                                            {configured && (
                                                <span className="bg-green-100 text-green-800 text-xs px-2 py-0.5 rounded-full">
                                                    Configured
                                                </span>
                                            )}
                                        </div>
                                        <p className="text-sm text-slate-500">{config.description}</p>
                                    </div>
                                </div>
                                <div className="flex items-center gap-3">
                                    {lastUpdated && (
                                        <span className="text-xs text-slate-400">
                                            Updated: {lastUpdated}
                                        </span>
                                    )}
                                    {isExpanded ? (
                                        <ChevronUp className="text-slate-400" size={20} />
                                    ) : (
                                        <ChevronDown className="text-slate-400" size={20} />
                                    )}
                                </div>
                            </button>

                            {/* Panel Content */}
                            {isExpanded && (
                                <div className="border-t border-slate-100">
                                    <div className="p-5 space-y-4">
                                        {/* Help Text */}
                                        {config.helpText && (
                                            <div className="flex items-start gap-2 p-3 bg-blue-50 rounded-lg text-sm text-blue-800">
                                                <Info size={16} className="mt-0.5 shrink-0" />
                                                <span>{config.helpText}</span>
                                            </div>
                                        )}

                                        {/* Prompt Textarea */}
                                        <div>
                                            <label className="block text-sm font-medium text-slate-700 mb-2">
                                                Prompt Template
                                            </label>
                                            <textarea
                                                className="w-full p-4 border border-slate-300 rounded-lg focus:ring-2 focus:ring-purple-500 focus:border-purple-500 transition-shadow font-mono text-sm resize-y min-h-[200px]"
                                                placeholder={config.placeholder}
                                                value={formData[config.id] || ''}
                                                onChange={e => setFormData(prev => ({
                                                    ...prev,
                                                    [config.id]: e.target.value
                                                }))}
                                                rows={8}
                                            />
                                        </div>
                                    </div>

                                    {/* Panel Actions */}
                                    <div className="px-5 py-4 bg-slate-50 border-t border-slate-100 flex justify-end gap-3">
                                        <button
                                            onClick={() => handleResetToDefault(config.id)}
                                            className="px-4 py-2 text-slate-600 hover:bg-slate-100 rounded-lg transition-colors text-sm"
                                        >
                                            Reset to Default
                                        </button>
                                        <button
                                            onClick={() => handleSave(config.id)}
                                            disabled={saving === config.id}
                                            className="px-4 py-2 bg-purple-600 text-white rounded-lg hover:bg-purple-700 disabled:opacity-50 flex items-center gap-2 transition-colors"
                                        >
                                            {saving === config.id ? (
                                                <Loader2 className="animate-spin" size={16} />
                                            ) : (
                                                <Save size={16} />
                                            )}
                                            Save Prompt
                                        </button>
                                    </div>
                                </div>
                            )}
                        </div>
                    );
                })}
            </div>

            {/* Footer Note */}
            <div className="mt-8 p-4 bg-amber-50 border border-amber-200 rounded-lg">
                <div className="flex items-start gap-3">
                    <AlertCircle className="text-amber-600 shrink-0 mt-0.5" size={20} />
                    <div className="text-sm text-amber-800">
                        <p className="font-medium mb-1">About AI Prompts</p>
                        <p>
                            These prompts serve as templates for AI-powered features. Use placeholders like
                            <code className="mx-1 px-1 py-0.5 bg-amber-100 rounded-sm">{'{{variable_name}}'}</code>
                            which will be replaced with actual data when the prompt is used.
                        </p>
                    </div>
                </div>
            </div>
        </div>
    );
}

import { useEffect, useState } from 'react';
import { Logger } from '../../utils/logger';
import { useAuth } from '../../context/AuthContext';
import { useAccount } from '../../context/AccountContext';
import { useNavigate } from 'react-router-dom';
import { LogIn, X, Trash2 } from 'lucide-react';
import { cn } from '../../utils/cn';

interface Account {
    id: string;
    name: string;
    domain: string | null;
    createdAt: string;
    _count: { users: number };
    features: AccountFeature[];
    users?: { userId: string, role: string }[]; // We might need to fetch users separately or include them if needed for impersonation
}

interface AccountFeature {
    id: string;
    featureKey: string;
    isEnabled: boolean;
}

const KNOWN_FEATURES = ['META_ADS', 'GOOGLE_ADS', 'ADVANCED_REPORTS', 'AI_WRITER', 'GOLD_PRICE_CALCULATOR', 'AD_TRACKING'];

export function AdminAccountsPage() {
    const { token, login } = useAuth();
    const { currentAccount, refreshAccounts } = useAccount();
    const navigate = useNavigate();
    const [accounts, setAccounts] = useState<Account[]>([]);
    const [loading, setLoading] = useState(true);
    const [deleteTarget, setDeleteTarget] = useState<Account | null>(null);
    const [confirmName, setConfirmName] = useState('');
    const [deleting, setDeleting] = useState(false);

    const fetchAccounts = () => {
        fetch('/api/admin/accounts', {
            headers: { Authorization: `Bearer ${token}` }
        })
            .then(res => {
                if (!res.ok) {
                    throw new Error(`Failed to fetch accounts: ${res.status}`);
                }
                return res.json();
            })
            .then(data => {
                setAccounts(data);
                setLoading(false);
            })
            .catch(err => {
                Logger.error('AdminAccountsPage fetch error:', { error: err });
                setLoading(false);
            });
    };

    useEffect(() => {
        fetchAccounts();
    }, [token]);

    const handleImpersonate = async (accountId: string) => {
        // First we need to find the OWNER of the account to impersonate
        // The /accounts endpoint includes `_count`, but maybe we should include `users` to find the owner?
        // Let's just fetch users for this account quickly
        try {
            const usersRes = await fetch(`/api/accounts/${accountId}/users`, { // This endpoint allows finding users
                headers: { Authorization: `Bearer ${token}` }
            });

            if (!usersRes.ok) {
                alert(`Failed to fetch users: ${usersRes.status}`);
                return;
            }

            const users = await usersRes.json();

            // Just pick the first element (likely owner or first staff) for demo
            // In a real app we'd let admin pick WHICH user to impersonate
            if (!users || users.length === 0) {
                alert('No users found in this account');
                return;
            }

            const targetUser = users[0].user; // Assuming structure from account.ts: include: { user: ... }

            if (!confirm(`Impersonate ${targetUser.fullName || targetUser.email}?`)) return;

            const res = await fetch('/api/admin/impersonate', {
                method: 'POST',
                headers: {
                    'Content-Type': 'application/json',
                    Authorization: `Bearer ${token}`
                },
                body: JSON.stringify({ targetUserId: targetUser.id })
            });

            if (!res.ok) {
                const errorData = await res.json().catch(() => ({ error: 'Unknown error' }));
                alert('Impersonation failed: ' + (errorData.error || res.status));
                return;
            }

            const data = await res.json();
            if (data.token) {
                // EDGE CASE FIX: Pass refresh token for silent refresh support
                login(data.token, data.user, data.refreshToken);
                navigate('/dashboard');
            } else {
                alert('Impersonation failed: ' + data.error);
            }
        } catch (e) {
            Logger.error('An error occurred', { error: e });
            alert('Failed to start impersonation');
        }
    };

    const toggleFeature = async (accountId: string, featureKey: string, currentValue: boolean) => {
        try {
            const res = await fetch(`/api/admin/accounts/${accountId}/toggle-feature`, {
                method: 'POST',
                headers: {
                    'Content-Type': 'application/json',
                    Authorization: `Bearer ${token}`
                },
                body: JSON.stringify({ featureKey, isEnabled: !currentValue })
            });

            if (res.ok) {
                // Update local state
                setAccounts(prev => prev.map(acc => {
                    if (acc.id !== accountId) return acc;

                    const existingFeatureIndex = acc.features.findIndex(f => f.featureKey === featureKey);
                    const newFeatures = [...acc.features];

                    if (existingFeatureIndex >= 0) {
                        newFeatures[existingFeatureIndex].isEnabled = !currentValue;
                    } else {
                        newFeatures.push({ id: 'temp', featureKey, isEnabled: !currentValue });
                    }
                    return { ...acc, features: newFeatures };
                }));
                if (currentAccount && currentAccount.id === accountId) {
                    refreshAccounts();
                }
            }
        } catch (e) {
            Logger.error('An error occurred', { error: e });
        }
    };

    const handleDeleteAccount = async () => {
        if (!deleteTarget || confirmName !== deleteTarget.name) return;

        setDeleting(true);
        try {
            const res = await fetch(`/api/admin/accounts/${deleteTarget.id}`, {
                method: 'DELETE',
                headers: {
                    'Content-Type': 'application/json',
                    Authorization: `Bearer ${token}`
                },
                body: JSON.stringify({ confirmAccountName: confirmName })
            });

            if (res.ok) {
                setAccounts(prev => prev.filter(acc => acc.id !== deleteTarget.id));
                setDeleteTarget(null);
                setConfirmName('');
            } else {
                const data = await res.json();
                alert('Delete failed: ' + data.error);
            }
        } catch (e) {
            Logger.error('An error occurred', { error: e });
            alert('Failed to delete account');
        } finally {
            setDeleting(false);
        }
    };

    if (loading) return <div>Loading accounts...</div>;

    return (
        <div className="space-y-6">
            <h1 className="text-2xl font-bold text-slate-800">Manage Accounts</h1>

            <div className="bg-white rounded-xl shadow-xs border border-slate-200 overflow-hidden">
                <table className="w-full text-left text-sm">
                    <thead className="bg-slate-50 border-b border-slate-100 uppercase text-xs text-slate-500 font-medium">
                        <tr>
                            <th className="p-4">Account Name</th>
                            <th className="p-4">Domain</th>
                            <th className="p-4">Users</th>
                            <th className="p-4">Features</th>
                            <th className="p-4 text-right">Actions</th>
                        </tr>
                    </thead>
                    <tbody className="divide-y divide-slate-100">
                        {accounts.map(account => (
                            <tr key={account.id} className="hover:bg-slate-50/50">
                                <td className="p-4 font-medium text-slate-900">{account.name}</td>
                                <td className="p-4 text-slate-500">{account.domain || '-'}</td>
                                <td className="p-4 text-slate-500">{account._count.users}</td>
                                <td className="p-4">
                                    <div className="flex gap-1 flex-wrap">
                                        {KNOWN_FEATURES.map(key => {
                                            const isEnabled = account.features.find(f => f.featureKey === key)?.isEnabled;
                                            return (
                                                <button
                                                    key={key}
                                                    onClick={() => toggleFeature(account.id, key, !!isEnabled)}
                                                    className={cn(
                                                        "px-2 py-1 rounded-sm text-xs transition-colors border",
                                                        isEnabled
                                                            ? "bg-green-50 text-green-700 border-green-200 hover:bg-green-100"
                                                            : "bg-slate-50 text-slate-400 border-slate-200 hover:bg-slate-100 hover:text-slate-600"
                                                    )}
                                                    title={`Toggle ${key}`}
                                                >
                                                    {key.split('_')[0]}
                                                </button>
                                            );
                                        })}
                                    </div>
                                </td>
                                <td className="p-4 text-right">
                                    <div className="flex items-center justify-end gap-2">
                                        <button
                                            onClick={() => handleImpersonate(account.id)}
                                            className="inline-flex items-center gap-2 px-3 py-1.5 text-xs font-medium text-blue-700 bg-blue-50 rounded-lg hover:bg-blue-100 transition-colors"
                                        >
                                            <LogIn size={14} />
                                            Impersonate
                                        </button>
                                        <button
                                            onClick={() => { setDeleteTarget(account); setConfirmName(''); }}
                                            className="inline-flex items-center gap-2 px-3 py-1.5 text-xs font-medium text-red-700 bg-red-50 rounded-lg hover:bg-red-100 transition-colors"
                                        >
                                            <Trash2 size={14} />
                                            Delete
                                        </button>
                                    </div>
                                </td>
                            </tr>
                        ))}
                    </tbody>
                </table>
            </div>

            {/* Delete Confirmation Modal */}
            {deleteTarget && (
                <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/50 backdrop-blur-xs">
                    <div className="bg-white/95 backdrop-blur-md rounded-2xl shadow-2xl border border-slate-200 p-6 w-full max-w-md mx-4">
                        <h2 className="text-lg font-bold text-slate-900 mb-2">Delete Account</h2>
                        <p className="text-sm text-slate-600 mb-4">
                            This action is <span className="font-semibold text-red-600">irreversible</span>. All data associated with this account will be permanently deleted.
                        </p>
                        <p className="text-sm text-slate-700 mb-4">
                            To confirm, type the account name: <span className="font-mono font-bold text-slate-900">{deleteTarget.name}</span>
                        </p>
                        <input
                            type="text"
                            value={confirmName}
                            onChange={(e) => setConfirmName(e.target.value)}
                            placeholder="Type account name to confirm"
                            className="w-full px-4 py-2 border border-slate-300 rounded-lg text-sm focus:outline-hidden focus:ring-2 focus:ring-red-500 focus:border-transparent mb-4"
                            autoFocus
                        />
                        <div className="flex justify-end gap-3">
                            <button
                                onClick={() => { setDeleteTarget(null); setConfirmName(''); }}
                                className="px-4 py-2 text-sm font-medium text-slate-700 bg-slate-100 rounded-lg hover:bg-slate-200 transition-colors"
                            >
                                Cancel
                            </button>
                            <button
                                onClick={handleDeleteAccount}
                                disabled={confirmName !== deleteTarget.name || deleting}
                                className={cn(
                                    "px-4 py-2 text-sm font-medium rounded-lg transition-colors",
                                    confirmName === deleteTarget.name && !deleting
                                        ? "bg-red-600 text-white hover:bg-red-700"
                                        : "bg-slate-200 text-slate-400 cursor-not-allowed"
                                )}
                            >
                                {deleting ? 'Deleting...' : 'Confirm Delete'}
                            </button>
                        </div>
                    </div>
                </div>
            )}
        </div>
    );
}

import { useState } from 'react';
import { Logger } from '../../utils/logger';
import { useAuth } from '../../context/AuthContext';
import { Send, AlertTriangle, CheckCircle, Info, MessageSquare, Bell } from 'lucide-react';

export function AdminBroadcastPage() {
    const { token } = useAuth();
    const [formData, setFormData] = useState({
        title: '',
        message: '',
        type: 'INFO',
        link: '',
        sendPush: false
    });
    const [sending, setSending] = useState(false);
    const [successMsg, setSuccessMsg] = useState('');

    const handleSubmit = async (e: React.FormEvent) => {
        e.preventDefault();
        setSending(true);
        setSuccessMsg('');

        try {
            const res = await fetch('/api/admin/broadcast', {
                method: 'POST',
                headers: {
                    'Content-Type': 'application/json',
                    Authorization: `Bearer ${token}`
                },
                body: JSON.stringify(formData)
            });

            if (res.ok) {
                const data = await res.json();
                let msg = `Successfully sent to ${data.count} accounts.`;
                if (formData.sendPush) {
                    msg += ` Push: ${data.pushSent} sent, ${data.pushFailed} failed.`;
                }
                setSuccessMsg(msg);
                setFormData({ title: '', message: '', type: 'INFO', link: '', sendPush: false });
            } else {
                alert('Failed to send broadcast');
            }
        } catch (err) {
            Logger.error('An error occurred', { error: err });
            alert('Error sending broadcast');
        } finally {
            setSending(false);
        }
    };

    return (
        <div className="max-w-2xl mx-auto space-y-6">
            <h1 className="text-2xl font-bold text-slate-800">Global Broadcast</h1>
            <p className="text-slate-500">Send a notification to ALL active accounts system-wide.</p>

            {successMsg && (
                <div className="bg-green-50 border border-green-200 text-green-700 p-4 rounded-lg flex items-center gap-2">
                    <CheckCircle size={20} /> {successMsg}
                </div>
            )}

            <form onSubmit={handleSubmit} className="bg-white rounded-xl shadow-xs border border-slate-200 p-6 space-y-4">
                <div>
                    <label className="block text-sm font-medium text-slate-700 mb-1">Title</label>
                    <input
                        type="text"
                        required
                        className="w-full px-3 py-2 border border-slate-200 rounded-lg focus:outline-hidden focus:ring-2 focus:ring-blue-500"
                        placeholder="e.g. Scheduled Maintenance"
                        value={formData.title}
                        onChange={e => setFormData({ ...formData, title: e.target.value })}
                    />
                </div>

                <div>
                    <label className="block text-sm font-medium text-slate-700 mb-1">Message</label>
                    <textarea
                        required
                        rows={4}
                        className="w-full px-3 py-2 border border-slate-200 rounded-lg focus:outline-hidden focus:ring-2 focus:ring-blue-500"
                        placeholder="Details about the update..."
                        value={formData.message}
                        onChange={e => setFormData({ ...formData, message: e.target.value })}
                    />
                </div>

                <div className="grid grid-cols-2 gap-4">
                    <div>
                        <label className="block text-sm font-medium text-slate-700 mb-1">Type</label>
                        <select
                            className="w-full px-3 py-2 border border-slate-200 rounded-lg focus:outline-hidden focus:ring-2 focus:ring-blue-500"
                            value={formData.type}
                            onChange={e => setFormData({ ...formData, type: e.target.value })}
                        >
                            <option value="INFO">Info (Blue)</option>
                            <option value="SUCCESS">Success (Green)</option>
                            <option value="WARNING">Warning (Yellow)</option>
                            <option value="ERROR">Error (Red)</option>
                        </select>
                    </div>
                    <div>
                        <label className="block text-sm font-medium text-slate-700 mb-1">Link (Optional)</label>
                        <input
                            type="text"
                            className="w-full px-3 py-2 border border-slate-200 rounded-lg focus:outline-hidden focus:ring-2 focus:ring-blue-500"
                            placeholder="/settings or https://..."
                            value={formData.link}
                            onChange={e => setFormData({ ...formData, link: e.target.value })}
                        />
                    </div>
                </div>

                {/* Push Notification Toggle */}
                <div className="flex items-center gap-3 p-3 bg-indigo-50 rounded-lg border border-indigo-100">
                    <input
                        type="checkbox"
                        id="sendPush"
                        checked={formData.sendPush}
                        onChange={e => setFormData({ ...formData, sendPush: e.target.checked })}
                        className="w-5 h-5 rounded border-indigo-300 text-indigo-600 focus:ring-indigo-500"
                    />
                    <label htmlFor="sendPush" className="flex items-center gap-2 cursor-pointer">
                        <Bell size={18} className="text-indigo-600" />
                        <div>
                            <p className="font-medium text-slate-800">Send Push Notification</p>
                            <p className="text-sm text-slate-500">Also send as a push notification to all subscribed devices</p>
                        </div>
                    </label>
                </div>

                <div className="pt-4">
                    <button
                        type="submit"
                        disabled={sending}
                        className="w-full bg-blue-600 text-white font-medium py-2.5 rounded-lg hover:bg-blue-700 transition-colors flex items-center justify-center gap-2 disabled:opacity-50"
                    >
                        {sending ? 'Sending...' : <><Send size={18} /> Send Broadcast</>}
                    </button>
                </div>
            </form>
        </div>
    );
}

import { useEffect, useState, useCallback } from 'react';
import { Logger } from '../../utils/logger';
import { useAuth } from '../../context/AuthContext';
import {
    Key, Save, Trash2, Loader2, Zap, Copy, Link, ExternalLink,
    Shield, Eye, EyeOff, Info, CheckCircle, AlertCircle
} from 'lucide-react';
import { PLATFORMS, type PlatformId, type FieldConfig } from './credentialsConfig';

// ─── Types ──────────────────────────────────────────────────────────

interface PlatformCredential {
    id: string;
    platform: string;
    credentials: Record<string, string>;
    notes?: string;
    updatedAt: string;
}

// ─── useCredentials Hook ────────────────────────────────────────────

/** Encapsulates all state + data-fetching for the credentials page. */
function useCredentials() {
    const { token } = useAuth();

    const [credentials, setCredentials] = useState<PlatformCredential[]>([]);
    const [loading, setLoading] = useState(true);
    const [saving, setSaving] = useState<string | null>(null);
    const [testing, setTesting] = useState<string | null>(null);
    const [formData, setFormData] = useState<Record<string, Record<string, string>>>({});
    const [notes, setNotes] = useState<Record<string, string>>({});
    const [message, setMessage] = useState<{ type: 'success' | 'error'; text: string } | null>(null);
    const [generating, setGenerating] = useState(false);
    const [revealedFields, setRevealedFields] = useState<Record<string, boolean>>({});

    /**
     * Server-sourced callback/webhook URLs keyed by callbackPath.
     * Why: window.location.origin diverges from API_URL behind a reverse proxy.
     */
    const [serverUrls, setServerUrls] = useState<Record<string, string>>({});

    const authHeaders = { Authorization: `Bearer ${token}` };

    const fetchCredentials = useCallback(async () => {
        try {
            const res = await fetch('/api/admin/platform-credentials', { headers: authHeaders });
            const data = await res.json();
            setCredentials(data);

            const initialForm: Record<string, Record<string, string>> = {};
            const initialNotes: Record<string, string> = {};

            PLATFORMS.forEach(platform => {
                initialForm[platform.id] = {};
                platform.fields.forEach(field => {
                    initialForm[platform.id][field.key] = '';
                });
                initialNotes[platform.id] = '';
            });

            data.forEach((cred: PlatformCredential) => {
                if (cred.credentials) {
                    Object.entries(cred.credentials).forEach(([key, value]) => {
                        if (initialForm[cred.platform]) {
                            initialForm[cred.platform][key] = value;
                        }
                    });
                }
                if (cred.notes) {
                    initialNotes[cred.platform] = cred.notes;
                }
            });

            setFormData(initialForm);
            setNotes(initialNotes);
        } catch (err) {
            Logger.error('An error occurred', { error: err });
        } finally {
            setLoading(false);
        }
    }, [token]);

    const fetchCallbackUrls = useCallback(async () => {
        try {
            const res = await fetch('/api/oauth/callback-urls', { headers: authHeaders });
            if (!res.ok) return;
            const data = await res.json();
            const map: Record<string, string> = {};
            if (data.google) map['/api/oauth/google/callback'] = data.google;
            if (data.metaAds) map['/api/oauth/meta/ads/callback'] = data.metaAds;
            if (data.metaMessaging) map['/api/oauth/meta/messaging/callback'] = data.metaMessaging;
            if (data.tiktok) map['/api/oauth/tiktok/callback'] = data.tiktok;
            if (data.metaWebhook) map['/api/meta-webhook'] = data.metaWebhook;
            setServerUrls(map);
        } catch {
            /* Fallback to window.location.origin via default empty map */
        }
    }, [token]);

    const handleSave = useCallback(async (platformId: string) => {
        setSaving(platformId);
        setMessage(null);
        try {
            const creds: Record<string, string> = {};
            Object.entries(formData[platformId] || {}).forEach(([key, value]) => {
                if (value.trim()) creds[key] = value.trim();
            });

            if (Object.keys(creds).length === 0) {
                setMessage({ type: 'error', text: 'Please fill in at least one credential field.' });
                return;
            }

            const res = await fetch(`/api/admin/platform-credentials/${platformId}`, {
                method: 'PUT',
                headers: { 'Content-Type': 'application/json', ...authHeaders },
                body: JSON.stringify({ credentials: creds, notes: notes[platformId] })
            });

            if (res.ok) {
                setMessage({ type: 'success', text: `${PLATFORMS.find(p => p.id === platformId)?.name} credentials saved.` });
                fetchCredentials();
            } else {
                const err = await res.json();
                setMessage({ type: 'error', text: err.error || 'Failed to save.' });
            }
        } catch {
            setMessage({ type: 'error', text: 'Network error.' });
        } finally {
            setSaving(null);
        }
    }, [formData, notes, token, fetchCredentials]);

    const handleDelete = useCallback(async (platformId: string) => {
        if (!confirm(`Delete all ${PLATFORMS.find(p => p.id === platformId)?.name} credentials? This cannot be undone.`)) return;
        try {
            const res = await fetch(`/api/admin/platform-credentials/${platformId}`, {
                method: 'DELETE',
                headers: authHeaders
            });
            if (res.ok) {
                setMessage({ type: 'success', text: 'Credentials deleted.' });
                fetchCredentials();
            }
        } catch {
            setMessage({ type: 'error', text: 'Failed to delete.' });
        }
    }, [token, fetchCredentials]);

    /** Tests SMTP connection with the saved credentials. */
    const handleTestSmtp = useCallback(async () => {
        setTesting('PLATFORM_SMTP');
        setMessage(null);
        try {
            const smtpData = formData['PLATFORM_SMTP'] || {};
            if (!smtpData.host || !smtpData.port || !smtpData.username || !smtpData.password) {
                setMessage({ type: 'error', text: 'Host, port, username, and password are required to test.' });
                return;
            }

            const res = await fetch('/api/admin/platform-smtp/test', {
                method: 'POST',
                headers: { 'Content-Type': 'application/json', ...authHeaders },
                body: JSON.stringify({
                    host: smtpData.host,
                    port: parseInt(smtpData.port),
                    username: smtpData.username,
                    password: smtpData.password,
                    secure: smtpData.secure === 'true'
                })
            });

            const result = await res.json();
            if (res.ok && result.success) {
                setMessage({ type: 'success', text: 'SMTP connection successful!' });
            } else {
                setMessage({ type: 'error', text: result.error || 'SMTP connection failed.' });
            }
        } catch {
            setMessage({ type: 'error', text: 'Network error during SMTP test.' });
        } finally {
            setTesting(null);
        }
    }, [formData, token]);

    /** Generates VAPID keys via the backend. */
    const handleGenerateVapidKeys = useCallback(async () => {
        setGenerating(true);
        setMessage(null);
        try {
            const res = await fetch('/api/admin/generate-vapid-keys', {
                method: 'POST',
                headers: authHeaders
            });

            if (!res.ok) {
                const text = await res.text();
                let errorMsg = `Server error (${res.status})`;
                try {
                    const err = JSON.parse(text);
                    errorMsg = err.error || err.message || errorMsg;
                } catch {
                    errorMsg = `${res.statusText || 'Server error'} (${res.status})`;
                }
                setMessage({ type: 'error', text: errorMsg });
                return;
            }

            const result = await res.json();
            if (result.alreadyExists) {
                setFormData(prev => ({
                    ...prev,
                    'WEB_PUSH_VAPID': { publicKey: result.publicKey, privateKey: '••••••••' }
                }));
                setMessage({ type: 'success', text: result.message || 'VAPID keys already configured.' });
            } else {
                setFormData(prev => ({
                    ...prev,
                    'WEB_PUSH_VAPID': { publicKey: result.publicKey, privateKey: '(saved securely)' }
                }));
                setMessage({ type: 'success', text: result.message || 'VAPID keys generated and saved!' });
            }
            fetchCredentials();
        } catch (err: unknown) {
            const errorMessage = err instanceof Error ? err.message : 'Network error generating keys';
            setMessage({ type: 'error', text: `Failed to generate keys: ${errorMessage}` });
        } finally {
            setGenerating(false);
        }
    }, [token, fetchCredentials]);

    const toggleReveal = useCallback((fieldKey: string) => {
        setRevealedFields(prev => ({ ...prev, [fieldKey]: !prev[fieldKey] }));
    }, []);

    const isConfigured = useCallback((platformId: string) =>
        credentials.some(c => c.platform === platformId),
        [credentials]);

    const getLastUpdated = useCallback((platformId: string) => {
        const cred = credentials.find(c => c.platform === platformId);
        if (!cred?.updatedAt) return null;
        return new Intl.DateTimeFormat('en-US', { dateStyle: 'medium', timeStyle: 'short' })
            .format(new Date(cred.updatedAt));
    }, [credentials]);

    useEffect(() => { fetchCredentials(); }, [fetchCredentials]);
    useEffect(() => { if (token) fetchCallbackUrls(); }, [fetchCallbackUrls]);

    /** Auto-dismiss success messages after 4 seconds */
    useEffect(() => {
        if (message?.type === 'success') {
            const timer = setTimeout(() => setMessage(null), 4000);
            return () => clearTimeout(timer);
        }
    }, [message]);

    return {
        loading, saving, testing, generating, message, setMessage,
        formData, setFormData, notes, setNotes,
        revealedFields, serverUrls,
        handleSave, handleDelete, handleTestSmtp, handleGenerateVapidKeys,
        toggleReveal, isConfigured, getLastUpdated,
    };
}

// ─── CredentialField ────────────────────────────────────────────────

interface CredentialFieldProps {
    field: FieldConfig;
    platformId: string;
    value: string;
    onChange: (value: string) => void;
    isRevealed: boolean;
    onToggleReveal: () => void;
    configured: boolean;
    /** Whether to style as a required field (red asterisk, solid border) */
    isRequired?: boolean;
}

/**
 * Single credential input field with optional sensitivity toggle.
 * Why extracted: the required-fields and optional-fields sections were
 * ~110 lines of copy-pasted JSX that only differed by filter predicate
 * and minor border styling.
 */
function CredentialField({
    field, value, onChange, isRevealed, onToggleReveal, configured, isRequired = false
}: CredentialFieldProps) {
    const borderClass = isRequired
        ? 'border-slate-300'
        : 'border-slate-200 bg-slate-50 focus:bg-white';

    return (
        <div>
            <label className={`flex items-center gap-1.5 text-sm font-medium mb-1.5 ${isRequired ? 'text-slate-700' : 'text-slate-600'}`}>
                {field.label}
                {isRequired && <span className="text-red-400 text-xs">*</span>}
            </label>
            <div className="relative">
                <input
                    type={field.sensitive && !isRevealed ? 'password' : 'text'}
                    className={`w-full px-3 py-2.5 border rounded-lg text-sm focus:ring-2 focus:ring-blue-500/20 focus:border-blue-500 transition-shadow placeholder:text-slate-400 ${borderClass}`}
                    placeholder={configured ? '••••••••' : field.placeholder}
                    value={value}
                    onChange={e => onChange(e.target.value)}
                />
                {field.sensitive && (
                    <button
                        type="button"
                        onClick={onToggleReveal}
                        className="absolute right-2.5 top-1/2 -translate-y-1/2 p-1 text-slate-400 hover:text-slate-600 transition-colors"
                        title={isRevealed ? 'Hide' : 'Show'}
                    >
                        {isRevealed ? <EyeOff size={16} /> : <Eye size={16} />}
                    </button>
                )}
            </div>
            {field.helpText && (
                <p className="mt-1 text-xs text-slate-400 flex items-start gap-1">
                    <Info size={11} className="mt-0.5 shrink-0" />
                    {field.helpText}
                </p>
            )}
        </div>
    );
}

// ─── CopyableUrl ────────────────────────────────────────────────────

/** Copyable URL row — displays a URL with a one-click copy button. */
function CopyableUrl({ label, url, onCopied }: { label: string; url: string; onCopied: () => void }) {
    return (
        <div className="flex items-center gap-3 group">
            <span className="text-xs font-medium text-slate-500 w-32 shrink-0">{label}</span>
            <div className="flex-1 flex items-center gap-2 bg-slate-50 border border-slate-200 rounded-lg px-3 py-2 font-mono text-xs text-slate-700 overflow-x-auto">
                {url}
            </div>
            <button
                onClick={() => { navigator.clipboard.writeText(url); onCopied(); }}
                className="p-2 rounded-lg text-slate-400 hover:text-blue-600 hover:bg-blue-50 transition-colors"
                title="Copy to clipboard"
            >
                <Copy size={14} />
            </button>
        </div>
    );
}

// ─── FieldSection ───────────────────────────────────────────────────

interface FieldSectionProps {
    fields: FieldConfig[];
    platformId: string;
    formData: Record<string, Record<string, string>>;
    setFormData: React.Dispatch<React.SetStateAction<Record<string, Record<string, string>>>>;
    revealedFields: Record<string, boolean>;
    toggleReveal: (fieldKey: string) => void;
    configured: boolean;
    isRequired: boolean;
}

/**
 * Renders a group of credential fields (required or optional).
 * Why extracted: eliminates the duplicated filter-then-map JSX block.
 */
function FieldSection({
    fields, platformId, formData, setFormData, revealedFields, toggleReveal, configured, isRequired
}: FieldSectionProps) {
    const filtered = fields.filter(f => isRequired ? f.required : !f.required);
    if (filtered.length === 0) return null;

    return (
        <div>
            <h3 className={`text-xs font-semibold uppercase tracking-wide mb-4 flex items-center gap-2 ${isRequired ? 'text-slate-500' : 'text-slate-400'}`}>
                {isRequired && <Key size={12} />}
                {isRequired ? 'Required Credentials' : 'Optional'}
            </h3>
            <div className="space-y-4">
                {filtered.map(field => {
                    const fieldId = `${platformId}.${field.key}`;
                    return (
                        <CredentialField
                            key={field.key}
                            field={field}
                            platformId={platformId}
                            value={formData[platformId]?.[field.key] || ''}
                            onChange={val => setFormData(prev => ({
                                ...prev,
                                [platformId]: { ...prev[platformId], [field.key]: val }
                            }))}
                            isRevealed={!!revealedFields[fieldId]}
                            onToggleReveal={() => toggleReveal(fieldId)}
                            configured={configured}
                            isRequired={isRequired}
                        />
                    );
                })}
            </div>
        </div>
    );
}

// ─── Page Component ─────────────────────────────────────────────────

/**
 * Super Admin page for managing platform API credentials.
 * Credentials are stored encrypted in the database.
 */
export function AdminCredentialsPage() {
    const {
        loading, saving, testing, generating, message, setMessage,
        formData, setFormData, notes, setNotes,
        revealedFields, serverUrls,
        handleSave, handleDelete, handleTestSmtp, handleGenerateVapidKeys,
        toggleReveal, isConfigured, getLastUpdated,
    } = useCredentials();

    const [activeTab, setActiveTab] = useState<PlatformId>('PLATFORM_SMTP');

    if (loading) {
        return (
            <div className="flex items-center justify-center py-20">
                <Loader2 className="animate-spin text-slate-400" size={28} />
            </div>
        );
    }

    const currentPlatform = PLATFORMS.find(p => p.id === activeTab)!;
    const configured = isConfigured(currentPlatform.id);
    const lastUpdated = getLastUpdated(currentPlatform.id);
    const configuredCount = PLATFORMS.filter(p => isConfigured(p.id)).length;

    return (
        <div className="max-w-4xl">
            {/* ── Page Header ── */}
            <div className="mb-8">
                <div className="flex items-center gap-3 mb-2">
                    <div className="p-2 bg-slate-100 rounded-lg">
                        <Shield className="text-slate-600" size={22} />
                    </div>
                    <div>
                        <h1 className="text-2xl font-bold text-slate-900">Platform Credentials</h1>
                        <p className="text-sm text-slate-500 mt-0.5">
                            {configuredCount}/{PLATFORMS.length} platforms configured
                        </p>
                    </div>
                </div>
            </div>

            {/* ── Toast Message ── */}
            {message && (
                <div
                    className={`mb-6 px-4 py-3 rounded-lg flex items-center gap-3 text-sm font-medium animate-in fade-in slide-in-from-top-2 duration-200
                        ${message.type === 'success'
                            ? 'bg-emerald-50 text-emerald-800 border border-emerald-200'
                            : 'bg-red-50 text-red-800 border border-red-200'
                        }`}
                >
                    {message.type === 'success' ? <CheckCircle size={16} /> : <AlertCircle size={16} />}
                    {message.text}
                </div>
            )}

            {/* ── Platform Sidebar + Content Layout ── */}
            <div className="flex gap-6">
                {/* Left Sidebar — Platform List */}
                <div className="w-56 shrink-0 space-y-1">
                    {PLATFORMS.map((platform) => {
                        const Icon = platform.icon;
                        const isActive = activeTab === platform.id;
                        const done = isConfigured(platform.id);

                        return (
                            <button
                                key={platform.id}
                                onClick={() => { setActiveTab(platform.id as PlatformId); setMessage(null); }}
                                className={`
                                    w-full flex items-center gap-3 px-3 py-2.5 rounded-lg text-left text-sm font-medium transition-all
                                    ${isActive
                                        ? 'bg-blue-50 text-blue-700 shadow-sm ring-1 ring-blue-200'
                                        : 'text-slate-600 hover:bg-slate-50 hover:text-slate-800'
                                    }
                                `}
                            >
                                <div className={`p-1.5 rounded-md ${isActive ? platform.iconColor : 'bg-slate-200'}`}>
                                    <Icon size={14} className="text-white" />
                                </div>
                                <span className="flex-1 truncate">{platform.name}</span>
                                {done && <CheckCircle size={14} className="text-emerald-500 shrink-0" />}
                            </button>
                        );
                    })}
                </div>

                {/* Right Content — Active Platform */}
                <div className="flex-1 min-w-0">
                    <div className="bg-white rounded-xl border border-slate-200 shadow-sm overflow-hidden">

                        {/* ── Platform Header ── */}
                        <div className="px-6 py-5 border-b border-slate-100">
                            <div className="flex items-start justify-between">
                                <div className="flex items-center gap-3">
                                    <div className={`p-2.5 rounded-xl ${currentPlatform.iconColor}`}>
                                        <currentPlatform.icon size={20} className="text-white" />
                                    </div>
                                    <div>
                                        <div className="flex items-center gap-2">
                                            <h2 className="text-lg font-semibold text-slate-900">{currentPlatform.name}</h2>
                                            {configured ? (
                                                <span className="inline-flex items-center gap-1 bg-emerald-50 text-emerald-700 text-xs font-medium px-2 py-0.5 rounded-full border border-emerald-200">
                                                    <CheckCircle size={10} /> Active
                                                </span>
                                            ) : (
                                                <span className="inline-flex items-center gap-1 bg-slate-100 text-slate-500 text-xs font-medium px-2 py-0.5 rounded-full">
                                                    Not configured
                                                </span>
                                            )}
                                        </div>
                                        <p className="text-sm text-slate-500 mt-0.5">{currentPlatform.description}</p>
                                        {lastUpdated && (
                                            <p className="text-xs text-slate-400 mt-1">Last updated {lastUpdated}</p>
                                        )}
                                    </div>
                                </div>
                                {currentPlatform.docsUrl && (
                                    <a
                                        href={currentPlatform.docsUrl}
                                        target="_blank"
                                        rel="noopener noreferrer"
                                        className="flex items-center gap-1.5 text-xs font-medium text-blue-600 hover:text-blue-700 bg-blue-50 hover:bg-blue-100 px-3 py-1.5 rounded-lg transition-colors shrink-0"
                                    >
                                        <ExternalLink size={12} />
                                        {currentPlatform.docsLabel || 'Developer Console'}
                                    </a>
                                )}
                            </div>
                        </div>

                        {/* ── URL Configuration Section ── */}
                        {(currentPlatform.callbackPath || currentPlatform.webhookPath) && (
                            <div className="px-6 py-4 bg-slate-50 border-b border-slate-100">
                                <div className="flex items-center gap-2 mb-3">
                                    <Link size={14} className="text-slate-500" />
                                    <span className="text-xs font-semibold text-slate-600 uppercase tracking-wide">Required URLs</span>
                                </div>
                                <p className="text-xs text-slate-500 mb-3">
                                    Copy these URLs into your{' '}
                                    <span className="font-medium text-slate-700">
                                        {currentPlatform.docsLabel || 'developer console'}
                                    </span>.
                                </p>
                                <div className="space-y-2">
                                    {currentPlatform.callbackPath && (
                                        <CopyableUrl
                                            label={currentPlatform.id === 'META_MESSAGING' ? 'OAuth Redirect' : 'Callback URL'}
                                            url={serverUrls[currentPlatform.callbackPath] || `${window.location.origin}${currentPlatform.callbackPath}`}
                                            onCopied={() => setMessage({ type: 'success', text: 'Copied to clipboard!' })}
                                        />
                                    )}
                                    {currentPlatform.webhookPath && (
                                        <CopyableUrl
                                            label="Webhook URL"
                                            url={serverUrls[currentPlatform.webhookPath] || `${window.location.origin}${currentPlatform.webhookPath}`}
                                            onCopied={() => setMessage({ type: 'success', text: 'Copied to clipboard!' })}
                                        />
                                    )}
                                </div>
                            </div>
                        )}

                        {/* ── Credential Fields ── */}
                        <div className="px-6 py-5 space-y-5">
                            <FieldSection
                                fields={currentPlatform.fields}
                                platformId={currentPlatform.id}
                                formData={formData}
                                setFormData={setFormData}
                                revealedFields={revealedFields}
                                toggleReveal={toggleReveal}
                                configured={configured}
                                isRequired={true}
                            />
                            <FieldSection
                                fields={currentPlatform.fields}
                                platformId={currentPlatform.id}
                                formData={formData}
                                setFormData={setFormData}
                                revealedFields={revealedFields}
                                toggleReveal={toggleReveal}
                                configured={configured}
                                isRequired={false}
                            />

                            {/* Notes */}
                            <div className="pt-2 border-t border-slate-100">
                                <label className="text-sm font-medium text-slate-500 mb-1.5 block">Notes</label>
                                <input
                                    type="text"
                                    className="w-full px-3 py-2.5 border border-slate-200 rounded-lg text-sm focus:ring-2 focus:ring-blue-500/20 focus:border-blue-500 transition-shadow placeholder:text-slate-400 bg-slate-50 focus:bg-white"
                                    placeholder="e.g., Production credentials from Google Cloud Console"
                                    value={notes[currentPlatform.id] || ''}
                                    onChange={e => setNotes(prev => ({ ...prev, [currentPlatform.id]: e.target.value }))}
                                />
                            </div>
                        </div>

                        {/* ── Actions Footer ── */}
                        <div className="px-6 py-4 bg-slate-50 border-t border-slate-100 flex items-center justify-between">
                            <div className="flex items-center gap-2">
                                {configured && (
                                    <button
                                        onClick={() => handleDelete(currentPlatform.id)}
                                        className="px-3 py-2 text-sm text-red-600 hover:bg-red-50 rounded-lg flex items-center gap-2 transition-colors"
                                    >
                                        <Trash2 size={14} />
                                        Remove Credentials
                                    </button>
                                )}
                            </div>
                            <div className="flex items-center gap-2">
                                {currentPlatform.testable && (
                                    <button
                                        onClick={() => handleTestSmtp()}
                                        disabled={testing === currentPlatform.id}
                                        className="px-4 py-2 text-sm text-amber-700 border border-amber-300 bg-amber-50 hover:bg-amber-100 rounded-lg flex items-center gap-2 transition-colors disabled:opacity-50"
                                    >
                                        {testing === currentPlatform.id ? <Loader2 className="animate-spin" size={14} /> : <Zap size={14} />}
                                        Test Connection
                                    </button>
                                )}
                                {currentPlatform.id === 'WEB_PUSH_VAPID' && (
                                    <button
                                        onClick={handleGenerateVapidKeys}
                                        disabled={generating}
                                        className="px-4 py-2 text-sm text-violet-700 border border-violet-300 bg-violet-50 hover:bg-violet-100 rounded-lg flex items-center gap-2 transition-colors disabled:opacity-50"
                                    >
                                        {generating ? <Loader2 className="animate-spin" size={14} /> : <Zap size={14} />}
                                        Generate Keys
                                    </button>
                                )}
                                <button
                                    onClick={() => handleSave(currentPlatform.id)}
                                    disabled={saving === currentPlatform.id}
                                    className="px-5 py-2 text-sm bg-blue-600 text-white rounded-lg hover:bg-blue-700 disabled:opacity-50 flex items-center gap-2 transition-colors font-medium shadow-sm"
                                >
                                    {saving === currentPlatform.id ? <Loader2 className="animate-spin" size={14} /> : <Save size={14} />}
                                    Save Credentials
                                </button>
                            </div>
                        </div>
                    </div>
                </div>
            </div>
        </div>
    );
}

import { useEffect, useState } from 'react';
import { Logger } from '../../utils/logger';
import { useAuth } from '../../context/AuthContext';
import { CheckCircle, XCircle, Clock, RotateCw } from 'lucide-react';
import { cn } from '../../utils/cn';
import { Pagination } from '../../components/ui/Pagination';

interface SyncLog {
    id: string;
    accountId: string;
    account: { name: string };
    entityType: string;
    status: string;
    itemsProcessed: number;
    errorMessage: string | null;
    startedAt: string;
    completedAt: string | null;
}

export function AdminLogsPage() {
    const { token } = useAuth();
    const [logs, setLogs] = useState<SyncLog[]>([]);
    const [loading, setLoading] = useState(true);
    const [page, setPage] = useState(1);
    const [limit, setLimit] = useState(20);
    const [totalPages, setTotalPages] = useState(1);

    const fetchLogs = (currentPage: number, currentLimit: number) => {
        setLoading(true);
        fetch(`/api/admin/logs?page=${currentPage}&limit=${currentLimit}`, {
            headers: { Authorization: `Bearer ${token}` }
        })
            .then(res => res.json())
            .then(data => {
                setLogs(data.logs);
                setTotalPages(data.totalPages);
                setPage(data.page);
                setLoading(false);
            })
            .catch(err => {
                Logger.error('An error occurred', { error: err });
                setLoading(false);
            });
    };

    useEffect(() => {
        fetchLogs(page, limit);
    }, [token, page, limit]); // Re-fetch when page changes

    return (
        <div className="space-y-6">
            <div className="flex justify-between items-center">
                <h1 className="text-2xl font-bold text-slate-800">System Logs</h1>
                <button
                    onClick={() => fetchLogs(page, limit)}
                    className="p-2 text-slate-500 hover:text-blue-600 transition-colors"
                >
                    <RotateCw size={20} />
                </button>
            </div>

            <div className="bg-white rounded-xl shadow-xs border border-slate-200 overflow-hidden">
                <div className="overflow-x-auto">
                    <table className="w-full text-left text-sm">
                        <thead className="bg-slate-50 border-b border-slate-100 uppercase text-xs text-slate-500 font-medium">
                            <tr>
                                <th className="p-4">Status</th>
                                <th className="p-4">Account</th>
                                <th className="p-4">Entity</th>
                                <th className="p-4">Time</th>
                                <th className="p-4">Details</th>
                            </tr>
                        </thead>
                        <tbody className="divide-y divide-slate-100">
                            {logs.map(log => (
                                <tr key={log.id} className="hover:bg-slate-50/50">
                                    <td className="p-4">
                                        {log.status === 'SUCCESS' && <div className="flex items-center gap-2 text-green-600"><CheckCircle size={16} /> Success</div>}
                                        {log.status === 'FAILED' && <div className="flex items-center gap-2 text-red-600"><XCircle size={16} /> Failed</div>}
                                        {log.status === 'IN_PROGRESS' && <div className="flex items-center gap-2 text-blue-600"><Clock size={16} /> Running</div>}
                                    </td>
                                    <td className="p-4 font-medium text-slate-900">{log.account?.name || 'Unknown'}</td>
                                    <td className="p-4 capitalize">{log.entityType}</td>
                                    <td className="p-4 text-slate-500">
                                        {new Date(log.startedAt).toLocaleString()}
                                    </td>
                                    <td className="p-4">
                                        {log.status === 'FAILED' ? (
                                            <span className="text-red-500 max-w-xs truncate block" title={log.errorMessage || ''}>
                                                {log.errorMessage}
                                            </span>
                                        ) : (
                                            <span className="text-slate-500">{log.itemsProcessed} items</span>
                                        )}
                                    </td>
                                </tr>
                            ))}
                            {!loading && logs.length === 0 && (
                                <tr>
                                    <td colSpan={5} className="p-8 text-center text-slate-400">No logs found</td>
                                </tr>
                            )}
                        </tbody>
                    </table>
                </div>

                {/* Pagination */}
                <Pagination
                    currentPage={page}
                    totalPages={totalPages}
                    onPageChange={setPage}
                    itemsPerPage={limit}
                    onItemsPerPageChange={(newLimit) => {
                        setLimit(newLimit);
                        setPage(1); // Reset to first page when limit changes
                    }}
                    allowItemsPerPage={true}
                />
            </div>
        </div>
    );
}

import { useEffect, useState, useRef } from 'react';
import { Logger } from '../../utils/logger';
import { useAuth } from '../../context/AuthContext';
import { Settings, Upload, Check, AlertCircle, Loader2, Globe, HardDrive, RefreshCw, UserPlus, ToggleLeft, ToggleRight } from 'lucide-react';

interface DatabaseInfo {
    source: 'manual' | 'auto';
    installed: boolean;
    size: number;
    sizeFormatted: string;
    buildDate: string;
    type: string;
}

interface GeoIPStatus {
    databases: DatabaseInfo[];
}

interface PlatformSettings {
    registrationEnabled: boolean;
    updatedAt: string;
}

/**
 * Super Admin settings page for system configuration.
 * Currently includes GeoIP database management.
 */
export function AdminSettingsPage() {
    const { token } = useAuth();
    const [status, setStatus] = useState<GeoIPStatus | null>(null);
    const [loading, setLoading] = useState(true);
    const [uploading, setUploading] = useState(false);
    const [uploadProgress, setUploadProgress] = useState(0);
    const [forcingUpdate, setForcingUpdate] = useState(false);
    const [message, setMessage] = useState<{ type: 'success' | 'error'; text: string } | null>(null);
    const [dragOver, setDragOver] = useState(false);
    const fileInputRef = useRef<HTMLInputElement>(null);

    // Platform settings state
    const [platformSettings, setPlatformSettings] = useState<PlatformSettings | null>(null);
    const [togglingRegistration, setTogglingRegistration] = useState(false);

    const fetchStatus = async () => {
        try {
            const res = await fetch('/api/admin/geoip-status', {
                headers: { Authorization: `Bearer ${token}` }
            });
            if (res.ok) {
                const data = await res.json();
                setStatus(data);
            }
        } catch (e) {
            Logger.error('Failed to fetch GeoIP status:', { error: e });
        } finally {
            setLoading(false);
        }
    };

    const fetchPlatformSettings = async () => {
        try {
            const res = await fetch('/api/admin/platform-settings', {
                headers: { Authorization: `Bearer ${token}` }
            });
            if (res.ok) {
                const data = await res.json();
                setPlatformSettings(data);
            }
        } catch (e) {
            Logger.error('Failed to fetch platform settings:', { error: e });
        }
    };

    const handleToggleRegistration = async () => {
        if (!platformSettings) return;

        setTogglingRegistration(true);
        setMessage(null);
        try {
            const res = await fetch('/api/admin/platform-settings', {
                method: 'PUT',
                headers: {
                    'Content-Type': 'application/json',
                    Authorization: `Bearer ${token}`
                },
                body: JSON.stringify({
                    registrationEnabled: !platformSettings.registrationEnabled
                })
            });
            const data = await res.json();
            if (res.ok) {
                setPlatformSettings(data);
                setMessage({
                    type: 'success',
                    text: data.registrationEnabled
                        ? 'New user registrations enabled'
                        : 'New user registrations disabled'
                });
            } else {
                setMessage({ type: 'error', text: data.error || 'Failed to update settings' });
            }
        } catch (e) {
            setMessage({ type: 'error', text: 'Network request failed' });
        } finally {
            setTogglingRegistration(false);
        }
    };

    useEffect(() => {
        fetchStatus();
        fetchPlatformSettings();
    }, [token]);

    const handleForceUpdate = async () => {
        setForcingUpdate(true);
        setMessage(null);
        try {
            const res = await fetch('/api/admin/geoip-force-update', {
                method: 'POST',
                headers: { Authorization: `Bearer ${token}` }
            });
            const data = await res.json();
            if (res.ok) {
                setMessage({ type: 'success', text: 'Auto-update completed successfully.' });
                fetchStatus();
            } else {
                setMessage({ type: 'error', text: data.error || 'Update failed' });
            }
        } catch (e) {
            setMessage({ type: 'error', text: 'Network request failed' });
        } finally {
            setForcingUpdate(false);
        }
    };

    const handleUpload = async (file: File) => {
        if (!file.name.endsWith('.mmdb')) {
            setMessage({ type: 'error', text: 'Only .mmdb files are accepted' });
            return;
        }

        setUploading(true);
        setUploadProgress(0);
        setMessage(null);

        const formData = new FormData();
        formData.append('database', file);

        try {
            const xhr = new XMLHttpRequest();

            xhr.upload.addEventListener('progress', (e) => {
                if (e.lengthComputable) {
                    setUploadProgress(Math.round((e.loaded / e.total) * 100));
                }
            });

            await new Promise<void>((resolve, reject) => {
                xhr.onload = () => {
                    if (xhr.status >= 200 && xhr.status < 300) {
                        const data = JSON.parse(xhr.responseText);
                        setMessage({ type: 'success', text: data.message || 'Database uploaded successfully!' });
                        fetchStatus();
                        resolve();
                    } else {
                        const error = JSON.parse(xhr.responseText);
                        reject(new Error(error.error || 'Upload failed'));
                    }
                };
                xhr.onerror = () => reject(new Error('Network error'));

                xhr.open('POST', '/api/admin/upload-geoip-db');
                xhr.setRequestHeader('Authorization', `Bearer ${token}`);
                xhr.send(formData);
            });
        } catch (e: unknown) {
            const message = e instanceof Error ? e.message : 'Upload failed';
            setMessage({ type: 'error', text: message });
        } finally {
            setUploading(false);
            setUploadProgress(0);
        }
    };

    const handleFileSelect = (e: React.ChangeEvent<HTMLInputElement>) => {
        const file = e.target.files?.[0];
        if (file) {
            handleUpload(file);
        }
    };

    const handleDrop = (e: React.DragEvent) => {
        e.preventDefault();
        setDragOver(false);
        const file = e.dataTransfer.files[0];
        if (file) {
            handleUpload(file);
        }
    };

    const handleDragOver = (e: React.DragEvent) => {
        e.preventDefault();
        setDragOver(true);
    };

    const handleDragLeave = () => {
        setDragOver(false);
    };

    if (loading) {
        return (
            <div className="flex items-center justify-center h-64">
                <Loader2 className="animate-spin text-slate-400" size={32} />
            </div>
        );
    }

    const manualDB = status?.databases.find(d => d.source === 'manual');
    const autoDB = status?.databases.find(d => d.source === 'auto');

    return (
        <div className="space-y-6">
            <h1 className="text-2xl font-bold text-slate-800 flex items-center gap-3">
                <Settings size={28} />
                System Settings
            </h1>

            {/* Platform Settings Section */}
            <div className="bg-white rounded-xl border border-slate-200 shadow-xs overflow-hidden">
                <div className="px-6 py-4 border-b border-slate-200 bg-slate-50">
                    <h2 className="text-lg font-semibold text-slate-800 flex items-center gap-2">
                        <UserPlus size={20} className="text-purple-600" />
                        User Registration
                    </h2>
                    <p className="text-sm text-slate-500 mt-1">
                        Control whether new users can register accounts on the platform.
                    </p>
                </div>

                <div className="p-6">
                    <div className="flex items-center justify-between">
                        <div>
                            <h3 className="font-medium text-slate-800">Allow New Registrations</h3>
                            <p className="text-sm text-slate-500 mt-1">
                                {platformSettings?.registrationEnabled
                                    ? 'New users can create accounts'
                                    : 'Only existing users can access the platform'}
                            </p>
                        </div>
                        <button
                            onClick={handleToggleRegistration}
                            disabled={togglingRegistration || !platformSettings}
                            className={`
                                relative inline-flex h-8 w-14 items-center rounded-full transition-colors
                                ${platformSettings?.registrationEnabled
                                    ? 'bg-emerald-500 hover:bg-emerald-600'
                                    : 'bg-slate-300 hover:bg-slate-400'}
                                ${togglingRegistration ? 'opacity-50 cursor-not-allowed' : 'cursor-pointer'}
                            `}
                        >
                            {togglingRegistration ? (
                                <Loader2 className="absolute left-1/2 -translate-x-1/2 animate-spin text-white" size={16} />
                            ) : (
                                <span
                                    className={`
                                        inline-block h-6 w-6 transform rounded-full bg-white shadow-sm transition-transform
                                        ${platformSettings?.registrationEnabled ? 'translate-x-7' : 'translate-x-1'}
                                    `}
                                />
                            )}
                        </button>
                    </div>

                    {platformSettings && !platformSettings.registrationEnabled && (
                        <div className="mt-4 p-3 bg-amber-50 border border-amber-200 rounded-lg flex items-start gap-3">
                            <AlertCircle className="text-amber-600 flex-shrink-0 mt-0.5" size={18} />
                            <div className="text-sm text-amber-800">
                                <strong>Registration is disabled.</strong> New users will not be able to create accounts.
                                Existing users and team members added manually can still log in.
                            </div>
                        </div>
                    )}
                </div>
            </div>

            {/* GeoIP Database Section */}
            <div className="bg-white rounded-xl border border-slate-200 shadow-xs overflow-hidden">
                <div className="px-6 py-4 border-b border-slate-200 bg-slate-50 flex justify-between items-center">
                    <div>
                        <h2 className="text-lg font-semibold text-slate-800 flex items-center gap-2">
                            <Globe size={20} className="text-blue-600" />
                            GeoIP Databases
                        </h2>
                        <p className="text-sm text-slate-500 mt-1">
                            Manage IP geolocation providers. The system automatically uses the newest database.
                        </p>
                    </div>
                    <button
                        onClick={fetchStatus}
                        className="p-2 text-slate-400 hover:text-slate-600 hover:bg-slate-200 rounded-lg transition-colors"
                        title="Refresh status"
                    >
                        <RefreshCw size={18} />
                    </button>
                </div>

                <div className="p-6 space-y-6">
                    {/* Auto DB Card */}
                    <div className="border border-slate-200 rounded-lg p-4">
                        <div className="flex justify-between items-start mb-4">
                            <div>
                                <h3 className="font-semibold text-slate-800 flex items-center gap-2">
                                    DB-IP Lite (Auto-Update)
                                    {autoDB?.installed && <span className="text-xs bg-blue-100 text-blue-700 px-2 py-0.5 rounded-full">Automated</span>}
                                </h3>
                                <p className="text-sm text-slate-500">Automatically fetches monthly updates from db-ip.com</p>
                            </div>
                            <button
                                onClick={handleForceUpdate}
                                disabled={forcingUpdate}
                                className="text-sm border border-slate-300 px-3 py-1.5 rounded-md hover:bg-slate-50 flex items-center gap-2 disabled:opacity-50"
                            >
                                {forcingUpdate ? <Loader2 size={14} className="animate-spin" /> : <RefreshCw size={14} />}
                                Force Update
                            </button>
                        </div>

                        {autoDB ? (
                            <div className="bg-slate-50 rounded-md p-3 flex items-center gap-4">
                                <div className="p-2 bg-emerald-100 rounded-full">
                                    <Check className="text-emerald-600" size={16} />
                                </div>
                                <div className="text-sm text-slate-600">
                                    <p className="font-medium text-slate-900">Installed</p>
                                    <p>Build Date: {new Date(autoDB.buildDate).toLocaleDateString()}</p>
                                    <p>Size: {autoDB.sizeFormatted}</p>
                                </div>
                            </div>
                        ) : (
                            <div className="bg-amber-50 rounded-md p-3 flex items-center gap-4 text-amber-800">
                                <AlertCircle size={20} />
                                <span className="text-sm">Not installed yet. Will fetch automatically or click Force Update.</span>
                            </div>
                        )}
                    </div>

                    {/* Manual DB Card */}
                    <div className="border border-slate-200 rounded-lg p-4">
                        <div className="mb-4">
                            <h3 className="font-semibold text-slate-800 flex items-center gap-2">
                                MaxMind GeoLite2 (Manual)
                                {manualDB?.installed && <span className="text-xs bg-purple-100 text-purple-700 px-2 py-0.5 rounded-full">Uploaded</span>}
                            </h3>
                            <p className="text-sm text-slate-500">Manually uploaded .mmdb file</p>
                        </div>

                        {manualDB ? (
                            <div className="bg-slate-50 rounded-md p-3 flex items-center gap-4 mb-4">
                                <div className="p-2 bg-emerald-100 rounded-full">
                                    <Check className="text-emerald-600" size={16} />
                                </div>
                                <div className="text-sm text-slate-600">
                                    <p className="font-medium text-slate-900">Installed</p>
                                    <p>Build Date: {new Date(manualDB.buildDate).toLocaleDateString()}</p>
                                    <p>Size: {manualDB.sizeFormatted}</p>
                                </div>
                            </div>
                        ) : (
                            <div className="bg-slate-50 rounded-md p-3 flex items-center gap-4 mb-4 text-slate-500">
                                <div className="p-2 bg-slate-200 rounded-full">
                                    <HardDrive className="text-slate-500" size={16} />
                                </div>
                                <span className="text-sm">No custom database uploaded.</span>
                            </div>
                        )}

                        {/* Upload Dropzone */}
                        <div
                            onDrop={handleDrop}
                            onDragOver={handleDragOver}
                            onDragLeave={handleDragLeave}
                            onClick={() => fileInputRef.current?.click()}
                            className={`
                                border-2 border-dashed rounded-lg p-6 text-center cursor-pointer transition-all
                                ${dragOver ? 'border-blue-500 bg-blue-50' : 'border-slate-300 hover:border-slate-400 hover:bg-slate-50'}
                                ${uploading ? 'pointer-events-none opacity-60' : ''}
                            `}
                        >
                            <input
                                ref={fileInputRef}
                                type="file"
                                accept=".mmdb"
                                onChange={handleFileSelect}
                                className="hidden"
                            />

                            {uploading ? (
                                <div className="space-y-2">
                                    <Loader2 className="animate-spin mx-auto text-blue-600" size={24} />
                                    <p className="text-sm text-slate-600">Uploading... {uploadProgress}%</p>
                                </div>
                            ) : (
                                <div className="flex flex-col items-center gap-2">
                                    <Upload className="text-slate-400" size={24} />
                                    <p className="text-sm font-medium text-slate-600">
                                        {manualDB ? 'Replace Manual Database' : 'Upload Manual Database'}
                                    </p>
                                    <p className="text-xs text-slate-400">
                                        Drag & drop .mmdb file
                                    </p>
                                </div>
                            )}
                        </div>
                    </div>

                    {/* Message */}
                    {message && (
                        <div className={`p-4 rounded-lg flex items-center gap-3 ${message.type === 'success' ? 'bg-emerald-50 text-emerald-800' : 'bg-red-50 text-red-800'}`}>
                            {message.type === 'success' ? <Check size={20} /> : <AlertCircle size={20} />}
                            {message.text}
                        </div>
                    )}
                </div>
            </div>
        </div>
    );
}

import React, { useState, useEffect, useMemo } from 'react';
import { Logger } from '../../utils/logger';
import { useAccount } from '../../context/AccountContext';
import { useAuth } from '../../context/AuthContext';
import { api } from '../../services/api';
import { Card, CardContent, CardHeader, CardTitle } from '../../components/ui/Card';
import { DateRangeFilter } from '../../components/analytics/DateRangeFilter';
import {
    BarChart3, ShoppingCart, TrendingDown, Search,
    ArrowUpRight
} from 'lucide-react';
import FunnelWidget from '../../components/widgets/FunnelWidget';
import AnalyticsStatsWidget from '../../components/widgets/AnalyticsStatsWidget';

interface AbandonmentData {
    addedToCartCount: number;
    purchasedCount: number;
    abandonedCount: number;
    abandonmentRate: number;
}

interface SearchData {
    topQueries: { query: string; count: number }[];
    totalSearches: number;
}

interface ExitData {
    topExitPages: { page: string; count: number }[];
}

export const AnalyticsOverviewPage: React.FC = () => {
    const [days, setDays] = useState(1); // Default to Today
    const { currentAccount } = useAccount();
    const { token } = useAuth();
    const [abandonment, setAbandonment] = useState<AbandonmentData | null>(null);
    const [searches, setSearches] = useState<SearchData | null>(null);
    const [exits, setExits] = useState<ExitData | null>(null);
    const [loading, setLoading] = useState(true);

    useEffect(() => {
        const fetchData = async () => {
            if (!currentAccount || !token) return;
            setLoading(true);
            try {
                const [abandonmentRes, searchesRes, exitsRes] = await Promise.all([
                    api.get<AbandonmentData>(`/api/tracking/abandonment?days=${days}`, token, currentAccount.id),
                    api.get<SearchData>(`/api/tracking/searches?days=${days}`, token, currentAccount.id),
                    api.get<ExitData>(`/api/tracking/exits?days=${days}`, token, currentAccount.id)
                ]);
                setAbandonment(abandonmentRes);
                setSearches(searchesRes);
                setExits(exitsRes);
            } catch (error) {
                Logger.error('Failed to fetch overview:', { error: error });
            } finally {
                setLoading(false);
            }
        };
        fetchData();
    }, [currentAccount, token, days]);

    /** Derive startDate/endDate from the days filter for widget props */
    const dateRange = useMemo(() => {
        const end = new Date();
        const start = new Date();
        start.setDate(end.getDate() - days);
        return {
            startDate: start.toISOString().split('T')[0],
            endDate: end.toISOString().split('T')[0]
        };
    }, [days]);

    return (
        <div className="p-6 space-y-6">
            <div className="flex items-center justify-between">
                <h1 className="text-2xl font-bold text-gray-900">Analytics Overview</h1>
                <DateRangeFilter value={days} onChange={setDays} />
            </div>

            {/* Top Row - Funnel & Stats */}
            <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
                <Card className="border-0 shadow-xs">
                    <CardHeader>
                        <CardTitle className="text-sm font-semibold flex items-center gap-2">
                            <TrendingDown className="w-4 h-4 text-green-500" />
                            Conversion Funnel
                        </CardTitle>
                    </CardHeader>
                    <CardContent className="p-0">
                        <FunnelWidget dateRange={dateRange} />
                    </CardContent>
                </Card>

                <Card className="border-0 shadow-xs">
                    <CardHeader>
                        <CardTitle className="text-sm font-semibold flex items-center gap-2">
                            <BarChart3 className="w-4 h-4 text-purple-500" />
                            Audience Insights
                        </CardTitle>
                    </CardHeader>
                    <CardContent className="p-0">
                        <AnalyticsStatsWidget dateRange={dateRange} />
                    </CardContent>
                </Card>
            </div>

            {/* Middle Row - Cart Abandonment */}
            {abandonment && (
                <Card className="border-0 shadow-xs">
                    <CardHeader>
